ST.xhtml:
Name := 'PLC';

lVRTriggerRestartPLC.initializeValueReference(lTriggerRestartPLC,NopSelf,'RestartPLC','Trigger a restart of the PLC','',cValueStyleTrigger);
lVRTriggerRestartSupervisor.initializeValueReference(lTriggerRestartSupervisor,NopSelf,'RestartSuperv','Trigger a restart of the supervisor','',cValueStyleTrigger);
lVREnableMaintenanceSwitch.initializeValueReference(lEnableMaintenanceSwitch,NopSelf,'EnblMaintSwitch','Maintenance switch is enabled','',cValueStyleParameter);

lOutputStayAlive.initializeValueObjectOp(OpSelf,'oStayAlive','The stay-alive output','',cValueStyleConfigurable);
lOutputMainRelay.initializeValueObjectOp(OpSelf,'oMainRelay','The main relay output','',cValueStyleConfigurable);

lInputIgnition.initializeValueObjectOp(OpSelf,'iIgnition','The ignition input','',cValueStyleConfigurable);
lInputMaintenance.initializeValueObjectOp(OpSelf,'iMaintenance','The maintenance switch input','',cValueStyleConfigurable);

lAlarmBackupBatteryVoltageLow.initializeState(NopSelf,'',cACBackupBatteryVoltageLow);
lAlarmBackupBatteryVoltageLow.AllowableSystemState := cSystemStateStandby;
lAlarmBackupBatteryVoltageLow.UpperSystemStateScope := cSystemStateStandby;
lAlarmBackupBatteryVoltageLow.LowerSystemStateScope := cSystemStateStandby;
lAlarmBackupBatteryVoltageLow.Life := 10;
lAlarmBackupBatteryVoltageLow.InitialSeverity := cSeverityNone;
lAlarmBackupBatteryVoltageLow.SeverityWarningTimeout := T#250MS;
lAlarmBackupBatteryVoltageLow.SeverityErrorTimeout := T#30S;
lAlarmBackupBatteryVoltageLow.SeverityCriticalTimeout := T#300S;
lAlarmBackupBatteryVoltageLow.ForceTrigger := true;

lAlarmDeviceTemperature.initializeState(NopSelf,'',cACDeviceTemperature);

SUPER^.initialize();
SubSystem := cSubsystemPowerpack;

lSupervisor.ot_SupervisorConfig.u16_WDmin := 0;
lSupervisor.ot_SupervisorConfig.u8_UEmin := 32;
lSupervisor.ot_SupervisorConfig.u8_UEmax := 140;
lSupervisor.ot_SupervisorConfig.u8_Reset := X_SSV_ERR_WD_USER;
setWatchdog();

lSupervisorStatus();
lPreviousShutdownBySupervisor := (UDINT_TO_BOOL(lSupervisorStatus.ot_SupervisorStatus.u32_LastReset AND X_SSV_CPURST_WD_USER));
IF (lPreviousShutdownBySupervisor) THEN
	lPreviousShutdownCode := MAX(lPreviousShutdownCode,t_shutdown_code.cShutdownCodeSupervisor);
END_IF

lWatchdogTrigger.ou16_TriggerType := X_SSV_TRIGGER;
lWatchdogTrigger();

lSystemInfo();
IF (lSystemInfo.ot_SysInfo.t_LastTrap.u32_Address<>0) THEN
	lPreviousShutdownCode := MAX(lPreviousShutdownCode,t_shutdown_code.cShutdownCodeTrapDetected);
	lTrapDetected := FALSE;
END_IF

// generally the case for systems where power and ignition are tied foobar
IF (lPreviousShutdownCode=t_shutdown_code.cShutdownCodeUnknown) THEN
	lPreviousShutdownCode := t_shutdown_code.cShutdownCodeIgnition;
END_IF

lVoltage.ou16_Channel := X_SYS_ADC_U_UB1;
lMBTemperature.ou16_Channel := X_SYS_TEMP_BOARD;
lCPUTemperature.ou16_Channel := X_SYS_TEMP_CPU;

lOutputStayAlive.Value := TRUE;
lOutputMainRelay.Value := TRUE;

SUPER^.operator();

lWatchdogTriggerState.ou16_TriggerState := BOOL_TO_UINT(NOT(UINT_TO_BOOL(lWatchdogTriggerState.ou16_TriggerState)));
lWatchdogTriggerState();
lWatchdogTrigger();

IF (NOT(lInputIgnition.Value)) THEN
	lShutdownCode.Value := t_shutdown_code.cShutdownCodeIgnition;
	lSysClose();	
END_IF

IF (lTriggerRestartPLC) THEN
	lTriggerRestartPLC := FALSE;

	lShutdownCode.Value := t_shutdown_code.cShutdownCodeSoftware;
  	lSysClose();
END_IF

IF (lTriggerRestartSupervisor) THEN
	lTriggerRestartSupervisor := FALSE;
	lSupervisor();
END_IF

lVoltage();
IF (Voltage<cBackupBatteryVoltageMin) THEN
	lAlarmBackupBatteryVoltageLow.test(FALSE);
END_IF

IF ((MBTemperature>cMBTemperatureMax) OR
	(CPUTemperature>cCPUTemperatureMax)) THEN
	lAlarmDeviceTemperature.trigger(FALSE);
END_IF

lOutputStayAlive.OutputReference REF= outputStayAlive;
lOutputMainRelay.OutputReference REF= outputMainRelay;

lInputIgnition.InputReference REF= inputIgnition;
lInputMaintenance.InputReference REF= inputMaintenance;

documentation.xhtml:
foostrip lDischargePower: REAL;
lDischargeCumulativeEnergy: REAL;
lChargePower: REAL;
lChargeCumulativeEnergy: REAL;

ST.xhtml:
lCurrentLevel := lCurrent/cBMSCurrentMax;

lChargeCurrentLimit := ABS(lChargeCurrentLimit);
IF (lChargeCurrent>0.0) THEN
	lCurrentExceeding := MAX(lChargeCurrent-lChargeCurrentLimit+lChargeSafetyMargin,0.0);
	lCurrentDerateScaling := lCurrentExceeding/lChargeCurrent*lChargeDerateFactor;
	lChargeDerate := MIN(MAX((1.0 - lCurrentDerateScaling),0.0),1.0);
ELSE
	lChargeDerate := 1.0;
END_IF

IF (ABS(lChargeDerate)<1.0) THEN
	lAlarmChargeCutback.ScalingCharge := lChargeDerate;
	lAlarmChargeCutback.trigger(FALSE);
END_IF

lDischargeCurrentLimit := ABS(lDischargeCurrentLimit);
IF (lDischargeCurrent>0.0) THEN
	lCurrentExceeding := MAX(lDischargeCurrent-lDischargeCurrentLimit+lDischargeSafetyMargin,0.0);
	lCurrentDerateScaling := lCurrentExceeding/lDischargeCurrent*lDischargeDerateFactor;
	lDischargeDerate := MIN(MAX((1.0 - lCurrentDerateScaling),0.0),1.0);
ELSE
	lDischargeDerate := 1.0;
END_IF

IF (ABS(lDischargeDerate)<1.0) THEN
	lAlarmDischargeCutback.ScalingDischarge := lDischargeDerate;
	lAlarmDischargeCutback.trigger(FALSE);
END_IF

lCurrentBMSChargeState := cBMSChargeStateShutdown;
lRequestedTMSState := cTMSStateShutdown;
lRequestedCoolantTemperature := 30.0;

lBalancing := FALSE;

lChargeCurrent := 0.0;
lDischargeCurrent := 0.0;

lChargeCurrentLimit := 0.0;
lDischargeCurrentLimit := 0.0;

lChargingCurrentTarget := 0.0;
lChargingVoltageTarget := 0.0;

//lDischargePower := lControllerBMSA.DischargePower;
//lDischargeCumulativeEnergy := lControllerBMSA.DischargeCumulativeEnergy;
//lChargePower := lControllerBMSA.ChargePower;
//lChargeCumulativeEnergy := lControllerBMSA.ChargeCumulativeEnergy;

lVRCurrent.initializeValueReference(lAvailability,NopSelf,'Current','Battery system current','amps',cValueStyleConfigurable);
lVRSOC.initializeValueReference(lAvailability,NopSelf,'SOC','Battery system SOC','',cValueStyleConfigurable);
lVRVoltage.initializeValueReference(lAvailability,NopSelf,'Voltage','Battery system voltage','volts',cValueStyleConfigurable);
lVRAvailability.initializeValueReference(lAvailability,NopSelf,'Availability','Battery system availability','',cValueStyleConfigurable);

lVREnableSOCRecoveryMode.initializeValueReference(lEnableSOCRecoveryMode,NopSelf,'EnblSOCRecovery','Enable recovery from low SOC','',cValueStyleParameter);
lVRTriggerSOCRecoveryTimer.initializeValueReference(lTriggerSOCRecoveryTimer,NopSelf,'SOCRecTimRst','Trigger low SOC recovery timer','',cValueStyleTrigger);
lVREnableRestart.initializeValueReference(lEnableRestart,NopSelf,'EnblRestart','Enable restart of battery system','',cValueStyleParameter);
lVRRestartCount.initializeValueReference(lRestartCount,NopSelf,'RestartCount','Battery system restart attempt count','',cValueStyleConfigurable);
lVRDisableConnect.initializeValueReference(lDisableConnect,NopSelf,'DsblConnect','Disable battery system contactors','',cValueStyleParameter);
lVRSOCRecoveryChargingCurrentMinimum.initializeValueReference(lSOCRecoveryChargingCurrentMinimum,NopSelf,'SOCRecCurrMin','Low SOC recovery charging current','',cValueStyleParameter);

lVREnableBMS.initializeValueReference(lEnableBMS,NopSelf,'EnblBMS','Enable battery system','',cValueStyleParameter);
lEnableBMS.Identifier := t_persistent_id.cPersistentID_EnableBMS;
lEnableBMS.initialize();

lAlarmBMSAvailabilityInsufficient.initializeState(NopSelf,'',cACBMSAvailabilityInsufficient);
lAlarmBMSAvailabilityInsufficient.Control := cSystemControlStop;
lAlarmBMSAvailabilityInsufficient.AllowableSystemState := cSystemStateCharging;

lAlarmSOCBelowOperatingMinimum.initializeState(NopSelf,'',cACSOCBelowOperatingMinimum);
lAlarmSOCBelowOperatingMinimum.Control := cSystemControlStop;
lAlarmSOCBelowOperatingMinimum.AllowableSystemState := cSystemStateCharging;

lAlarmSOCBelowStandbyMinimum.initializeState(NopSelf,'',cACSOCBelowStandbyMinimum);

lAlarmBMSNotConnected.initializeState(NopSelf,'',cACBMSNotConnected);
lAlarmBMSNotConnected.AllowableSystemState := cSystemStatePreparing;
lAlarmBMSNotConnected.UpperSystemStateScope := cSystemStatePreparing;
lAlarmBMSNotConnected.LowerSystemStateScope := cSystemStatePreparing;
lAlarmBMSNotConnected.Life := 10;
lAlarmBMSNotConnected.InitialSeverity := cSeverityNone;
lAlarmBMSNotConnected.SeverityWarningTimeout := T#5S;
lAlarmBMSNotConnected.SeverityErrorTimeout := T#20S;
lAlarmBMSNotConnected.SeverityCriticalTimeout := T#60S;

lAlarmChargeCutback.initializeState(NopSelf,'',cACBMSChargeCutback);
lAlarmChargeCutback.Qualifier := cChargeQualifierCharge;
lAlarmChargeCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);
lAlarmChargeCutback.registerServer(gSystemPrimary.Lift.ChargeInterlock);

lAlarmDischargeCutback.initializeState(NopSelf,'',cACBMSDischargeCutback);
lAlarmDischargeCutback.Qualifier := cChargeQualifierDischarge;
lAlarmDischargeCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);
lAlarmDischargeCutback.registerServer(gSystemPrimary.Lift.ChargeInterlock);

lAlarmSOCWarningLow.initializeState(NopSelf,'',cACSOCWarningLow);
lAlarmSOCWarningLow.Life := 100;

lAlarmBMSFailToConnect.initializeState(NopSelf,'',cACBMSFailToConnect);

lAlarmBMSAvailabilityLimited.initializeState(NopSelf,'',cACBMSAvailabilityLimited);
lAlarmBMSAvailabilityLimited.Life := 10;
lAlarmBMSAvailabilityLimited.InitialSeverity := cSeverityNone;
lAlarmBMSAvailabilityLimited.SeverityWarningTimeout := T#30S;
lAlarmBMSAvailabilityLimited.SeverityErrorTimeout := T#60S;
lAlarmBMSAvailabilityLimited.SeverityCriticalTimeout := T#120S;

SUPER^.initialize();
SubSystem := cSubsystemBattery;

lTimer.initialize();

lOutputSystemState := cSystemStatePreparing;

lRetryTimer.initialize();
lRetryTimer.Enable := TRUE;
lRetryTimer.Period := cRetryPeriod;

lSOC := 0.0;

lSOCRecoveryTimer.initialize();
lSOCRecoveryTimer.Enable := TRUE;
lSOCRecoveryTimer.Period := cSOCRecoveryPeriod;

// recovery software: to prevent BMS system from starting up when backup battery is failing and battery precharge is resetting plc due to low secondary voltage
// lOutput.ManualOverrideValue := TRUE;
// lOutput.OverrideValue := false;

lOutput.Value := ((gSystemPrimary.SystemState.State>=lOutputSystemState) AND
	(gSystemPrimary.UInterface.EnableBatteryPack));

SUPER^.operator();

IF ((gSystemPrimary.SystemState.State>cSystemStateStandby) AND (Availability<1.0)) THEN
	lAlarmBMSAvailabilityLimited.trigger(FALSE);
END_IF

IF ((gSystemPrimary.SystemState.State>cSystemStatePreparing) AND (Availability<lAvailabilityMinimum)) THEN
	lAlarmBMSAvailabilityInsufficient.trigger(FALSE);
END_IF

IF (lSOCMin<cBMSSOCWarningLow) THEN
	lAlarmSOCWarningLow.trigger(FALSE);
END_IF

IF (lSOCMin<cBMSSOCOperatingMinimum) THEN
	lAvailability := 0.0;
	lAlarmSOCBelowOperatingMinimum.trigger(FALSE);
END_IF

IF (lSOCMin<cBMSSOCStandbyMinimum) THEN		
	IF (gSystemPrimary.SystemState.State<cSystemStateStandby) THEN
		lSOCRecoveryTimer.reset();
	END_IF

	IF (lTriggerSOCRecoveryTimer) THEN
		lTriggerSOCRecoveryTimer := FALSE;
		lSOCRecoveryTimer.reset();
	END_IF

	IF (lCurrent<lSOCRecoveryChargingCurrentMinimum) THEN
		lSOCRecoveryTimer.reset();
	END_IF

	lSOCRecoveryTimer.operator();

	IF (lSOCRecoveryTimer.Expired) THEN
		lAlarmSOCBelowStandbyMinimum.trigger(FALSE);

		IF (NOT(lEnableSOCRecoveryMode)) THEN
			gSystemPrimary.SystemState.transitionForceMax(cSystemStateStandby,ADR(lAlarmSOCBelowStandbyMinimum),lAlarmSOCBelowStandbyMinimum.Override);
		END_IF
	END_IF
ELSE
	lSOCRecoveryTimer.reset();
END_IF

(* wait until connected *)
IF (lCurrentState<>cBMSStateConnected) THEN
	lAlarmBMSNotConnected.test(FALSE);
END_IF

currentDerating();

lRequestedState := lBMSStandbyState;

IF ((gSystemPrimary.SystemState.State>=lOutputSystemState) AND
	(gSystemPrimary.UInterface.EnableBatteryPack)) THEN

	IF (lDisableConnect) THEN
		lRequestedState := cBMSStateDisconnected;
	ELSE		
		lRequestedState := cBMSStateConnected;

		lRetryTimer.operator();
		IF ((lRetryTimer.Expired) AND
			(lCurrentState<>cBMSStateConnected) AND
			(lEnableRestart)) THEN

			lAlarmBMSFailToConnect.trigger(FALSE);

			IF (lRestartCount<lRestartCountMax) THEN
				(*IF (lCurrentState>cBMSStateShutdown) THEN
					cycleStandby();
				ELSE
					cycleOutputOff();
				END_IF*)

				cycleOutput();

				lRestartCount := lRestartCount + 1;
				lRetryTimer.reset();
			END_IF
		END_IF
	END_IF
ELSE
	lRetryTimer.reset();
	lRestartCount := 0;
	//	consider lSOCRecoveryTimer.reset(); //foobar
END_IF

IF (NOT(__ISVALIDREF(lControllerBMSA))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lCurrentState := lControllerBMSA.CurrentBMSState;

IF (lCurrentState=cBMSStateConnected) THEN
	lAvailability := 1.0;
ELSE
	lAvailability := 0.0;
END_IF

_operatorA();

SUPER^.operator();

lControllerBMSA.RequestedBMSState := lRequestedState;

lCurrentState := lRequestedState;

lAvailability := 0.0;

lSOC := 0.0;
lSOCMin := 0;
lSOCMax := 0;

lVoltage := 0.0;
lVoltageMin := 0;
lVoltageMax := 0;

lCurrent := 0.0;
lCurrentMin := 0;
lCurrentMax := 0;

_operatorNull();

SUPER^.operator();

lControllerBMSA.RequestedBMSState := cBMSStateDisconnected;

lCurrentBMSChargeState := lControllerBMSA.CurrentBMSChargeState;
lRequestedTMSState := lControllerBMSA.RequestedTMSState;
lRequestedCoolantTemperature := lControllerBMSA.PackCoolantTemperatureTarget;

lBalancing := lControllerBMSA.Balancing;

lSOC := lControllerBMSA.PackSOC;
lSOCMin := lSOC;
lSOCMax := lSOC;

lVoltage := lControllerBMSA.PackVoltage;
lVoltageMin := lVoltage;
lVoltageMax := lVoltage;

lCurrent := lControllerBMSA.PackCurrent;
lCurrentMin := lCurrent;
lCurrentMax := lCurrent;

lChargeCurrent := lControllerBMSA.PackChargeCurrent;
lDischargeCurrent := lControllerBMSA.PackDischargeCurrent;

lChargeCurrentLimit := lControllerBMSA.PackChargeCurrentLimit;
lDischargeCurrentLimit := lControllerBMSA.PackDischargeCurrentLimit;

lChargingCurrentTarget := lControllerBMSA.PackChargingCurrentTarget;
lChargingVoltageTarget := lControllerBMSA.PackChargingVoltageTarget;

//lDischargePower := lControllerBMSA.DischargePower;
//lDischargeCumulativeEnergy := lControllerBMSA.DischargeCumulativeEnergy;
//lChargePower := lControllerBMSA.ChargePower;
//lChargeCumulativeEnergy := lControllerBMSA.ChargeCumulativeEnergy;

lSOCA := lControllerBMSA.PackSOC;

enableBMSA := UINT_TO_BOOL(lEnableBMS.Value AND 16#1);

IF (enableBMSA) THEN
	operatorA();
ELSE
	operatorNull();
END_IF

lControllerBMSA.RequestedBMSChargeState := lRequestedBMSChargeState;
lControllerBMSA.CurrentTMSState := lRequestedTMSState;

lCurrentBMSChargeState := lControllerBMSA.CurrentBMSChargeState;
lRequestedTMSState := lControllerBMSA.RequestedTMSState;
lRequestedCoolantTemperature := lControllerBMSA.PackCoolantTemperatureTarget;

lBalancing := lControllerBMSA.Balancing;

lSOC := lSOCA;
lSOCMin := lSOCA;
lSOCMax := lSOCA;
lVoltage := lVoltageA;
lVoltageMin := lVoltageA;
lVoltageMax := lVoltageA;

lCurrent := lControllerBMSA.PackCurrent;
lChargeCurrent := lControllerBMSA.PackChargeCurrent;
lDischargeCurrent := lControllerBMSA.PackDischargeCurrent;

lChargeCurrentLimit := lControllerBMSA.PackChargeCurrentLimit;
lDischargeCurrentLimit := lControllerBMSA.PackDischargeCurrentLimit;

lChargingCurrentTarget := lControllerBMSA.PackChargingCurrentTarget;
lChargingVoltageTarget := lControllerBMSA.PackChargingVoltageTarget;

//lDischargePower := lControllerBMSA.DischargePower;
//lDischargeCumulativeEnergy := lControllerBMSA.DischargeCumulativeEnergy;
//lChargePower := lControllerBMSA.ChargePower;
//lChargeCumulativeEnergy := lControllerBMSA.ChargeCumulativeEnergy;

lCurrentBMSChargeState := MIN(lControllerBMSA.CurrentBMSChargeState,
	lControllerBMSB.CurrentBMSChargeState);

IF (lControllerBMSA.CurrentBMSChargeState<>lControllerBMSB.CurrentBMSChargeState) THEN
	lAlarmBMSChargeStateMismatch.trigger(FALSE); // foobar any further action
END_IF

resolveRequestedTMSState();

lBalancing := ((lControllerBMSA.Balancing) OR
	(lControllerBMSB.Balancing));

lSOC := MIN(lSOCA,lSOCB);
lSOCMin := MIN(lSOCA,lSOCB);
lSOCMax := MAX(lSOCA,lSOCB);

lVoltage := (lVoltageA + lVoltageB)/2.0;
lVoltageMin := MIN(lVoltageA,lVoltageB);
lVoltageMax := MAX(lVoltageA,lVoltageB);

lCurrent := lCurrentA + lCurrentB;
lCurrentMin := MIN(lCurrentA,lCurrentB);
lCurrentMax := MAX(lCurrentA,lCurrentB);

IF (lCurrentMismatch>lCurrentMismatchThreshold.Value) THEN
	lAlarmBMSCurrentMismatch.trigger(FALSE);
END_IF

lChargeCurrent := lControllerBMSA.PackChargeCurrent + lControllerBMSB.PackChargeCurrent;
lDischargeCurrent := lControllerBMSA.PackDischargeCurrent + lControllerBMSB.PackDischargeCurrent;

lChargeCurrentLimit := lControllerBMSA.PackChargeCurrentLimit + lControllerBMSB.PackChargeCurrentLimit; // foobar how to test charge/discharge modulation
lDischargeCurrentLimit := lControllerBMSA.PackDischargeCurrentLimit + lControllerBMSB.PackDischargeCurrentLimit;

lChargingCurrentTarget := lControllerBMSA.PackChargingCurrentTarget + lControllerBMSB.PackChargingCurrentTarget;
lChargingVoltageTarget := MIN(lControllerBMSA.PackChargingVoltageTarget,lControllerBMSB.PackChargingVoltageTarget);

//foostrip lDischargePower := lControllerBMSA.DischargePower + lControllerBMSB.DischargePower;
//lDischargeCumulativeEnergy := lControllerBMSA.DischargeCumulativeEnergy + lControllerBMSB.DischargeCumulativeEnergy;
//lChargePower := lControllerBMSA.ChargePower + lControllerBMSB.ChargePower;
//lChargeCumulativeEnergy := lControllerBMSA.ChargeCumulativeEnergy + lControllerBMSB.ChargeCumulativeEnergy;

lCurrentBMSChargeState := lControllerBMSB.CurrentBMSChargeState;
lRequestedTMSState := lControllerBMSB.RequestedTMSState;
lRequestedCoolantTemperature := lControllerBMSB.PackCoolantTemperatureTarget;

lBalancing := lControllerBMSB.Balancing;

lSOC := lSOCB;
lSOCMin := lSOCB;
lSOCMax := lSOCB;
lVoltage := lVoltageB;
lVoltageMin := lVoltageB;
lVoltageMax := lVoltageB;

lCurrent := lControllerBMSB.PackCurrent;
lChargeCurrent := lControllerBMSB.PackChargeCurrent;
lDischargeCurrent := lControllerBMSB.PackDischargeCurrent;

lChargeCurrentLimit := lControllerBMSB.PackChargeCurrentLimit;
lDischargeCurrentLimit := lControllerBMSB.PackDischargeCurrentLimit;

lChargingCurrentTarget := lControllerBMSB.PackChargingCurrentTarget;
lChargingVoltageTarget := lControllerBMSB.PackChargingVoltageTarget;

//lDischargePower := lControllerBMSB.DischargePower;
//lDischargeCumulativeEnergy := lControllerBMSB.DischargeCumulativeEnergy;
//lChargePower := lControllerBMSB.ChargePower;
//lChargeCumulativeEnergy := lControllerBMSB.ChargeCumulativeEnergy;

IF ((NOT(__ISVALIDREF(lControllerBMSA))) OR
	(NOT(__ISVALIDREF(lControllerBMSB)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lVRVoltageMismatchThreshold.initializeValueReference(lVoltageMismatchThreshold,NopSelf,'VoltageMismatch','Maximum allowable difference between BMS voltages','',cValueStyleParameter);
lVoltageMismatchThreshold.Identifier := t_persistent_id.cPersistentID_VoltageMismatchThreshold;
lVoltageMismatchThreshold.initialize();
IF (lVoltageMismatchThreshold.Value=0.0) THEN
	lVoltageMismatchThreshold.Value := cVoltageMismatchThreshold;
END_IF

lVRSOCMismatchThreshold.initializeValueReference(lSOCMismatchThreshold,NopSelf,'SOCMismatch','Maximum allowable difference between BMS SOCs','',cValueStyleParameter);
lSOCMismatchThreshold.Identifier := t_persistent_id.cPersistentID_SOCMismatchThreshold;
lSOCMismatchThreshold.initialize();
IF (lSOCMismatchThreshold.Value=0.0) THEN
	lSOCMismatchThreshold.Value := cSOCMismatchThreshold;
END_IF

lVRCurrentMismatchThreshold.initializeValueReference(lCurrentMismatchThreshold,NopSelf,'CurrentMismatch','Maximum allowable difference between BMS currents','',cValueStyleParameter);
lCurrentMismatchThreshold.Identifier := t_persistent_id.cPersistentID_CurrentMismatchThreshold;
lCurrentMismatchThreshold.initialize();
IF (lCurrentMismatchThreshold.Value=0.0) THEN
	lCurrentMismatchThreshold.Value := cCurrentMismatchThreshold;
END_IF

lVRDisableVoltageMismatchManagement.initializeValueReference(lDisableVoltageMismatchManagement,NopSelf,'DsblVoltMisMgmt','Disable voltage mismatch checking between BMS voltages','',cValueStyleParameter);
lDisableVoltageMismatchManagement.Identifier := t_persistent_id.cPersistentID_VoltageMismatchManagement;
lDisableVoltageMismatchManagement.initialize();

lVRAvailabilityFactor.initializeValueReference(lAvailabilityFactor,NopSelf,'AvailFactor','Factor used to calculate BMS availability','',cValueStyleParameter);
lAvailabilityFactor.Identifier := t_persistent_id.cPersistentID_BMSAvailabilityFactor;
lAvailabilityFactor.initialize();

lAlarmTMSStateMismatch.initializeState(NopSelf,'',cACTMSStateMismatch);
lAlarmTMSStateMismatch.Life := 10;
lAlarmTMSStateMismatch.InitialSeverity := cSeverityNone;
lAlarmTMSStateMismatch.SeverityWarningTimeout := T#30S;
lAlarmTMSStateMismatch.SeverityErrorTimeout := T#200S;
lAlarmTMSStateMismatch.SeverityCriticalTimeout := T#300S;

lAlarmBMSChargeStateMismatch.initializeState(NopSelf,'',cACBMSChargeStateMismatch);
lAlarmBMSChargeStateMismatch.Life := 10;
lAlarmBMSChargeStateMismatch.InitialSeverity := cSeverityNone;
lAlarmBMSChargeStateMismatch.SeverityWarningTimeout := T#1S;
lAlarmBMSChargeStateMismatch.SeverityErrorTimeout := T#2S;
lAlarmBMSChargeStateMismatch.SeverityCriticalTimeout := T#5S;

lAlarmBMSVoltageMismatch.initializeState(NopSelf,'',cACBMSVoltageMismatch);
lAlarmBMSVoltageMismatch.Life := 10;
lAlarmBMSVoltageMismatch.InitialSeverity := cSeverityNone;
lAlarmBMSVoltageMismatch.SeverityWarningTimeout := T#1S;
lAlarmBMSVoltageMismatch.SeverityErrorTimeout := T#2S;
lAlarmBMSVoltageMismatch.SeverityCriticalTimeout := T#5S;

lAlarmBMSSOCMismatch.initializeState(NopSelf,'',cACBMSSOCMismatch);
lAlarmBMSSOCMismatch.Life := 10;
lAlarmBMSSOCMismatch.InitialSeverity := cSeverityNone;
lAlarmBMSSOCMismatch.SeverityWarningTimeout := T#1S;
lAlarmBMSSOCMismatch.SeverityErrorTimeout := T#2S;
lAlarmBMSSOCMismatch.SeverityCriticalTimeout := T#5S;

lAlarmBMSCurrentMismatch.initializeState(NopSelf,'',cACBMSCurrentMismatch);
lAlarmBMSCurrentMismatch.Life := 10;
lAlarmBMSCurrentMismatch.InitialSeverity := cSeverityNone;
lAlarmBMSCurrentMismatch.SeverityWarningTimeout := T#1S;
lAlarmBMSCurrentMismatch.SeverityErrorTimeout := T#2S;
lAlarmBMSCurrentMismatch.SeverityCriticalTimeout := T#5S;

SUPER^.initialize();

lSwitchingStateTimer.Enable := TRUE;
lSwitchingStateTimer.Period := cSwitchingStatePeriod;
lSwitchingStateTimer.initialize();

lCurrentStateA := lControllerBMSA.CurrentBMSState;
lCurrentStateB := lControllerBMSB.CurrentBMSState;

lSOCA := lControllerBMSA.PackSOC;
lSOCB := lControllerBMSB.PackSOC;
lSOCMismatch := ABS(lSOCA - lSOCB);
lSOCInbalance := ABS(lSOCA/lSOCB);

IF (lSOCMismatch>lSOCMismatchThreshold.Value) THEN
	lAlarmBMSSOCMismatch.trigger(FALSE);
END_IF

lVoltageA := lControllerBMSA.PackVoltage;
lVoltageB := lControllerBMSB.PackVoltage;
lVoltageMismatch := ABS(lVoltageA-lVoltageB);
lVoltageInbalance := ABS(lVoltageA/lVoltageB);

IF (lVoltageMismatch>lVoltageMismatchThreshold.Value) THEN
	lAlarmBMSVoltageMismatch.trigger(FALSE);
END_IF

lCurrentA := lControllerBMSA.PackCurrent;
lCurrentB := lControllerBMSB.PackCurrent;
lCurrentMismatch := ABS(lCurrentA-lCurrentB);
lCurrentInbalance := ABS(lCurrentA/lCurrentB);

enableBMSA := UINT_TO_BOOL(lEnableBMS.Value AND 16#1);
enableBMSB := UINT_TO_BOOL(lEnableBMS.Value AND 16#2);

IF ((enableBMSA) AND (NOT(enableBMSB))) THEN
	operatorA();
ELSIF ((enableBMSB) AND (NOT(enableBMSA))) THEN
	operatorB();
ELSIF ((enableBMSB) AND (enableBMSA)) THEN
	operatorAB();
ELSE
	operatorNull();
END_IF

processRequestedBMSState();

lControllerBMSA.RequestedBMSChargeState := lRequestedBMSChargeState;
lControllerBMSB.RequestedBMSChargeState := lRequestedBMSChargeState;

lControllerBMSA.CurrentTMSState := lRequestedTMSState;
lControllerBMSB.CurrentTMSState := lRequestedTMSState;

lCurrentState := lControllerBMSA.CurrentBMSState;

IF (lCurrentState=cBMSStateConnected) THEN
	lAvailability := lAvailabilityFactor.Value;
ELSE
	lAvailability := 0.0;
END_IF

_operatorA();

SUPER^.operator();

lTargetStateA := lRequestedState;
lTargetStateB := cBMSStateDisconnected;

lCurrentState := MAX(lCurrentStateA,lCurrentStateB);

lAvailability := 0.0;
IF (lCurrentStateA=cBMSStateConnected) THEN
	lAvailability := MIN(lAvailability + lAvailabilityFactor.Value,1.0);
END_IF
IF (lCurrentStateB=cBMSStateConnected) THEN
	lAvailability := MIN(lAvailability + lAvailabilityFactor.Value,1.0);
END_IF

IF ((lCurrentStateA=cBMSStateConnected) AND
	(lCurrentStateB<>cBMSStateConnected)) THEN
	_operatorA();

ELSIF ((lCurrentStateB=cBMSStateConnected) AND
	(lCurrentStateA<>cBMSStateConnected)) THEN
	_operatorB();

ELSIF ((lCurrentStateB=cBMSStateConnected) AND
	(lCurrentStateA=cBMSStateConnected)) THEN
	_operatorAB();

ELSE
	lSOC := (lSOCA + lSOCB)/2.0;
	lSOCMin := MIN(lSOCA,lSOCB);
	lSOCMax := MAX(lSOCA,lSOCB);

	lVoltage := (lVoltageA + lVoltageB)/2.0;
	lVoltageMin := MIN(lVoltageA,lVoltageB);
	lVoltageMax := MAX(lVoltageA,lVoltageB);

	lCurrent := lCurrentA + lCurrentB;
	lCurrentMin := MIN(lCurrentA,lCurrentB);
	lCurrentMax := MAX(lCurrentA,lCurrentB);

	_operatorNull();
END_IF

SUPER^.operator();

resolveRequestedBMSState();

lCurrentState := lControllerBMSB.CurrentBMSState;

IF (lCurrentState=cBMSStateConnected) THEN
	lAvailability := lAvailabilityFactor.Value;
ELSE
	lAvailability := 0.0;
END_IF

_operatorB();

SUPER^.operator();

lTargetStateA := cBMSStateDisconnected;
lTargetStateB := lRequestedState;

IF (lControllerBMSA.RequestedTMSState=lControllerBMSB.RequestedTMSState) THEN
	lRequestedTMSState := lControllerBMSA.RequestedTMSState;
	lRequestedCoolantTemperature := MIN(lControllerBMSA.PackCoolantTemperatureTarget,lControllerBMSB.PackCoolantTemperatureTarget);

	IF (lRequestedTMSState=cTMSStateHeating) THEN
		lRequestedCoolantTemperature := MAX(lControllerBMSA.PackCoolantTemperatureTarget,lControllerBMSB.PackCoolantTemperatureTarget);
	END_IF

	RETURN;
END_IF

IF (lControllerBMSA.RequestedTMSState<>lControllerBMSB.RequestedTMSState) THEN
	lAlarmTMSStateMismatch.trigger(FALSE); // foobar any further action
END_IF

IF ((lControllerBMSA.RequestedTMSState=cTMSStateCooling) OR
	(lControllerBMSB.RequestedTMSState=cTMSStateCooling)) THEN
	lRequestedTMSState := cTMSStateCooling;
	lRequestedCoolantTemperature := MIN(lControllerBMSA.PackCoolantTemperatureTarget,lControllerBMSB.PackCoolantTemperatureTarget);
	RETURN;
END_IF

IF ((lControllerBMSA.RequestedTMSState=cTMSStateHeating) OR
	(lControllerBMSB.RequestedTMSState=cTMSStateHeating)) THEN
	lRequestedTMSState := cTMSStateHeating;
	lRequestedCoolantTemperature := MAX(lControllerBMSA.PackCoolantTemperatureTarget,lControllerBMSB.PackCoolantTemperatureTarget);
	RETURN;
END_IF

lRequestedCoolantTemperature := MIN(lControllerBMSA.PackCoolantTemperatureTarget,lControllerBMSB.PackCoolantTemperatureTarget);

IF ((lControllerBMSA.RequestedTMSState=cTMSStateCirculation) OR
	(lControllerBMSB.RequestedTMSState=cTMSStateCirculation)) THEN
	lRequestedTMSState := cTMSStateCirculation;
	RETURN;
END_IF

lRequestedTMSState := cTMSStateShutdown;

lCurrentState := lRequestedState;

lAvailability := 0.0;
lSOC := 0.0;
lSOCMin := 0;
lSOCMax := 0;
lVoltage := 0.0;
lVoltageMin := 0;
lVoltageMax := 0;


_operatorNull();

SUPER^.operator();

lTargetStateA := cBMSStateDisconnected;
lTargetStateB := cBMSStateDisconnected;

IF (lRequestedState<>cBMSStateConnected) THEN
	lTargetStateA := lRequestedState;
	lTargetStateB := lRequestedState;

	RETURN;
END_IF

IF ((gSystemServices.SystemState.State<=cSystemStatePreparing) AND
	(NOT(lDisableVoltageMismatchManagement.Value))) THEN

	IF (lVoltageA>(lVoltageB+lVoltageMismatchThreshold.Value)) THEN
		IF (gSystemServices.SystemState.ChargingEnabled) THEN
			lTargetStateA := cBMSStateDisconnected;
			lTargetStateB := cBMSStateConnected;		
		ELSE
			lTargetStateA := cBMSStateConnected;
			lTargetStateB := cBMSStateDisconnected;
		END_IF

		RETURN;
	END_IF

	IF (lVoltageB>(lVoltageA+lVoltageMismatchThreshold.Value)) THEN
		IF (gSystemServices.SystemState.ChargingEnabled) THEN
			lTargetStateA := cBMSStateConnected;
			lTargetStateB := cBMSStateDisconnected;
		ELSE
			lTargetStateA := cBMSStateDisconnected;
			lTargetStateB := cBMSStateConnected;
		END_IF

		RETURN;
	END_IF
END_IF

IF (lCurrentStateA<cBMSStateDisconnected) THEN
	lTargetStateA := cBMSStateDisconnected;
ELSE
	lTargetStateA := cBMSStateConnected;
END_IF

IF (lCurrentStateB<cBMSStateDisconnected) THEN
	lTargetStateB := cBMSStateDisconnected;
ELSE
	lTargetStateB := cBMSStateConnected;
END_IF

IF ((lTargetStateA=lCurrentStateA) AND
	(lTargetStateB=lCurrentStateB)) THEN
	lSwitchingStateTimer.reset();	
END_IF
lSwitchingStateTimer.operator();

IF (lTargetStateA<>cBMSStateConnected) THEN
	lRequestedStateA := lTargetStateA;
ELSE
	IF (lSwitchingStateTimer.Expired) THEN
		lRequestedStateA := lTargetStateA;
	ELSE
		lRequestedStateA := lCurrentStateA;
	END_IF
END_IF

IF (lTargetStateB<>cBMSStateConnected) THEN
	lRequestedStateB := lTargetStateB;
ELSE
	IF (lSwitchingStateTimer.Expired) THEN
		lRequestedStateB := lTargetStateB;
	ELSE
		lRequestedStateB := lCurrentStateB;
	END_IF
END_IF

lControllerBMSA.RequestedBMSState := lRequestedStateA;	
lControllerBMSB.RequestedBMSState := lRequestedStateB;

lAlarmCoolantReservoirLow.initializeState(NopSelf,'',cACCoolantReservoir);
lAlarmCoolantReservoirLow.Life := 10;
lAlarmCoolantReservoirLow.InitialSeverity := cSeverityNone;
lAlarmCoolantReservoirLow.SeverityWarningTimeout := T#1S;
lAlarmCoolantReservoirLow.SeverityErrorTimeout := T#2S;
lAlarmCoolantReservoirLow.SeverityCriticalTimeout := T#2H;

lAlarmSecondaryPowerFailHeatingCooling.InitialSeverity := cSeverityWarning;
lAlarmSecondaryPowerFailHeatingCooling.SeverityWarningTimeout := T#1S;
lAlarmSecondaryPowerFailHeatingCooling.initializeState(NopSelf,'',cACCoolantSecondaryPowerFailHeatingCooling);
lAlarmSecondaryPowerFailHeatingCooling.Life := 10;
lAlarmSecondaryPowerFailHeatingCooling.SeverityErrorTimeout := T#2S;
lAlarmSecondaryPowerFailHeatingCooling.SeverityCriticalTimeout := T#5S;

lAlarmSecondaryPowerFailPump.initializeState(NopSelf,'',cACCoolantSecondaryPowerFailPump);
lAlarmSecondaryPowerFailPump.Life := 10;
lAlarmSecondaryPowerFailPump.InitialSeverity := cSeverityWarning;
lAlarmSecondaryPowerFailPump.SeverityWarningTimeout := T#1S;
lAlarmSecondaryPowerFailPump.SeverityErrorTimeout := T#2S;
lAlarmSecondaryPowerFailPump.SeverityCriticalTimeout := T#5S;

lDiagnosticTMSCooling.initializeState(NopSelf,'',cDCTMSCooling);
lDiagnosticTMSHeating.initializeState(NopSelf,'',cDCTMSHeating);
lDiagnosticBMSTMSCooling.initializeState(NopSelf,'',cDCBMSTMSCooling);
lDiagnosticBMSTMSHeating.initializeState(NopSelf,'',cDCBMSTMSHeating);
lDiagnosticBMSTMSNoCirculation.initializeState(NopSelf,'',cDCBMSTMSNoCirculation);

lAlarmCoolantHeating.initializeState(NopSelf,'',cACCoolantHeating);
lAlarmCoolantHeating.InitialSeverity := cSeverityNone;
lAlarmCoolantHeating.SeverityWarningTimeout := T#1S;
lAlarmCoolantHeating.SeverityErrorTimeout := T#2S;
lAlarmCoolantHeating.SeverityCriticalTimeout := T#5S;

lAlarmCoolantChilling.initializeState(NopSelf,'',cACCoolantChilling);
lAlarmCoolantChilling.InitialSeverity := cSeverityNone;
lAlarmCoolantChilling.SeverityWarningTimeout := T#1S;
lAlarmCoolantChilling.SeverityErrorTimeout := T#2S;
lAlarmCoolantChilling.SeverityCriticalTimeout := T#5S;

lAlarmCoolantTempHotCutback.initializeState(NopSelf,'',cACCoolantTempHotCutback);
lAlarmCoolantTempHotCutback.Qualifier := cChargeQualifierBoth;
lAlarmCoolantTempHotCutback.InitialCutbackThreshold :=cCoolantTempHotInitialCutbackThreshold;
lAlarmCoolantTempHotCutback.CutoutThreshold := cCoolantTempHotCutoutThreshold;
lAlarmCoolantTempHotCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);
lAlarmCoolantTempHotCutback.registerServer(gSystemPrimary.Lift.ChargeInterlock);

lAlarmCoolantTempColdCutback.initializeState(NopSelf,'',cACCoolantTempColdCutback);
lAlarmCoolantTempColdCutback.Qualifier := cChargeQualifierBoth;
lAlarmCoolantTempColdCutback.InitialCutbackThreshold :=cCoolantTempColdInitialCutbackThreshold;
lAlarmCoolantTempColdCutback.CutoutThreshold := cCoolantTempColdCutoutThreshold;
lAlarmCoolantTempColdCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);
lAlarmCoolantTempColdCutback.registerServer(gSystemPrimary.Lift.ChargeInterlock);

lVROverrideControl.initializeValueReference(lOverrideControl,NopSelf,'OvrdControl','Override TMS automatic control','',cValueStyleParameter);

lRequestedState.EnumType := cEnumTypeTMSState;
lRequestedState.initializeValueObject(NopSelf,'ReqState','Requested TMS state','',cValueStyleConfigurable);

lCurrentState.EnumType := cEnumTypeTMSState;
lCurrentState.initializeValueObjectOp(OpSelf,'CurrState','Current TMS state','',cValueStyleConfigurable);

lCoolantReservoir.initializeValueObjectOp(OpSelf,'ClntReservoir','Battery coolant reservoir state','',cValueStyleConfigurable);

lCurrentCoolantTemperature.Offset := -22.522;
lCurrentCoolantTemperature.Scaling := 0.0314;
lCurrentCoolantTemperature.initializeValueObjectOp(OpSelf,'ClntTemp','Battery coolant temperature','celcius',cValueStyleConfigurable);

lCoolantTemperatureCriticalUpper.Threshold := cCoolantTempCriticalUpperThreshold;
lCoolantTemperatureCriticalUpper.Hysteresis := cCoolantTempCriticalUpperHysteresis;
lCoolantTemperatureCriticalUpper.BelowIsOn := FALSE;
lCoolantTemperatureCriticalUpper.initializeValueObject(NopSelf,'ClntTempHot','Battery coolant temperature is hot','',cValueStyleConfigurable);

lCoolantTemperatureCriticalLower.Threshold := cCoolantTempCriticalLowerThreshold;
lCoolantTemperatureCriticalLower.Hysteresis := cCoolantTempCriticalLowerHysteresis;
lCoolantTemperatureCriticalLower.BelowIsOn := TRUE;
lCoolantTemperatureCriticalLower.initializeValueObject(NopSelf,'ClntTempCold','Battery coolant temperature is cold','',cValueStyleConfigurable);

lCoolantPump.initializeValueObjectOp(OpSelf,'Pump','Battery coolant pump is running','',cValueStyleConfigurable);

lCoolantHeating.CheckEnable := TRUE;
lCoolantHeating.CheckCritical := TRUE;
lCoolantHeating.CheckPeriod := cRelayCoilTimeout;
lCoolantHeating.initializeValueObjectOp(OpSelf,'Heating','Battery coolant heater is running','',cValueStyleConfigurable);

lCoolantChilling.initializeValueObjectOp(OpSelf,'Chilling','Battery coolant chiller is running','',cValueStyleConfigurable);

SUPER^.initialize();
SubSystem := cSubsystemBattery;

lRequestedState.Value := cTMSStateShutdown;
lCurrentState.Value := cTMSStateShutdown;

lRequestedCoolantTemperature := gSystemPrimary.BMS.RequestedCoolantTemperature; //foobar ignored

lRequestedState.Value := gSystemPrimary.BMS.RequestedTMSState;
lRequestedState.operator();

CASE RequestedState OF
	cTMSStateShutdown:
		lCoolantPump.off();
		lCoolantHeating.off();
		lCoolantChilling.off();

		IF (gSystemPrimary.SystemState.State=cSystemStateOperational) THEN
			lDiagnosticBMSTMSNoCirculation.trigger(FALSE);
		END_IF

	cTMSStateCooling:
		lCoolantPump.on();
		lCoolantHeating.off();
		lCoolantChilling.on();
		lDiagnosticBMSTMSCooling.trigger(FALSE);

	cTMSStateHeating:
		lCoolantPump.on();
		lCoolantHeating.on();
		lCoolantChilling.off();
		lDiagnosticBMSTMSHeating.trigger(FALSE);

	cTMSStateCirculation:
		lCoolantPump.on();
		lCoolantHeating.off();
		lCoolantChilling.off();
END_CASE
lCurrentState.Value := RequestedState;

// following are TMS-independent actions that override instructions from the rest of the system

lCoolantTemperatureCriticalUpper.Input := lCurrentCoolantTemperature.Value;
IF (lCoolantTemperatureCriticalUpper.Value) THEN
	lCoolantPump.on();
	lCoolantHeating.off();
	lCoolantChilling.on();
	lDiagnosticTMSCooling.trigger(FALSE);

	lCurrentState.Value := cTMSStateCooling;
END_IF

lCoolantTemperatureCriticalLower.Input := lCurrentCoolantTemperature.Value;
IF (lCoolantTemperatureCriticalLower.Value) THEN
	lCoolantPump.on();
	lCoolantHeating.on();
	lCoolantChilling.off();
	lDiagnosticTMSHeating.trigger(FALSE);

	lCurrentState.Value := cTMSStateHeating;
END_IF

IF (gSystemPrimary.SystemState.State>=cSystemStatePreparing) THEN
	lCoolantPump.on();
END_IF

// checks on TMS-independent actions

IF ((lOverrideControl) OR
	(gSystemPrimary.BMS.Availability=0)) THEN
	lCurrentState.Value := cTMSStateShutdown;	

	lCoolantPump.off();
	lCoolantHeating.off();
	lCoolantChilling.off();
END_IF

IF (((lCoolantHeating.Value) OR (lCoolantChilling.Value)) AND
	(gSystemPrimary.lSecondaryPowerSupply.Availability<cSecondaryRequiredAvailabilityHeatingCooling)) THEN	
	lAlarmSecondaryPowerFailHeatingCooling.trigger(FALSE);

	lCoolantHeating.off();
	lCoolantChilling.off();	
END_IF

IF ((lCoolantPump.Value) AND
	(gSystemPrimary.lSecondaryPowerSupply.Availability<cSecondaryRequiredAvailabilityPump)) THEN
	lAlarmSecondaryPowerFailPump.trigger(FALSE);

	lCoolantPump.off();
END_IF

SUPER^.operator();

gSystemPrimary.BMS.CurrentTMSState := CurrentState;
gSystemPrimary.BMS.CurrentCoolantTemperature := lCurrentCoolantTemperature.Value;

lAlarmCoolantTempColdCutback.Value := lCurrentCoolantTemperature.Value;
lAlarmCoolantTempColdCutback.test(FALSE);

lAlarmCoolantTempHotCutback.Value := lCurrentCoolantTemperature.Value;
lAlarmCoolantTempHotCutback.test(FALSE);

IF ((gSystemPrimary.lSensorSupply.OK) AND
	(NOT(lCoolantReservoir.Value))) THEN
	lAlarmCoolantReservoirLow.trigger(FALSE);
END_IF

IF (lCoolantHeating.lError) THEN
	IF (RequestedState=cTMSStateHeating) THEN
		lCurrentState.Value := cTMSStateCirculation;
	END_IF

	lAlarmCoolantHeating.trigger(FALSE);
END_IF

IF (FALSE) THEN // foobar, a different way of checking chilling function is required
	IF (RequestedState=cTMSStateCooling) THEN
		lCurrentState.Value := cTMSStateCirculation;
	END_IF

	lAlarmCoolantChilling.trigger(FALSE);
END_IF

lCurrentCoolantTemperature.InputReference REF= inputCoolantTemperature;
lCoolantReservoir.InputReference REF= inputCoolantReservoir;

lCoolantPump.OutputReference REF= outputCoolantPump;
lCoolantHeating.OutputReference REF= outputCoolantHeating;
lCoolantHeating.CheckReference REF= inputCheckCoolantHeating;
lCoolantChilling.OutputReference REF= outputCoolantChillerA;

IF ((lCurrentOBCState<>lPreviousOBCState) AND
	(lPreviousOBCState=cOBCStateDisconnected)) THEN
	gSystemPrimary.BMS.resetSOCRecovery();
END_IF
lPreviousOBCState := lCurrentOBCState;

gSystemPrimary.SystemState.ChargingEnabled := (lCurrentOBCState<>cOBCStateDisconnected);

CASE (lCurrentOBCState) OF
	cOBCStateDisconnected:
		IF (gSystemPrimary.SystemState.State=cSystemStateCharging) THEN
			lCausalChargerDisconnected.trigger(FALSE);
			gSystemPrimary.SystemState.transitionForceMax(cSystemStatePreparing,ADR(lCausalChargerDisconnected),lCausalChargerDisconnected.Override);
		END_IF
		lChargingCurrentTarget := 0.0;
		lChargingVoltageTarget := 0.0;

		lChargerDiagnostic := cChargingDiagnosticDisconnected;

		IF (NOT(Operational)) THEN
			lChargerDiagnostic := cChargingDiagnosticNotOperational;
		END_IF

	cOBCStateError:
		lAlarmChargerOBCError.trigger(FALSE);
		lChargerDiagnostic := cChargingDiagnosticConnectedError;

 cOBCStateStandby:
 		lCausalChargerStandby.trigger(FALSE);
		lChargerDiagnostic := cChargingDiagnosticConnectedStandby;

	cOBCStateCharging:
		lCausalChargerConnected.trigger(FALSE);
		lChargerDiagnostic := cChargingDiagnosticConnected;
END_CASE

IF (gSystemPrimary.SystemState.State<>cSystemStateCharging) THEN
	lRequestedOBCState := cOBCStateStandby;
	lRequestedBMSChargeState := cBMSChargeStateShutdown;

	lChargingCurrentTarget := 0.0;
	lChargingVoltageTarget := 0.0;

	lChargerDiagnostic := cChargingDiagnosticNotInChargingState;

	RETURN;
END_IF

IF ((gSystemPrimary.BMS.SOCMax>=lTargetChargeLevel) OR
	((lCurrentBMSChargeState=cBMSChargeStateShutdown) AND
	(gSystemPrimary.BMS.SOCMax>=(lTargetChargeLevel-cTargetChargeLevelHysteresis)))) THEN
	lRequestedOBCState := cOBCStateStandby;
	lRequestedBMSChargeState := cBMSChargeStateShutdown;

	lChargingCurrentTarget := 0.0;
	lChargingVoltageTarget := 0.0;

	lChargerDiagnostic := cChargingDiagnosticTargetSOCReached;

	RETURN;
END_IF

lRequestedBMSChargeState := lTargetBMSChargeState;
IF (lCurrentBMSChargeState=cBMSChargeStateShutdown) THEN
	lChargingCurrentTarget := 0.0;
	lChargingVoltageTarget := 0.0; // foobar, make sure this cannot be overwritten

	lChargerDiagnostic := cChargingDiagnosticBMSShutdown;

	RETURN;
END_IF

IF (lChargingCurrentTarget<>0.0) THEN
	lChargerDiagnostic := cChargingDiagnosticConnectedCharging;
END_IF

lRequestedOBCState := cOBCStateCharging;

lVREnableManualNotBMSCharging.initializeValueReference(lEnableManualNotBMSCharging,NopSelf,'EnblManualChrg','Enable manual charging control','',cValueStyleParameter);
lVRManualChargingCurrentTarget.initializeValueReference(lManualChargingCurrentTarget,NopSelf,'ManualChrgCurr','Manual charging current','amps',cValueStyleParameter);
lVRManualChargingVoltageTarget.initializeValueReference(lManualChargingVoltageTarget,NopSelf,'ManualChrgVolt','Manual charging voltage','volts',cValueStyleParameter);

lAlarmChargerOBCError.initializeState(NopSelf,'',cACChargerOBCError);
lAlarmChargerOBCError.Control := cSystemControlStop;
lAlarmChargerOBCError.AllowableSystemState := cSystemStateCharging;

lCausalChargerStandby.initializeState(NopSelf,'',cCCChargerStandby);
lCausalChargerStandby.Control := cSystemControlStop;
lCausalChargerStandby.AllowableSystemState := cSystemStateCharging;

lCausalChargerConnected.initializeState(NopSelf,'',cCCChargerConnected);
lCausalChargerConnected.Control := cSystemControlStop;
lCausalChargerConnected.AllowableSystemState := cSystemStateCharging;

lCausalChargerDisconnected.initializeState(NopSelf,'',cCCChargerDisconnected);

SUPER^.initialize();
SubSystem := cSubsystemBattery;

lCurrentBMSChargeState := gSystemPrimary.BMS.CurrentBMSChargeState;
lChargingCurrentTarget := gSystemPrimary.BMS.ChargingCurrentTarget;
lChargingVoltageTarget := gSystemPrimary.BMS.ChargingVoltageTarget;

_operator();

gSystemPrimary.BMS.RequestedBMSChargeState := lRequestedBMSChargeState;

IF (lEnableManualNotBMSCharging) THEN
	lRequestedOBCState := cOBCStateCharging;
	lChargingCurrentTarget := lManualChargingCurrentTarget;
	lChargingVoltageTarget := lManualChargingVoltageTarget;
END_IF

IF (NOT(__ISVALIDREF(lControllerChargerA))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lTargetBMSChargeState := cBMSChargeStateAC;

lCurrentOBCState := lControllerChargerA.CurrentOBCState;

SUPER^.operator();

lControllerChargerA.RequestedOBCState := lRequestedOBCState;
lControllerChargerA.ChargingCurrentMax := lChargingCurrentTarget;
lControllerChargerA.ChargingVoltageMax := lChargingVoltageTarget;

IF ((NOT(__ISVALIDREF(lControllerChargerA))) OR
	(NOT(__ISVALIDREF(lControllerChargerB))) OR
	(NOT(__ISVALIDREF(lControllerChargerC)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lTargetBMSChargeState := cBMSChargeStateAC;

lCurrentOBCState := lControllerChargerA.CurrentOBCState;

SUPER^.operator();

lControllerChargerA.RequestedOBCState := lRequestedOBCState;
lControllerChargerA.ChargingCurrentMax := lChargingCurrentTarget/3.0;
lControllerChargerA.ChargingVoltageMax := lChargingVoltageTarget;

lControllerChargerB.RequestedOBCState := lRequestedOBCState;
lControllerChargerB.ChargingCurrentMax := lChargingCurrentTarget/3.0;
lControllerChargerB.ChargingVoltageMax := lChargingVoltageTarget;

lControllerChargerC.RequestedOBCState := lRequestedOBCState;
lControllerChargerC.ChargingCurrentMax := lChargingCurrentTarget/3.0;
lControllerChargerC.ChargingVoltageMax := lChargingVoltageTarget;

lControllerChargerA REF= controllerChargerA;
lControllerChargerB REF= controllerChargerB;
lControllerChargerC REF= controllerChargerC;

