ST.xhtml:
lAlarmBMSRequestDisconnect.initializeState(NopSelf,'',cACBMSRequestDisconnect);
lAlarmBMSRequestDisconnect.Life := 10;
lAlarmBMSRequestDisconnect.InitialSeverity := cSeverityError;
lAlarmBMSRequestDisconnect.SeverityWarningTimeout := T#0S;
lAlarmBMSRequestDisconnect.SeverityErrorTimeout := T#5S;
lAlarmBMSRequestDisconnect.SeverityCriticalTimeout := T#25S;

lAlarmChargeAvailabilityLimited.initializeState(NopSelf,'',cBMSChargeAvailabilityLimited);
lAlarmChargeAvailabilityLimited.Life := 10;

lAlarmChargeAvailabilityLimitedSevere.initializeState(NopSelf,'',cBMSChargeAvailabilityLimitedSevere);
lAlarmChargeAvailabilityLimitedSevere.Life := 10;

lAlarmDischargeAvailabilityLimited.initializeState(NopSelf,'',cBMSDischargeAvailabilityLimited);
lAlarmDischargeAvailabilityLimited.Life := 10;

lAlarmDischargeAvailabilityLimitedSevere.initializeState(NopSelf,'',cBMSDischargeAvailabilityLimitedSevere);
lAlarmDischargeAvailabilityLimitedSevere.Life := 10;

