SUPER^.initialize();
SubSystem := cSubsystemBattery;

lPeripheral.initialize();

lAlarmCANOpenSlaveNotOperational.InitialSeverity := cSeverityNone;
lAlarmCANOpenSlaveNotOperational.SeverityWarningTimeout := T#250MS;
lAlarmCANOpenSlaveNotOperational.SeverityErrorTimeout := T#1S;
lAlarmCANOpenSlaveNotOperational.SeverityCriticalTimeout := T#5S;

lAlarmCANOpenSlaveAllowableUp.AllowableSystemState := cSystemStatePreparing;
lAlarmCANOpenSlaveAllowableUp.UpperSystemStateScope := cSystemStatePreparing;
lAlarmCANOpenSlaveAllowableUp.LowerSystemStateScope := cSystemStatePreparing;

lStartSystemStateScope := t_system_state.cSystemStatePreparing;
lOperationalSystemStateScopeLower := t_system_state.cSystemStateCharging;
lModulationSystemStateScope := t_system_state.cSystemStateCharging;

lModulationSeverity := cSeverityError;

lEnableValidTransmissions := TRUE;
lEnableDetectionTPDO := TRUE;
lEnableNMTDetectionTPDO := TRUE;
lEnableNMTOverrideTPDO := TRUE;

lContextPtr := ADR(lContext);
lContextIndex := 0;
lFaultNumber := 0;
lFaultCode := 0;
lCollected := false;

SUPER^.operator();

lPeripheral.operator();

IF (NOT(ValidTransmissions)) THEN
	lCurrentBMSState.Value := cBMSStateShutdown;
END_IF

IF (lCurrentBMSState.Value<cBMSStateDisconnected) THEN
	lRequestedTMSState.Value := cTMSStateShutdown;
	lCurrentBMSChargeState.Value := cBMSChargeStateShutdown;
	lRequestDisconnect.Value := FALSE;

	lFaultLevel.Value := cBMSFaultLevelNone;
	lPackFaultNumber.Value := 0;
	lPackFaultCode.Value := 0;
	lFaultCharger.Value := FALSE;
	lFaultContactor.Value := FALSE;

	lPackSOC.Value := 0.0;
	lPackSOH.Value := 1.0;

	lPackCurrent.Value:= 0.0;
	lPackChargeCurrentLimit.Value := 0.0;
	lPackDischargeCurrentLimit.Value := 0.0;
	lPackVoltage.Value := 0.0;

	RETURN;
END_IF

IF ((gSystemPrimary.SystemState.State>cSystemStatePreparing) AND
	(RequestDisconnect)) THEN
	lAlarmBMSRequestDisconnect.trigger(FALSE);

	IF (lAlarmBMSRequestDisconnect.Severity>=cSeverityCritical) THEN
		lRequestedBMSState.Value := cBMSStateDisconnected;
	END_IF
END_IF

lChargeAvailability := lPackChargeCurrentLimit.Value/cChargeCurrentLimit;
IF (lChargeAvailability<cAvailabilityLimitedSevere) THEN
	lAlarmChargeAvailabilityLimitedSevere.trigger(FALSE);
ELSIF (lChargeAvailability<1.0) THEN
	lAlarmChargeAvailabilityLimited.trigger(FALSE);
END_IF

lDischargeAvailability := lPackChargeCurrentLimit.Value/cDischargeCurrentLimit;
IF (lDischargeAvailability<cAvailabilityLimitedSevere) THEN
	lAlarmDischargeAvailabilityLimitedSevere.trigger(FALSE);
ELSIF (lDischargeAvailability<1.0) THEN
	lAlarmDischargeAvailabilityLimited.trigger(FALSE);
END_IF

//foostrip lChargeEnergy.integrate(PackChargeCurrent,PackVoltage);
//lDischargeEnergy.integrate(PackDischargeCurrent,PackVoltage);

IF (lPackFaultNumber.Value<>lFaultNumber) THEN
	lFaultNumber := lPackFaultNumber.Value;
	lFaultCode := 0;
	lContextIndex := 0;
	lContext := 0;
	lCollected := FALSE;

	for i:= 0 to 7 do
		lFaults[i] := 0;
	END_FOR
END_IF

IF (lFaultNumber=0) THEN
	RETURN;
END_IF

IF (lFaultCode<>lPackFaultCode.Value) THEN
	lFaultCode := lPackFaultCode.Value;

	IF (lContextIndex<cContextSize) THEN
		lContextPtr := ADR(lContext);
		lContextPtr := lContextPtr + lContextIndex;

		lContextPtr^ := INT_TO_BYTE(lFaultCode);
		lFaults[lContextIndex] := lFaultCode;
	END_IF

	lContextIndex := lContextIndex + 1;
END_IF

IF (lContextIndex>=lFaultNumber) THEN
	lContextIndex := 0;
	lCollected := TRUE;
END_IF

IF (lCollected) THEN
	lAlarmBMSFault.triggerWithContext(lContext);
END_IF

lCurrentBMSState.InputReference REF= gateway2PLCState1;
lRequestedTMSState.InputReference REF= gateway2PLCState1;
lCurrentBMSChargeState.InputReference REF= gateway2PLCState1;

lBalancing.InputReference REF= gateway2PLCState1;
lRequestDisconnect.InputReference REF= gateway2PLCState1;

lFaultCharger.InputReference REF= gateway2PLCState2;
lFaultContactor.InputReference REF= gateway2PLCState2;
lFaultLevel.InputReference REF= gateway2PLCState2;

lPackCurrent.InputReference REF= packCurrent;
lPackChargeCurrentLimit.InputReference REF= packChargeCurrentLimit;
lPackDischargeCurrentLimit.InputReference REF= packDischargeCurrentLimit;
lPackVoltage.InputReference REF= packVoltage;

lPackAverageTemperature.InputReference REF= packAverageTemperature;
lPackMaxTemperature.InputReference REF= packMaxTemperature;
lPackMinTemperature.InputReference REF= packMinTemperature;

lPackSOC.InputReference REF= packSOC;
lPackSOH.InputReference REF= packSOH;

lPackChargingCurrentTarget.InputReference REF= packChargingCurrentTarget;
lPackChargingVoltageTarget.InputReference REF= packChargingVoltageTarget;
lPackCoolantTemperatureTarget.InputReference REF= packCoolantTemperatureTarget;

lPackTotalChargeEnergy.InputReferenceA REF= packTotalChargeEnergyA;
lPackTotalChargeEnergy.InputReferenceB REF= packTotalChargeEnergyB;
lPackTotalChargeEnergy.InputReferenceC REF= packTotalChargeEnergyC;

lPackTotalDischargeEnergy.InputReferenceA REF= packTotalDischargeEnergyA;
lPackTotalDischargeEnergy.InputReferenceB REF= packTotalDischargeEnergyB;
lPackTotalDischargeEnergy.InputReferenceC REF= packTotalDischargeEnergyC;

lPackFaultNumber.InputReference REF= packFaultNumber;
lPackFaultCode.InputReference REF= packFaultCode;

lRequestedBMSState.OutputReference REF= pLC2GatewayState;
lCurrentTMSState.OutputReference REF= pLC2GatewayState;
lRequestedBMSChargeState.OutputReference REF= pLC2GatewayState;

lCurrentCoolantTemperature.OutputReference REF= coolantTemperature;

lPackChargingCurrentTarget.Override := FALSE;

IF (Operational) THEN
	IF ((RequestedBMSChargeState<>cBMSChargeStateShutdown) AND (lOverrideBMSChargeStateControl)) THEN
		CurrentBMSChargeState := RequestedBMSChargeState;
		lPackChargingCurrentTarget.Override := TRUE;
	ELSE
		CurrentBMSChargeState := lCurrentBMSChargeState.Value;
	END_IF
ELSE
	CurrentBMSChargeState := cBMSChargeStateShutdown;	
END_IF

IF (Operational) THEN
	CurrentBMSState := lCurrentBMSState.Value;
ELSE
	CurrentBMSState := cBMSStateShutdown;	
END_IF

IF (Operational) THEN
	FaultCharger := lFaultCharger.Value;
ELSE
	FaultCharger := FALSE;	
END_IF

IF (Operational) THEN
	FaultContactor := lFaultContactor.Value;
ELSE
	FaultContactor := FALSE;	
END_IF

IF (Operational) THEN
	FaultLevel := lFaultLevel.Value;
ELSE
	FaultLevel := cBMSFaultLevelNone;	
END_IF

IF (Operational) THEN // foobar should this be ValidTransmissions?
	PackChargeCurrentLimit := lPackChargeCurrentLimit.Value;
ELSE
	PackChargeCurrentLimit := 0.0;	
END_IF

IF (Operational) THEN
	PackChargingCurrentTarget := lPackChargingCurrentTarget.Value;
ELSE
	PackChargingCurrentTarget := 0.0;	
END_IF

IF (Operational) THEN
	PackCurrent := lPackCurrent.Value;
ELSE
	PackCurrent := 0.0;	
END_IF

IF (Operational) THEN
	PackDischargeCurrentLimit := lPackDischargeCurrentLimit.Value;
ELSE
	PackDischargeCurrentLimit := 0.0;	
END_IF

IF (Operational) THEN
	RequestedTMSState := lRequestedTMSState.Value;
ELSE
	RequestedTMSState := cTMSStateShutdown;	
END_IF

lChargingVoltageMax.Offset := 0.0;
lChargingVoltageMax.Scaling := 10.0;
lChargingVoltageMax.initializeValueObjectOp(OpSelf,'TargVoltage','Onboard charger target voltage','volts',cValueStyleConfigurable);

lChargingCurrentMax.Offset := 0.0;
lChargingCurrentMax.Scaling := 10.0;
lChargingCurrentMax.initializeValueObjectOp(OpSelf,'TargCurrent','Onboard charger target current','amps',cValueStyleConfigurable);

lHeatingMode.Index := 0;
