lPower.initializeValueObjectOp(OpSelf,'Power','Onboard charger measured power','kW',cValueStyleConfigurable);

lDiagnosticState.initializeValueObjectOp(OpSelf,'Diagnostic','Onboard charger current diagnostic','',cValueStyleConfigurable);

lStatusCC.Index := 5;
lStatusCC.initializeValueObjectOp(OpSelf,'CC','Onboard charger CC signal','',cValueStyleConfigurable);
lStatusCC.InputReference REF= lDiagnosticState.ValueReference;

lStatusCP.Index := 6;
lStatusCP.initializeValueObjectOp(OpSelf,'CP','Onboard charger CP signal','',cValueStyleConfigurable);
lStatusCP.InputReference REF= lDiagnosticState.ValueReference;

lOBCStatus.Index := 8;
lOBCStatus.Length := 2;
lOBCStatus.EnumType := cEnumTypeOBCStatus;
lOBCStatus.initializeValueObjectOp(OpSelf,'OBCStatus','Onboard charger OBC status','',cValueStyleConfigurable);
lOBCStatus.InputReference REF= lDiagnosticState.ValueReference;

lCurrentOBCState.EnumType := cEnumTypeOBCState;
lCurrentOBCState.initializeValueObject(NopSelf,'CrrOBCStt','Onboard charger current OBC state','',cValueStyleConfigurable);

lRequestedOBCState.EnumType := cEnumTypeOBCState;
lRequestedOBCState.initializeValueObject(NopSelf,'ReqOBCStt','Onboard charger requested OBC state','',cValueStyleConfigurable);

SUPER^.initialize();
SubSystem := cSubsystemBattery;

lAlarmCANOpenSlaveNotOperational.InitialSeverity := cSeverityNone;
