lAlarmCANOpenSlaveAllowableUp.LowerSystemStateScope := cSystemStatePreparing;

lStartSystemStateScope := t_system_state.cSystemStatePreparing;
lOperationalSystemStateScopeLower := t_system_state.cSystemStateCharging;
lModulationSystemStateScope := t_system_state.cSystemStateCharging;

lModulationSeverity := cSeverityError; // foobar default or not?

lOBCStatusTimer.initialize();
lOBCStatusTimer.Enable := TRUE;
lOBCStatusTimer.Period := cOBCStatusPeriod;

SUPER^.operator();

setCurrentOBCState();

HeatingMode := FALSE;

CASE (RequestedOBCState) OF
	cOBCStateDisconnected:
		StopCharging := TRUE;	
	cOBCStateCharging:
		StopCharging := FALSE;
	cOBCStateStandby:
		StopCharging := TRUE;
	cOBCStateError:
		StopCharging := TRUE;
END_CASE

// lFaultHardware.Index := 0; 16#1
// lFaultTemperature.Index := 1; 16#2
// lFaultInputVoltage.Index := 2; 16#4
// lFaultBattery.Index := 3; 16#8
// lFaultCommunications.Index := 4; 16#10
// lWarningTemperature.Index := 14; 16#4000

// lStatusSwitch.Index := 12;
// lStatusFan.Index := 15;

IF (WORD_TO_BOOL(UINT_TO_WORD(lDiagnosticState.Value) AND 16#401F)) THEN
	lAlarmCANOpenSlaveNotify.triggerWithContext(UINT_TO_WORD(lDiagnosticState.Value));
END_IF

IF (NOT(Operational)) THEN
	CurrentOBCState := cOBCStateDisconnected;
	RETURN;
END_IF

IF (OBCStatus<>cOBCStatusNone) THEN
	lOBCStatusTimer.reset();
END_IF
lOBCStatusTimer.operator();

IF (((NOT(lOBCStatusTimer.Expired)) OR
	(lIgnoreOBCStatusNone)) AND
	(OBCStatus=cOBCStatusNone)) THEN
	lOBCStatusDerived := cOBCStatusStandby ;
ELSE
	lOBCStatusDerived := OBCStatus;
END_IF

IF (lOBCStatusDerived=cOBCStatusNone) THEN
	CurrentOBCState := cOBCStateDisconnected;
	RETURN;
END_IF

IF (StatusCC) THEN
	CurrentOBCState := cOBCStateDisconnected;
	RETURN;
END_IF

CurrentOBCState := cOBCStateStandby;

IF ((NOT(StatusCC)) AND (StatusCP)) THEN
	// foobar not powered on
	RETURN;
END_IF

IF ((NOT(StatusCP)) AND
	(NOT(StatusCC)) AND
	(OBCStatus=cOBCStatusCharging) AND
	(lEnabled)) THEN
	CurrentOBCState := cOBCStateCharging;
END_IF

IF (OBCStatus=cOBCStatusError) THEN
	CurrentOBCState := cOBCStateError;
END_IF

lVoltage.InputReference REF= voltage;
lCurrent.InputReference REF= current;
lPower.InputReference REF= power;
lDiagnosticState.InputReference REF= status;

lChargingVoltageMax.OutputReference REF= chargingVoltageMax;
lChargingCurrentMax.OutputReference REF= chargingCurrentMax;
lHeatingMode.OutputReference REF= mode;
lStopCharging.OutputReference REF= command;

