	t_motor_emcy_id.cEMCY_VDC_OFF_SHORTED,
	t_motor_emcy_id.cEMCY_HW_FAULT,
	t_motor_emcy_id.cEMCY_POWERMOS_SHORTED,
	t_motor_emcy_id.cEMCY_CTRAP_THRESHOLD,
	t_motor_emcy_id.cEMCY_OUT_MISMATCH_PU,
	t_motor_emcy_id.cEMCY_SP_MISMATCH_XX,
	t_motor_emcy_id.cEMCY_ANALOG_INPUT,
	t_motor_emcy_id.cEMCY_OVERLOAD,
	t_motor_emcy_id.cEMCY_VDC_LINK_OVERV:
		lAlarmCANOpenSlaveBlock.triggerWithContext(INT_TO_LWORD(eid));
		RETURN;

	t_motor_emcy_id.cEMCY_EB_DRIVSHRT,
	t_motor_emcy_id.cEMCY_EB_DRIVOPEN,
	t_motor_emcy_id.cEMCY_EVP_COIL_OPEN,
	t_motor_emcy_id.cEMCY_VACC_NOT_OK,
	t_motor_emcy_id.cEMCY_BMS_NOT_READY,
	t_motor_emcy_id.cEMCY_POT_MISMATCH,
	t_motor_emcy_id.cEMCY_AGV,
	t_motor_emcy_id.cEMCY_REMA_T_ALARM,
	t_motor_emcy_id.cEMCY_SENS_BAT_TEMP_KO,
	t_motor_emcy_id.cEMCY_EMERGENCY,
	t_motor_emcy_id.cEMCY_LIFT_LOWER,
	t_motor_emcy_id.cEMCY_PARAM_TRANSFER,
	t_motor_emcy_id.cEMCY_EPS_RELAY_OPEN,
	t_motor_emcy_id.cEMCY_EB_COIL_OPEN,
	t_motor_emcy_id.cEMCY_PEB_PEVP_NOT_OK,
	t_motor_emcy_id.cEMCY_PEV_NOT_OK,
	t_motor_emcy_id.cEMCY_VACC_OUT_RANGE,
	t_motor_emcy_id.cEMCY_HW_FAULT_EB,
	t_motor_emcy_id.cEMCY_CONT_DRV_EV,
	t_motor_emcy_id.cEMCY_COIL_SHOR_EVAUX,
	t_motor_emcy_id.cEMCY_EVP_DRIVER_OPEN,
	t_motor_emcy_id.cEMCY_DRV_SHOR_EV,
	t_motor_emcy_id.cEMCY_NO_CAN_WR_MSGXX,
	t_motor_emcy_id.cEMCY_STO_SS1_ALARM_XX,
	t_motor_emcy_id.cEMCY_WRONG_PERFORM,
	t_motor_emcy_id.cEMCY_WRONG_SLAVE_VER,
	t_motor_emcy_id.cEMCY_MS_PAR_CHK_MISM,
	t_motor_emcy_id.cEMCY_CURRENT_PROFILE,
	t_motor_emcy_id.cEMCY_EEPROM_KO,
	t_motor_emcy_id.cEMCY_COIL_SHOR_EB,
	t_motor_emcy_id.cEMCY_STO_SS1_ACTIVEXX,
	t_motor_emcy_id.cEMCY_RPM_HIGH,
	t_motor_emcy_id.cEMCY_STALL_ROTOR,
	t_motor_emcy_id.cEMCY_INCORRECT_START,
	t_motor_emcy_id.cEMCY_FORW_BACK,
	t_motor_emcy_id.cEMCY_MOTOR_TEMP_STOP:
		lAlarmCANOpenSlaveBlock.triggerWithContext(INT_TO_LWORD(eid));
		IF (first) THEN
			lAlarmCANOpenSlaveStop.triggerWithContext(INT_TO_LWORD(eid));
		END_IF

		RETURN;

	t_motor_emcy_id.cEMCY_THERMIC_SENS_KO,
	t_motor_emcy_id.cEMCY_THERMPUSENSKO,
	t_motor_emcy_id.cEMCY_SENS_MOT_TEMP_KO:
		lAlarmCANOpenSlaveBlock.triggerWithContext(INT_TO_LWORD(eid));; //foobar disable remedy
		RETURN;
END_CASE

lAlarmCANOpenSlaveNotify.triggerWithContext(INT_TO_LWORD(eid));

	//t_motor_emcy_id.cEMCY_REMA_T_ALARM,								//duplicate id
	//	lAlarmCANOpenStop.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_SP_MISMATCH_PUMP,                     //duplicate id
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_OPEN_COIL_EV,							//duplicate id
	//	lAlarmCANOpenStop.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_WRONG_FBSENSSET,					//duplicate id
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_WSET_TG_EB_XX,						//duplicate id
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_INPUT_MISMATCH,						//duplicate id
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_SAFETY_DIAG_XX,						//duplicate
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_SAFETY_SW_XX,							//duplicate
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_SAFETY_INIT_XX,						//duplicate
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_OUT_MISMATCH_XX,				duplicate label
	//	lAlarmCANOpenSlaveBlock.triggerWithContext(eid);

	//t_motor_emcy_id.cEMCY_STO_SS1_ALARM_XX,					duplicate label
	//	lEventHandlerOperatingBlockingFault.operator(eid,controller,info);

IF (lTypeSteer) THEN
	lNominalCurrent := cNominalCurrent150A;
	lPolePairs := cPolePairs150A;

	lMotorTemperatureInvalidRange := cMotorTemperatureInvalidRange150A;
	lMotorTemperatureSensorRecovery := cMotorTemperatureInvalidRange150A;
ELSE
	lNominalCurrent := cNominalCurrent400A;
	lPolePairs := cPolePairs400A;

	lMotorTemperatureInvalidRange := cMotorTemperatureInvalidRange400A;
	lMotorTemperatureSensorRecovery := cMotorTemperatureInvalidRange400A;
END_IF

lVREnableStallAutomaticClearing.initializeValueReference(lEnableStallAutomaticClearing,NopSelf,'EnblStallClr','Stall states are automatically cleared','',cValueStyleParameter);
lVREnableStallResponse.initializeValueReference(lEnableStallResponse,NopSelf,'EnbleStallResp','Automatically handle stall states','',cValueStyleParameter);
lVREnableHoldStationary.initializeValueReference(lEnableHoldStationary,NopSelf,'EnbleHoldStat','Hold on stationary','',cValueStyleParameter);
lVREnableStallDetection.initializeValueReference(lEnableStallDetection,NopSelf,'EnbleStallDet','Stall states are automatically detected','',cValueStyleParameter);
lVREnableThrottleArbitration.initializeValueReference(lEnableThrottleArbitration,NopSelf,'EnblThrttArb','Enable throttle arbitration','',cValueStyleParameter);
lVREnableNMTDetectionTPDO.initializeValueReference(lEnableNMTDetectionTPDO,NopSelf,'EnbleNMTDet','Detect NMT state from TPOD traffic','',cValueStyleParameter);
lVREnableInitializeHold.initializeValueReference(lEnableInitializeHold,NopSelf,'EnblInitHold','Enable initial hold strategy','',cValueStyleParameter);

lAlarmControllerTemperatureCutback.initializeState(NopSelf,'',cACControllerTemperatureCutback);
lAlarmControllerTemperatureCutback.Qualifier := cChargeQualifierBoth;

lAlarmMotorTemperatureCutback.initializeState(NopSelf,'',cACMotorTemperatureCutback);
lAlarmMotorTemperatureCutback.Qualifier := cChargeQualifierBoth;

lAlarmMotorTemperatureSensor.initializeState(NopSelf,'',cACMotorTemperatureSensor);
lAlarmMotorTemperatureSensor.Life := 10;

lTargetSpeed.Scaling := 10.0 * lPolePairs;
lTargetSpeed.initializeValueObject(NopSelf,'TargetSpeed','Motor target speed','rpm',cValueStyleConfigurable);

lEnable.Index := 0;
lEnable.initializeValueObject(NopSelf,'EnableMotor','Motor enable state','',cValueStyleConfigurable);

lForward.Index := 3;
lForward.initializeValueObject(NopSelf,'Forward','Motor forward state','',cValueStyleConfigurable);

lReverse.Index := 4;
lReverse.initializeValueObject(NopSelf,'Reverse','Motor reverse state','',cValueStyleConfigurable);

lClearAlarm.Index := 13;
lClearAlarm.initializeValueObject(NopSelf,'ClearAlarm','Motor clear alarm state','',cValueStyleConfigurable);

lVelocity.Scaling := 0.1 / lPolePairs;
lVelocity.initializeValueObjectOp(OpSelf,'Velocity','Motor current velocity','rpm',cValueStyleConfigurable);

lTPDO1Stuffing.Index := 15;
lTPDO1Stuffing.initializeValueObjectOp(OpSelf,'TPO1Stuffing','Motor TPOD stuffing state','',cValueStyleConfigurable);

lCurrent.Scaling := lNominalCurrent/200.0;
lCurrent.initializeValueObjectOp(OpSelf,'Current','Motor measured current','amps',cValueStyleConfigurable);

lAlarm.initializeValueObjectOp(OpSelf,'Alarm','Motor alarm state','',cValueStyleConfigurable);

lMotorTemperature.Offset := -40;
lMotorTemperature.initializeValueObjectOp(OpSelf,'MotorTemp','Motor temperature','celcius',cValueStyleConfigurable);

lControllerTemperature.initializeValueObjectOp(OpSelf,'CntrlTemp','Controller temperature','celcius',cValueStyleConfigurable);

lBatteryCurrent.Scaling := lNominalCurrent/127.0;//foobar usint not sint, requires offset?
lBatteryCurrent.initializeValueObjectOp(OpSelf,'BattCurrent','Motor battery current','amps',cValueStyleConfigurable);

lBatteryVoltage.Scaling := 0.001*lNominalVoltage;
lBatteryVoltage.initializeValueObjectOp(OpSelf,'BattVoltage','Motor battery voltage','volts',cValueStyleConfigurable);

lBatteryPower.Scaling := 0.001;
lBatteryPower.Offset := 0.0;
lBatteryPower.initializeValueObjectOp(OpSelf,'BattPower','Motor battery power','kW',cValueStyleConfigurable);

lTorque.initializeValueObject(NopSelf,'Torque','Motor current torque','Nm',cValueStyleConfigurable);

SUPER^.initialize();

lStallTimer.Enable := TRUE;
lStallTimer.Period := cStallPeriod;
lStallTimer.initialize();

lTorqueTimer.initialize();
lTorqueTimer.Enable := TRUE;
lTorqueTimer.Period := cTorquePeriod;

lThrottleArbitrationTimer.initialize();
lThrottleArbitrationTimer.Enable := TRUE;
lThrottleArbitrationTimer.Period := cThrottleArbitrationPeriod;

lRPDO1Message.t_Id.u32_Id := 16#200 + lControllerId;
lRPDO1Message.t_Id.u8_Xtd := X_OFF;
lRPDO1Message.u8_Dlc := 8;
lRPDO1Message.au8_Data[0] := 0;
lRPDO1Message.au8_Data[1] := 0;
lRPDO1Message.au8_Data[2] := 0;
lRPDO1Message.au8_Data[3] := 0;
lRPDO1Message.au8_Data[4] := 0;
lRPDO1Message.au8_Data[5] := 0;
lRPDO1Message.au8_Data[6] := 0;
lRPDO1Message.au8_Data[7] := 0;

lSDORead.DEVICE := lControllerId + 2;
lSDOWrite.DEVICE := lControllerId + 2;

lSDOTorque.DEVICE := lControllerId + 2;
lSDOTorque.CHANNEL := 0;
lSDOTorque.NETWORK := lNetworkId;
lSDOTorque.ENABLE := FALSE;
lSDOTorque.TIMEOUT := 500;
lSDOTorque.MODE := CIA405.SDO_MODE.AUTO;
lSDOTorque.DATA := ADR(lSDOTorqueData);

lNMTDetectionTimer.initialize();
lNMTDetectionTimer.Enable := TRUE;
lNMTDetectionTimer.Period := cNMTDetectionPeriod;

lEnabledTimer.initialize();
lEnabledTimer.Enable := TRUE;
lEnabledTimer.Period := cEnabledPeriod;

lMotorTemperatureEnableCANSequence.initialize();
lCheckMotorTemperatureEnableCANMessage.initialize();

lInitializeMotorHoldTimer.initialize();
lInitializeMotorHoldTimer.Enable := TRUE;
lInitializeMotorHoldTimer.Period := cInitializeMotorHoldPeriod;

IF (lTypeSteer) THEN
	lAlarmControllerTemperatureCutback.InitialCutbackThreshold := cControllerTemperatureInitialCutbackThreshold150A;
	lAlarmControllerTemperatureCutback.CutoutThreshold := cControllerTemperatureCutoutThreshold150A;
	lAlarmControllerTemperatureCutback.MinimiumThreshold := cControllerTemperatureMinimumThreshold150A;

	lAlarmMotorTemperatureCutback.InitialCutbackThreshold := cMotorTemperatureInitialCutbackThreshold150A;
	lAlarmMotorTemperatureCutback.CutoutThreshold := cMotorTemperatureCutoutThreshold150A;
	lAlarmMotorTemperatureCutback.MinimiumThreshold := cMotorTemperatureMinimumThreshold150A;

	lAlarmCANOpenSlaveModulation.registerServer(gSystemPrimary.Travel.Interlock);
	lAlarmCANOpenSlaveBlock.registerServer(gSystemPrimary.Travel.Interlock);

	lAlarmControllerTemperatureCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);
	lAlarmMotorTemperatureCutback.registerServer(gSystemPrimary.Travel.ChargeInterlock);

	lMaximumVelocity := cSteerMotorMaximumVelocityAsHz;

	lAlwaysEnable := FALSE;
	lAutomaticEnable := TRUE;
ELSE
	lAlarmControllerTemperatureCutback.InitialCutbackThreshold := cControllerTemperatureInitialCutbackThreshold400A;
	lAlarmControllerTemperatureCutback.CutoutThreshold := cControllerTemperatureCutoutThreshold400A;
	lAlarmControllerTemperatureCutback.MinimiumThreshold := cControllerTemperatureMinimumThreshold400A;

	lAlarmMotorTemperatureCutback.InitialCutbackThreshold := cMotorTemperatureInitialCutbackThreshold400A;
	lAlarmMotorTemperatureCutback.CutoutThreshold := cMotorTemperatureCutoutThreshold400A;
	lAlarmMotorTemperatureCutback.MinimiumThreshold := cMotorTemperatureMinimumThreshold400A;
END_IF

SUPER^.operator();

IF (gSystemPrimary.SystemState.State<>cSystemStateOperational) THEN
	RequestedThrottle := 0.0;
	Diagnostic := cMotorDiagnosticNotOperational;
END_IF

IF (NOT(gSystemPrimary.OperatingMode.Ready)) THEN
	RequestedThrottle := 0.0;
	Diagnostic := cMotorDiagnosticOperatingMode;
END_IF

IF (HoldStationary) THEN
	RequestedThrottle := 0.0;
	Diagnostic := cMotorDiagnosticHoldStationary;	
END_IF

IF (NOT(Enabled)) THEN
	RequestedThrottle := 0.0;
	Diagnostic := cMotorDiagnosticDisabled;
END_IF

lRequestedThrottlePrevious := RequestedThrottle;
lProposedThrottle := lRequestedThrottlePrevious;
lMeasuredThrottle := velocityToThrottle(Velocity);

stallManagement();
throttleArbitration();

lFreeWheel := ((lEnableFreeWheel) AND (ABS(lProposedThrottle)<lThrottleFreeWheelThreshold));
lEnableFreeWheel := FALSE;

IF (ABS(lProposedThrottle)<lThrottleThreshold) THEN
	lProposedThrottle := 0.0;
END_IF

IF (lAlwaysEnable) THEN
	lEnable.Value := NOT(lFreeWheel);

ELSIF (lAutomaticEnable) THEN
	IF (lProposedThrottle<>0) THEN
		lEnabledTimer.reset();
	END_IF	
	IF ((lHoldStationary) AND (lEnableHoldStationary)) THEN
		lEnabledTimer.reset();
	END_IF
	lEnabledTimer.operator();

	lEnable.Value := ((Enabled) AND
		(gSystemPrimary.SystemState.State>=cSystemStateExitOperational) AND
		(NOT(lEnabledTimer.Expired)) AND
		(NOT(lFreeWheel)));

ELSE
	lEnable.Value := Enabled;	

END_IF

lTargetVelocity := throttleToVelocity(lProposedThrottle);

IF (lEnableInitializeHold) THEN
	lInitializeMotorHoldTimer.operator();

	IF (lTargetVelocity=0) THEN
		IF (lInitializeMotorHoldTimer.Expired) THEN
			initializeMotorHold();
		END_IF
	ELSE
		lInitializeMotorHoldTimer.reset();
	END_IF

	IF (lInitializeMotorHoldCounter>0) THEN
		lInitializeMotorHoldCounter := lInitializeMotorHoldCounter - 1;

		IF (lTargetVelocity=0) THEN
			lTargetVelocity := 0.1/lPolePairs;
			Diagnostic := cMotorDiagnosticInitializeHold;
		END_IF
	END_IF
END_IF

IF (NOT(lEnable.Value)) THEN
	lForward.Value := FALSE;
	lReverse.Value := FALSE;
ELSE
	IF (lTargetVelocity = 0) THEN
		// forward and reverse carry forward from previous
		// ensure both are not active at the same time, at least one is active

		IF (lForward.Value) THEN
			lReverse.Value := FALSE;
		END_IF
		IF (lReverse.Value) THEN
			lForward.Value := FALSE;
		END_IF
		IF ((NOT(lForward.Value)) AND (NOT(lReverse.Value))) THEN
			lForward.Value := TRUE;		
		END_IF
	ELSE
		lForward.Value := (lTargetVelocity > 0);
		lReverse.Value := (lTargetVelocity < 0);
	END_IF
END_IF

lTargetSpeed.Value := ABS(lTargetVelocity);
lStationary := ((Velocity=0) AND (TargetSpeed=0));

rpdo1();

IF ((lTorqueTimer.Enable) AND 
	(RequestedThrottle<>0.0)) THEN
	lTorqueTimer.operator();
	IF (lTorqueTimer.Expired) THEN
		lTorqueTimer.reset();
		requestSDOTorque();
	END_IF
	IF (lSDOTorqueSuccess) THEN
		lTorque.Input := DWORD_TO_UINT(lSDOLastSuccessfulReadData);
		lSDOTorqueSuccess := FALSE;
	END_IF
ELSE
	lTorque.Input := 0; //foobar check sdo are we getting real values
END_IF

IF (lSDOTorque.ENABLE) THEN
	lSDOTorque(DATALENGTH:=lSDOTorqueDataLength);
	IF ((lSDOTorque.CONFIRM) OR (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDOTorque.ENABLE := FALSE;
		lSDOTorqueAttemptCounter := lSDOTorqueAttemptCounter + 1;
		IF (lSDOTorque.CONFIRM) THEN
			lSDOTorqueSuccess := TRUE;
			lSDOTorqueLastSuccessfulReadData := lSDOTorqueData;
			lSDOTorqueSuccessCounter := lSDOTorqueSuccessCounter + 1;
		END_IF
	END_IF	
END_IF

lMotorTemperatureEnableCANSequence.operator(); // foobar deprecated?
lCheckMotorTemperatureEnableCANMessage.operator(); // foobar deprecated?

lAlarmControllerTemperatureCutback.Value := ControllerTemperature;
lAlarmControllerTemperatureCutback.test(FALSE);

IF (MotorTemperature>=lMotorTemperatureInvalidRange) THEN
	lAlarmMotorTemperatureSensor.trigger(FALSE);
	lAlarmMotorTemperatureCutback.Value := lMotorTemperatureSensorRecovery;
ELSE
	lAlarmMotorTemperatureCutback.Value := MotorTemperature;
END_IF
lAlarmMotorTemperatureCutback.test(FALSE);

lBatteryPower.Value := lBatteryCurrent.Value * lBatteryVoltage.Value;

lDiagnostic := _Diagnostic;
_Diagnostic := cMotorDiagnosticOK;

cancelSDOTorque();

lSDOTorque.ENABLE := TRUE;

lSDOTorque.INDEX := 16#210E;
lSDOTorque.SUBINDEX := 0;
lSDOTorqueDataLength := 2;

lSDOTorqueSuccess := FALSE;

IF (NOT(lEnableRPDO1)) THEN
	RETURN;
END_IF

lControl := ((2) OR
	(UINT_TO_WORD(lEnable.Output)) OR
	(UINT_TO_WORD(lForward.Output)) OR
	(UINT_TO_WORD(lReverse.Output)) OR
	(UINT_TO_WORD(lClearAlarm.Output)) OR //foobar clearing and recovering from alarms
	SHL(BOOL_TO_WORD(lSyncAlternateState),15));

lRPDO1Message.au8_Data[0] := UINT_TO_BYTE(lTargetSpeed.Output);
lRPDO1Message.au8_Data[1] := WORD_TO_BYTE(SHR(UINT_TO_WORD(lTargetSpeed.Output),8));
lRPDO1Message.au8_Data[2] := UINT_TO_BYTE(lControl);
lRPDO1Message.au8_Data[3] := WORD_TO_BYTE(SHR(UINT_TO_WORD(lControl),8));

IF (lMaster.TransmitMessage.transmit(lRPDO1Message)=C_OVERFLOW) THEN
	lOverflowCounter := lOverflowCounter + 1;
ELSE
	lSyncAlternateState := NOT(lSyncAlternateState);
END_IF

IF (lSDORead.INDEX=16#20F1) THEN
	lMotorTemperatureEnabled := (lSDOReadData<>0);
	lMotorTemperatureEnabledVerified := TRUE;
END_IF

IF (NOT(lEnableStallDetection)) THEN
	lStalled := lStallInput := FALSE;
	RETURN;
END_IF

lStallInput := ((Velocity=0) AND (TargetSpeed>0)); // foobar no reportable for stall detection

IF (TargetSpeed=0) THEN
	lZeroTargetSpeedIndicator := lZeroTargetSpeedIndicator + 1;
	lTargetSpeedIndicator := 0;
ELSE
	lTargetSpeedIndicator := lTargetSpeedIndicator + 1;
	lZeroTargetSpeedIndicator := 0;	
END_IF

IF (Velocity=0) THEN
	lZeroCurrentVelocityIndicator := lZeroCurrentVelocityIndicator + 1;
	lCurrentVelocityIndicator := 0;
ELSE
	lCurrentVelocityIndicator := lCurrentVelocityIndicator + 1;
	lZeroCurrentVelocityIndicator := 0;	
END_IF

IF (NOT(lStallInput)) THEN
	lStallTimer.reset();
	lNoStallIndicator := lNoStallIndicator + 1;
	lStallIndicator := 0;
ELSE
	lStallIndicator := lStallIndicator + 1;
	lNoStallIndicator := 0;
END_IF

lStallTimer.operator();
IF ((lStallInput) AND (lStallTimer.Expired)) THEN
	IF (NOT(lStalled)) THEN
		lStalledCount := lStalledCount + 1;
	END_IF

	lStalled := TRUE;
ELSE
	lStalled := FALSE;
END_IF

IF (lStalled) THEN
	lStalledIndicator := lStalledIndicator + 1;
	lNotStalledIndicator := 0;
ELSE
	lNotStalledIndicator := lNotStalledIndicator + 1;
	lStalledIndicator := 0;
END_IF

stallDetection();

CASE lStallState OF
	cStallStateNone:
		IF (Stalled) THEN
			lStallState := cStallStateDetected;
		END_IF

	cStallStateDetected:		
		lStallState := cStallStateCurrent;

	cStallStateCurrent:
		IF (NOT(Stalled)) THEN
			IF (lEnableStallAutomaticClearing) THEN
				lStallState := cStallStateNone;
			ELSE
				lStallState := cStallStateClearing;
			END_IF
		END_IF

	cStallStateClearing:
		lStallState := cStallStateNone;
END_CASE

IF ((lStallState>cStallStateNone) AND
	(lEnableStallResponse)) THEN
	stallResponse();
END_IF

SUPER^.startHandler();

IF ((lEnableDiscriminatoryMotorTemperatureControl) AND
	(NOT(lMotorTemperatureEnabledVerified))) THEN
	checkMotorTemperatureEnabled();
END_IF

IF (lEnableThrottleArbitration) THEN IF (lRequestedThrottlePrevious<>RequestedThrottle) THEN lThrottleArbitrationTimer.reset(); END_IF
lThrottleArbitrationTimer.operator();
IF ((ABS(RequestedThrottle)>lThrottleArbitrationThreshold) AND (lThrottleArbitrationTimer.Expired) AND (((RequestedThrottle>0) AND (lMeasuredThrottle>0)) OR ((RequestedThrottle<0) AND (lMeasuredThrottle<0)))) THEN lThrottleArbitrationDelta := ABS(RequestedThrottle) - ABS(lMeasuredThrottle); IF (lThrottleArbitrationDelta>lThrottleArbitrationAllowableDelta) THEN lProposedThrottle := lMeasuredThrottle; END_IF END_IF END_IF

lVelocity.InputReference REF= velocity;
lTPDO1Stuffing.InputReference ref= status;
lCurrent.InputReference ref= current;
lAlarm.InputReference ref= alarm;
lMotorTemperature.InputReference ref= motorTemperature;
lControllerTemperature.InputReference ref= controllerTemperature;
lBatteryCurrent.InputReference ref= batteryCurrent;
lBatteryVoltage.InputReference ref= batteryVoltage;

// lTorque.InputReference

IF ((lEnableDiscriminatoryMotorTemperatureControl) AND
	(NOT(lMotorTemperatureEnabledVerified))) THEN
	checkMotorTemperatureEnabled();
END_IF

MotorTemperatureEnabled := lMotorTemperatureEnabled;

IF (NOT(lEnableDiscriminatoryMotorTemperatureControl)) THEN
	lMotorTemperatureEnabled := MotorTemperatureEnabled;
	RETURN;
END_IF

IF (lMotorTemperatureEnabled<>MotorTemperatureEnabled) THEN
	lMotorTemperatureEnableCANSequence.MotorTemperatureEnabledRequest := MotorTemperatureEnabled;
	lMotorTemperatureEnableCANSequence.start();
//	IF (MotorTemperatureEnabled) THEN
//		requestSDOWrite(TRUE,16#20F1,16#2,cMotorTemperatureType,4);
//	ELSE
//		requestSDOWrite(TRUE,16#20F1,16#2,0,4);
//	END_IF
END_IF

IF (lEnableNMTDetectionTPDO) THEN

	IF (lTPDO1StuffingPrevious<>lTPDO1Stuffing.Value) THEN
		lNMTDetectionTimer.reset();
	END_IF
	lTPDO1StuffingPrevious := lTPDO1Stuffing.Value;

	lNMTDetectionTimer.operator();
	IF (NOT(lNMTDetectionTimer.Expired)) THEN
		lNodeState := t_node_state.OPERATIONAL;
		RETURN;
	ELSE
		IF (gSystemPrimary.SystemState.State>=lStartSystemStateScope) THEN
			start();
		END_IF
	END_IF
END_IF

lNodeState := NodeState;

lNominalCurrent := cNominalCurrent;
lPolePairs := cPolePairs;

lMotorTemperatureInvalidRange := cMotorTemperatureInvalidRange;
lMotorTemperatureSensorRecovery := cMotorTemperatureInvalidRange;

SUPER^.initialize();

lAlarmControllerTemperatureCutback.InitialCutbackThreshold := cControllerTemperatureInitialCutbackThreshold;
lAlarmControllerTemperatureCutback.CutoutThreshold := cControllerTemperatureCutoutThreshold;
