// radians
lAngle.Offset := 0.0 - UDINT_TO_REAL(cCalibrationValue);
lAngle.Scaling := 2.0 * cPi / UDINT_TO_REAL(lStepsPerRevolution) * lSign;

// hz
lAngularVelocity.Offset := 0.0;
lAngularVelocity.Scaling := 1000.0 / UDINT_TO_REAL(lStepsPerRevolution) * lSign;

IF (executeContext^.matchCommand(sCommandZero)) THEN	
	zero();
	RETURN;
END_IF

SUPER^.execute(executeContext);

IF (lTypeSteer) THEN
	lUpper.Identifier := t_persistent_id.cPersistentID_SteerUpper;
	lFactor := 1.0;
	lOffset := 0.0;

	LowerErrorBound := -1.04;
	UpperErrorBound := 1.04;
END_IF

lVRUpper.initializeValueReference(lUpper,NopSelf,'Upper','Angle at upper end of range','radians',cValueStyleParameter);
lUpper.initialize();

lRangeError.initializeState(NopSelf,'',cACSensorRangeError);

lPosition.initializeValueObject(NopSelf,'Position','Position in established range','',cValueStyleConfigurable);

SUPER^.initialize();

IF (lTypeSteer) THEN
	lAlarmCANOpenSlaveModulation.registerServer(gSystemPrimary.Travel.Interlock);

	Upper := 94.0 / 180.0 * cPi;
END_IF

SUPER^.operator();

IF (NOT(lEnabled)) THEN
	lPosition.Value := 0.0;	
	lPosition.operator();
	RETURN;
END_IF

IF (Upper<>0) THEN
	lPosition.Value := (Angle/Upper*lFactor) + lOffset;
ELSE
	lPosition.Value := 0.0;	
END_IF
lPosition.operator();

IF ((lPosition.Value>lUpperErrorBound) OR
	(lPosition.Value<lLowerErrorBound)) THEN
	lRangeError.trigger(FALSE);
END_IF

IF (executeContext^.matchCommand(sCommandUpper)) THEN	
	setUpper();
	RETURN;
END_IF

