IF (requested=cFunctionalModeAny) THEN
	enableAndRequest := cFunctionalDiagnosticOK;
	RETURN;
END_IF

mode REF= getMode(requested);
previous := mode.Enabled;

mode.Enabled := TRUE;
enableAndRequest := request(requested);
IF (enableAndRequest>cFunctionalDiagnosticNotYetActive) THEN
	mode.Enabled := previous;
END_IF

getMode REF= lFunctionalModeDefault;

CASE mode OF		
	cFunctionalModeDefault:
		getMode REF= lFunctionalModeDefault;	
	cFunctionalModeTravel:
		getMode REF= lFunctionalModeTravel;
	cFunctionalModeLift:
		getMode REF= lFunctionalModeLift;
END_CASE

SUPER^.initialize();

lFunctionalModeDefault.Available := TRUE;
lFunctionalModeDefault.Enabled := TRUE;
lFunctionalModeDefault.initialize();

lFunctionalModeTravel.Available := TRUE;
lFunctionalModeTravel.Enabled := TRUE;
lFunctionalModeTravel.initialize();

lFunctionalModeLift.Available := TRUE;
lFunctionalModeLift.Enabled := TRUE;
lFunctionalModeLift.initialize();

lMode REF= lFunctionalModeDefault;

lRequested := FALSE;
lDiagnostic := cFunctionalDiagnosticOK;

enableAndRequest(gSystemPrimary.UInterface.FunctionalModeRequest);

IF (lMode.State=cModeStateEntering) THEN
	IF (NOT(lMode.enter())) THEN
		lDiagnostic := cFunctionalDiagnosticNotYetActive;
		RETURN;
	END_IF

	RETURN;
END_IF

IF (lMode.State=cModeStateExiting) THEN
	IF (NOT(lMode.leave())) THEN
		lDiagnostic := cFunctionalDiagnosticWaitingToExit;
		RETURN;
	END_IF

	RETURN;
END_IF

IF (requested=cFunctionalModeAny) THEN
	lDiagnostic := cFunctionalDiagnosticOK;
	request := lDiagnostic;
	RETURN;
END_IF

IF (CurrentMode=requested) THEN
	IF (NOT(lMode.enter())) THEN
		//gMessageManager.register(lCode:=cMCAdviseFunctionalModeNotYetActive);
		lDiagnostic := cFunctionalDiagnosticNotYetActive;
		request := lDiagnostic;
		RETURN;		
	END_IF

	lDiagnostic := cFunctionalDiagnosticOK;
	request := lDiagnostic;
	RETURN;
END_IF

IF (lRequested) THEN
	//gMessageManager.register(lCode:=cMCAdviseFunctionalModeRace);
	lDiagnostic := cFunctionalDiagnosticRace;
	request := lDiagnostic;
	RETURN;	
END_IF

mode REF= getMode(requested);

IF (NOT(mode.Enabled)) THEN
	//gMessageManager.register(lCode:=cMCAdviseFunctionalModeIllegalRequest);
	lDiagnostic := cFunctionalDiagnosticNotEnabled;
	request := lDiagnostic;
	RETURN;
END_IF

IF (NOT(gSystemPrimary.OperatingMode.Stopped)) THEN
	//gMessageManager.register(lCode:=cMCAdviseFunctionalModeNotStationary);
	lDiagnostic := cFunctionalDiagnosticNotStationary;
	request := lDiagnostic;
	RETURN;
END_IF

IF (NOT(lMode.leave())) THEN
	//gMessageManager.register(lCode:=cMCAdviseFunctionalModeWaitingOnPreviousToExit);
	lDiagnostic := cFunctionalDiagnosticWaitingOnPreviousToExit;
	request := lDiagnostic;
	RETURN;
END_IF

lMode REF= mode;
lRequested := TRUE;

IF (NOT(lMode.enter())) THEN
	//gMessageManager.register(lCode:=cMCAdviseFunctionalModeNotYetActive);
	lDiagnostic := cFunctionalDiagnosticNotYetActive;
	request := lDiagnostic;
	RETURN;
END_IF

lDiagnostic := cFunctionalDiagnosticOK;
request := lDiagnostic;

