	//gMessageManager.register(lCode:=cMCAdviseNoFunctionUnlessOperational);
END_IF

IF ((lEnableUMFSCheck) AND (lInputResolved<>0) AND (NOT(gSystemPrimary.lUMFS.Allow))) THEN
	Diagnostic := cMovementDiagnosticUMFS;
	lInputNulled := TRUE;
	//gMessageManager.register(lCode:=cMCAdviseNoFunctionIfUMFS);
END_IF

IF ((lInputResolved<>0) AND (gSystemPrimary.OperatingMode.lMode<cOperatingModeStopped)) THEN
	Diagnostic := cMovementDiagnosticOperatingMode;
	lInputNulled := TRUE;
	//gMessageManager.register(lCode:=cMCAdviseNoFunctionWhenParked);
END_IF

IF (lInputResolved<>0) THEN
	lFunctionalDiagnostic := gSystemPrimary.FunctionalModeControl.request(lFunctionalMode);
	IF ((lFunctionalDiagnostic<>cFunctionalDiagnosticOK) AND
		(lEnableFunctionalMode)) THEN
		Diagnostic := cMovementDiagnosticFunctionalMode;
		lInputNulled := TRUE;
		//gMessageManager.register(lCode:=cMCAdviseNoFunctionWhenParked);
	END_IF
END_IF

IF ((gSystemPrimary.UInterface.IsSlow) AND
	(lEnableUInterfaceSlow)) THEN
	lCurrentUInterfaceSlowFactor := gSystemPrimary.UInterface.SlowFactor * lUInterfaceSlowFactor;
END_IF

IF ((gSystemPrimary.UInterface.IsBeginner) AND
	(lEnableBeginnerSlow)) THEN
	lCurrentBeginnerSlowFactor := lBeginnerSlowFactor;
END_IF

IF ((gSystemPrimary.OperatingMode.IsSlow) AND
	(lEnableOperatingModeSlow)) THEN
	lCurrentOperatingModeSlowFactor := gSystemPrimary.OperatingMode.SlowFactor * lOperatingModeSlowFactor;
END_IF

IF ((lEnableFunctionSlow)) THEN
	lCurrentFunctionSlowFactor := lFunctionSlowFactor;
END_IF

lInputScaling := lInputScaling *
	MIN(MIN(MIN(lCurrentUInterfaceSlowFactor,lCurrentBeginnerSlowFactor),lCurrentOperatingModeSlowFactor),lCurrentFunctionSlowFactor);

lCurrentFunctionSlowFactor := 1.0;
lCurrentOperatingModeSlowFactor := 1.0;
lCurrentUInterfaceSlowFactor := 1.0;

lVREnableFunctionalMode.initializeValueReference(lEnableFunctionalMode,NopSelf,'EnblFuncMode','Enable functional mode check','',cValueStyleParameter);
lVREnableUMFSCheck.initializeValueReference(lEnableUMFSCheck,NopSelf,'EnblUMFSChk','Enable UMFS check','',cValueStyleParameter);

lChargeInterlock.initializeEventOp(OpSelf,'',cECMovementChargeInterlock);
lChargeInterlock.registerServer(ADR(lInterlock));

SUPER^.initialize();

lRegisterUMFSPrimary := TRUE;
lRegisterUMFSAuxilliary := TRUE;
lRegisterUMFSSecondary := TRUE;

lEnableOperatingModeSlow := TRUE;
lEnableUMFSCheck  := TRUE;

lRegisterActive:= TRUE;
lEnableOnlyOnActiveAllow := TRUE;

lCurrentFunctionSlowFactor := 1.0;
lCurrentOperatingModeSlowFactor := 1.0;
lCurrentUInterfaceSlowFactor := 1.0;

_Throttle.Name := 'Throttle';
lThrottle REF= _Throttle;
registerNonOperational(ADR(_Throttle));

lMovementA.Name := 'mA';
registerNonOperational(ADR(lMovementA));

lMovementA.Name := 'mB';
registerNonOperational(ADR(lMovementB));

SUPER^.initialize();

SUPER^.operator();

lMovementA.InputValue := lThrottle.Value * lScalingA;
lMovementA.operator();

lMovementB.InputValue := lThrottle.Value * lScalingB;
lMovementB.operator();

lVREnabledStallManagement.initializeValueReference(lEnabledStallManagement,NopSelf,'EnblStallMgmt','Enable stall management','',cValueStyleParameter);
lVRInputDeadBand.initializeValueReference(lInputDeadBand,NopSelf,'Deadband','Input deadband','',cValueStyleParameter);

lInterlock.initializeEventOp(OpSelf,'',cECMovementInputInterlock);

lInput.initializeValueObject(NopSelf,'Input','Input value','',cValueStyleConfigurable);
lInputSecondary.initializeValueObject(NopSelf,'InputSecndry','Secondary input value','',cValueStyleConfigurable);

SUPER^.initialize();

lInputNulled := FALSE;
lInputScaling := 1.0;
lInputThresholdAbsolute := 1.0;

lInputResolved := lInput.Value;

IF (ABS(lInput.Value) <= lInputDeadBand) THEN
	lInputPresentPrimary := FALSE;

	IF (lInput.Value<>0.0) THEN
		Diagnostic := cMovementDiagnosticDeadband;
		lInputResolved := 0.0;
	END_IF
ELSE
	lInputPresentPrimary := TRUE;
END_IF

IF ((lRegisterUMFSPrimary) AND (lInputPresentPrimary)) THEN
	gSystemPrimary.lUMFS.registerUIPrimary();
END_IF

lInputPresentAuxilliary := lInputPresentAuxilliaryRequest;
lInputPresentAuxilliaryRequest := FALSE;

IF ((lRegisterUMFSAuxilliary) AND (lInputPresentAuxilliary)) THEN
	gSystemPrimary.lUMFS.registerUIAuxilliary();
END_IF

lInputPresentSecondary := FALSE;
IF (lEnableInputSecondary) THEN
	lInputPresentSecondary := (lInputSecondary.Value<>0.0);

	IF (NOT(InputPresentPrimary)) THEN
		lInputResolved := lInputSecondary.Value;
		Diagnostic := cMovementDiagnosticDerived;	
	END_IF

	lEnableInputSecondary := FALSE;
ELSE
	lInputSecondary.Value := 0.0;	
END_IF

IF ((lRegisterUMFSSecondary) AND (lInputPresentSecondary)) THEN
	gSystemPrimary.lUMFS.registerUISecondary();
END_IF

IF (NOT(Enabled)) THEN
	lInputResolved := 0.0;
	lInputPresentPrimary := FALSE;
	lInputPresentSecondary := FALSE;
	lActive := FALSE;
	Diagnostic := cMovementDiagnosticDisabled;
ELSE
	lActive := ((InputPresentPrimary) OR (InputPresentSecondary));
	IF ((lRegisterActive) AND (lActive)) THEN
		gSystemPrimary.Active.registerActive();
	END_IF

	IF (((NOT(gSystemPrimary.Active.Allow)) AND (lEnableOnlyOnActiveAllow))) THEN
		Diagnostic := cMovementDiagnosticActiveDisallow;
		lInputResolved := 0.0;
	END_IF

	checks();

	IF (lInputNulled) THEN
		lInputResolved := 0.0;
	END_IF
END_IF

IF (lInputResolved<>0.0) THEN
	IF (NOT(lInputScalingOverride)) THEN
		lInputProcessed := lInputResolved * lInputScaling;
	ELSE
		lInputProcessed := lInputResolved;
	END_IF
	IF (ABS(lInputProcessed)>lInputThresholdAbsolute) THEN
		lInputProcessed := lInputThresholdAbsolute*lInputProcessed/ABS(lInputProcessed);
		Diagnostic := cMovementDiagnosticThreshold;
	END_IF
ELSE
	lInputProcessed := 0.0;
END_IF

brake();

SUPER^.operator();

lThrottleValue := lInterlock.update(lInputProcessed);
IF (lThrottleValue<>lInputProcessed) THEN
	Diagnostic := cMovementDiagnosticInterlock;
END_IF

stall();

lThrottle.Value := lThrottleValue;
lThrottle.operator();

lMoving := FALSE;
IF (lRegisterOperatingMode) THEN
	IF (lThrottle.Value<>0) THEN
		IF (Stalled) THEN
			gSystemPrimary.OperatingMode.registerStalled();
		ELSE
			lMoving := TRUE;
			gSystemPrimary.OperatingMode.registerRunning();
		END_IF
	ELSE
		gSystemPrimary.OperatingMode.registerStopped();
	END_IF
END_IF

lDiagnostic := _Diagnostic;
_Diagnostic := cMovementDiagnosticOK;
lInputScalingOverride := FALSE;

IF ((lEnabledStallManagement) AND 
	(Stalled)) THEN
	lThrottle.Value := 0.0;
	Diagnostic := cMovementDiagnosticStalled;
END_IF

IF (lInput.Value>0) THEN
	RequestedDirection := cDirectionForward;
ELSIF (lInput.Value<0) THEN
	RequestedDirection := cDirectionReverse;
ELSE
	RequestedDirection := cDirectionStationary;	 
END_IF

IF (__ISVALIDREF(lThrottle)) THEN
	Stalled := lThrottle.Stalled;
ELSE
	Stalled := FALSE;
END_IF

IF (__ISVALIDREF(lThrottle)) THEN
	Stationary := lThrottle.Stationary;
ELSE
	Stationary := FALSE;
END_IF

_Throttle.Name := 'Throttle';
lThrottle REF= _Throttle;
registerNonOperational(ADR(_Throttle));

lMovementA.Name := 'mA';
registerNonOperational(ADR(lMovementA));

lMovementA.Name := 'mB';
registerNonOperational(ADR(lMovementB));

lMovementA.Name := 'mC';
registerNonOperational(ADR(lMovementC));

lMovementA.Name := 'mD';
registerNonOperational(ADR(lMovementD));

SUPER^.initialize();

SUPER^.operator();

lMovementA.InputValue := lThrottle.Value * lScalingA;
lMovementA.operator();

lMovementB.InputValue := lThrottle.Value * lScalingB;
lMovementB.operator();

lMovementC.InputValue := lThrottle.Value * lScalingC;
lMovementC.operator();

lMovementD.InputValue := lThrottle.Value * lScalingD;
lMovementD.operator();

IF (lCutoutThreshold<=lInitialCutbackThreshold) THEN
	lFactor := 0.0;
ELSE
	lFactor := (-1.0)/(lCutoutThreshold - lInitialCutbackThreshold);
END_IF

IF ((input>lInitialCutbackThreshold) AND
	(__ISVALIDREF(lMovement)) AND
	(lEnabled)) THEN
	lOutputThreshold := MAX(((input-lInitialCutbackThreshold)*lFactor),0.0);

	lMovement.InputThresholdAbsolute := lOutputThreshold;
	modulate := TRUE;	
ELSE
	modulate := FALSE;	
END_IF

