Name := 'ProgMovTest1';

SUPER^.initialize();
SubSystem := cSubsystemTravel;

lCode := cProgMovCode_Test1;
lTimeStepMax := 2000;

registerMovement(cProgMovCode_Travel_LATPos90_Forward);
registerMovement(cProgMovCode_Travel_LAT0_Forward);

lInactiveTimer.reset();
lSuccess := FALSE;
lTimeStep := 0;

IF (Enabled) THEN
	ProgMovDiagnostic := cProgMovDiagnosticEnabling;
	lState := cProgMovStatePreparing;
END_IF

IF (LeavingCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticLeaving;
	lState := cProgMovStateLeaving;
END_IF

IF (InterruptCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticInterrupted;
	lState := cProgMovStateLeaving;
END_IF

IF (ActiveCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticActivating;
	lState := cProgMovStateWaiting;
END_IF

lInactiveTimer.operator();
IF (lInactiveTimer.Expired) THEN
	lEnabled := FALSE;
	lState := cProgMovStateDisabled;
	ProgMovDiagnostic := cProgMovDiagnosticInactiveTimeout;
END_IF

Name := 'ProgMov';

_Throttle.Name := 'Throttle';
lThrottle REF= _Throttle;
registerNonOperational(ADR(_Throttle));

SUPER^.initialize();

lEnabledStallManagement := FALSE;
lRegisterOperatingMode := FALSE;
lEnableOnlyOnActiveAllow := FALSE;

lInactiveTimer.initialize();
lInactiveTimer.Enable := TRUE;
lInactiveTimer.Period := cInactiveTimer;

IF (LeavingCompleteCondition) THEN
	lEnabled := FALSE;
	lState := cProgMovStateDisabled;
	ProgMovDiagnostic := cProgMovDiagnosticLeaving;
END_IF

SUPER^.operator();

IF (NOT(Enabled)) THEN
	lState := cProgMovStateDisabled;
END_IF

CASE (lState) OF
	cProgMovStateDisabled:
		disabled();

	cProgMovStatePreparing:
		preparing();

	cProgMovStateInactive:
		inactive();

	cProgMovStateWaiting:
		waiting();

	cProgMovStateRunning:
		running();

	cProgMovStateFinishing:
		finishing();

	cProgMovStateLeaving:
		leaving();	
END_CASE

lProgMovDiagnostic := _ProgMovDiagnostic;
_ProgMovDiagnostic := cProgMovDiagnosticDisabled;

IF (PreparedCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticPrepared;
	lState := cProgMovStateInactive;
END_IF

ProgMovDiagnostic := cProgMovDiagnosticRunning;
lTimeStep := lTimeStep + 1;

IF (NOT(ActiveCondition)) THEN
	ProgMovDiagnostic := cProgMovDiagnosticDeactivatingFromRunning;
	lState := cProgMovStateFinishing;
END_IF

IF (InterruptCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticInterrupted;
	lState := cProgMovStateLeaving;
END_IF

IF (FinishCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticFinishing;
	lState := cProgMovStateFinishing;
	lSuccess := TRUE;
END_IF

IF (NOT(ActiveCondition)) THEN
	ProgMovDiagnostic := cProgMovDiagnosticDeactivatingFromWaiting;
	lState := cProgMovStateInactive;
END_IF

IF (StartCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticStarting;
	lState := cProgMovStateRunning;

	lSuccess := FALSE;
	lTimeStep := 0;
END_IF

InterruptCondition := FALSE;

IF (gSystemPrimary.UInterface.JoystickInputPresent) THEN
	InterruptCondition := TRUE;	
END_IF

getMovement REF= lProgMovNull;

CASE code OF		

	(*
cProgMovCode_Lift_Top:
		getMovement REF= lProgMov_Lift_Top;	

	cProgMovCode_Lift_Bottom:
		getMovement REF= lProgMov_Lift_Bottom;	

	cProgMovCode_Lift_StandardOnGround:
		getMovement REF= lProgMov_Lift_StandardOnGround;	

	cProgMovCode_Lift_StandardGround:
		getMovement REF= lProgMov_Lift_StandardGround;	

	cProgMovCode_Lift_StandardTruck:
		getMovement REF= lProgMov_Lift_StandardTruck;	

	cProgMovCode_Lift_StandardStack1:
		getMovement REF= lProgMov_Lift_StandardStack1;	

	cProgMovCode_Lift_StandardStack2:
		getMovement REF= lProgMov_Lift_StandardStack2;	

	cProgMovCode_Lift_HicubeOnGround:
		getMovement REF= lProgMov_Lift_HicubeOnGround;	

	cProgMovCode_Lift_HicubeGround:
		getMovement REF= lProgMov_Lift_HicubeGround;	

	cProgMovCode_Lift_HicubeTruck:
		getMovement REF= lProgMov_Lift_HicubeTruck;	

	cProgMovCode_Lift_HicubeStack1:
		getMovement REF= lProgMov_Lift_HicubeStack1;	

	cProgMovCode_Lift_HicubeStack2:
		getMovement REF= lProgMov_Lift_HicubeStack2;	

	cProgMovCode_Travel_LAT0_Forward:
		getMovement REF= lProgMov_Travel_LAT0_Forward;		

	cProgMovCode_Travel_LAT0_Reverse:
		getMovement REF= lProgMov_Travel_LAT0_Reverse;		

	cProgMovCode_Travel_LAT0_4WS_Forward:
		getMovement REF= lProgMov_Travel_LAT0_4WS_Forward;		

	cProgMovCode_Travel_LAT0_4WS_Reverse:
		getMovement REF= lProgMov_Travel_LAT0_4WS_Reverse;		

	cProgMovCode_Travel_LATPos90_Forward:
		getMovement REF= lProgMov_Travel_LATPos90_Forward;

	cProgMovCode_Travel_LATPos90_Reverse:
		getMovement REF= lProgMov_Travel_LATPos90_Reverse;

	cProgMovCode_Travel_LATNeg90_Forward:
		getMovement REF= lProgMov_Travel_LATNeg90_Forward;

	cProgMovCode_Travel_LATNeg90_Reverse:
		getMovement REF= lProgMov_Travel_LATNeg90_Reverse;

	cProgMovCode_Test1:
		getMovement REF= lProgMov_Test1;*)

	cProgMovCode_Steer_0:
		getMovement REF= lProgMov_Steer_0;
END_CASE

Name := 'ProgMovCntrl';

registerNonOperational(ADR(lProgMovNull));

lProgMov_Steer_0.Code := cProgMovCode_Steer_0;
lProgMov_Steer_0.Name := gTypeHandler.getTokenForEnum(cEnumTypeProgMovCode,cProgMovCode_Steer_0);
lProgMov_Steer_0.TargetAngle := 0;
lProgMov_Steer_0.TargetAngleIncrement := cPi/180.0/3.0;
lProgMov_Steer_0.TargetAngleZeroThreshold := 0.005;
registerNonOperational(ADR(lProgMov_Steer_0));

(*lProgMov_Test1.Code := cProgMovCode_Test1;
lProgMov_Test1.Name := getStringForProgMovCode(cProgMovCode_Test1);
lProgMov_Test1.TimeStepMax := 2000;
lProgMov_Test1.registerMovement(cProgMovCode_Travel_LATPos90_Forward);
lProgMov_Test1.registerMovement(cProgMovCode_Travel_LAT0_Forward);
registerNonOperational(ADR(lProgMov_Test1));*)

lMovement REF= lProgMovNull;

SUPER^.initialize();
SubSystem := cSubsystemMachine;

request(gSystemPrimary.UInterface.AutomationRequest);

IF ((NOT(lMovement.Enabled)) OR
	(gSystemPrimary.SystemState.State<cSystemStateOperational)) THEN
	lMovement REF= lProgMovNull;
END_IF

lMovement.operator();

IF (requested=cProgMovCodeNone) THEN
	RETURN;
END_IF

IF (requested=cProgMovCode_Clear) THEN
	lMovement REF= lProgMovNull;
	RETURN;
END_IF

movement REF= getMovement(requested);
IF (NOT(__ISVALIDREF(movement))) THEN
	RETURN;
END_IF

IF (movement.Code=cProgMovCodeNone) THEN
	RETURN;
END_IF

IF (NOT(movement.Available)) THEN
	RETURN;
END_IF

movement.Enabled := TRUE;
IF (NOT(movement.Enabled)) THEN
	movement.Enabled := FALSE;
	RETURN;
END_IF

lMovement REF= movement;

// allows continuous request, will not abort if requesting current

SUPER^.disabled();

lSequenceAchieved := FALSE;
lMovement REF= lProgMovNull;

IF (lCurrent>=lCount) THEN
	lSequenceAchieved := TRUE;
	lMovement REF= lProgMovNull;
	RETURN;
END_IF

lCurrent := lCurrent + 1;
request(lSequence[lCurrent]);

IF (lCount>=cCOuntMax) THEN
	gCodeErrorHandler(pMessage:=CONCAT('exceeded sequence size in ',lIdentity));
	RETURN;
END_IF

lCount := lCount+1;
lSequence[lCount] := code;

lMovement REF= lProgMovNull;

movement REF= gSystemPrimary.ProgrammedMovementControl.getMovement(code);

IF (NOT(__ISVALIDREF(movement))) THEN
	lSequenceAchieved := TRUE;
	RETURN;
END_IF

IF (movement.Code=cProgMovCodeNone) THEN
	lSequenceAchieved := TRUE;
	RETURN;
END_IF

IF (NOT(movement.Available)) THEN
	lSequenceAchieved := TRUE;
	RETURN;
END_IF

movement.Enabled := TRUE;
IF (NOT(movement.Enabled)) THEN
	movement.Enabled := FALSE;
	lSequenceAchieved := TRUE;
	RETURN;
END_IF

lMovement REF= movement;

SUPER^.running();

IF (lState<>cProgMovStateRunning) THEN
	RETURN;
END_IF

IF (not(lMovement.Enabled)) THEN
	next();
	RETURN;
END_IF

lMovement.operator();

IF (NOT(ActiveCondition)) THEN
	ProgMovDiagnostic := cProgMovDiagnosticDeactivatingFromWaiting;
	lState := cProgMovStateInactive;
END_IF

IF (StartCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticStarting;
	lState := cProgMovStateRunning;

	lSuccess := FALSE;
	lTimeStep := 0;
END_IF

lCurrent := 0;

InterruptCondition := FALSE;

IF ((gSystemPrimary.UInterface.TravelJoystickInputPresent) AND
	(gSystemPrimary.UInterface.LiftJoystickInputPresent)) THEN
	InterruptCondition := TRUE;	
END_IF

Name := 'ProgMovNull';

SUPER^.initialize();
SubSystem := cSubsystemMachine;

lCode := cProgMovCodeNone;

lSuccess := FALSE;
lEnabled := FALSE;
lState := cProgMovStateDisabled;
lProgMovDiagnostic := cProgMovDiagnosticDisabled;

SUPER^.running();

IF (lState<>cProgMovStateRunning) THEN
	RETURN;
END_IF

IF (ABS(gSystemPrimary.Steering.TargetAngle-lTargetAngle)<=lTargetAngleZeroThreshold) THEN
	lTargetAngleAchieved := TRUE;
ELSE
	lTargetAngleAchieved := FALSE;

	IF (gSystemPrimary.Steering.TargetAngle < lTargetAngle) THEN
		gSystemPrimary.Steering.TargetAngleIncrementDerived := lTargetAngleIncrement;
		gSystemPrimary.Steering.EnableDerivedTargetAngleIncrement := TRUE;
	END_IF
	IF (gSystemPrimary.Steering.TargetAngle > lTargetAngle) THEN
		gSystemPrimary.Steering.TargetAngleIncrementDerived := 0.0 - lTargetAngleIncrement;
		gSystemPrimary.Steering.EnableDerivedTargetAngleIncrement := TRUE;
	END_IF
END_IF

IF (NOT(ActiveCondition)) THEN
	ProgMovDiagnostic := cProgMovDiagnosticDeactivatingFromWaiting;
	lState := cProgMovStateInactive;
END_IF

IF (StartCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticStarting;
	lState := cProgMovStateRunning;

	lSuccess := FALSE;
	lTimeStep := 0;
END_IF

InterruptCondition := FALSE;

IF (gSystemPrimary.Steering.InputPresentPrimary) THEN
	InterruptCondition := TRUE;	
END_IF

SUPER^.finishing();

IF (lState<>cProgMovStateFinishing) THEN
	RETURN;
END_IF

IF (gSystemPrimary.Steering.CurrentMode<>lSteerModeOnFinishing) THEN
	gSystemPrimary.Steering.requestSteerMode(lSteerModeOnFinishing);
END_IF

SUPER^.running();

IF (lState<>cProgMovStateRunning) THEN
	RETURN;
END_IF

IF (ABS(gSystemPrimary.Steering.TargetAngle-lTargetAngle)<=lTargetAngleZeroThreshold) THEN
	lTargetAngleAchieved := TRUE;
ELSE
	lTargetAngleAchieved := FALSE;

	IF (gSystemPrimary.Steering.TargetAngle < lTargetAngle) THEN
		gSystemPrimary.Steering.TargetAngleIncrementDerived := lTargetAngleIncrement;
		gSystemPrimary.Steering.EnableDerivedTargetAngleIncrement := TRUE;
	END_IF
	IF (gSystemPrimary.Steering.TargetAngle > lTargetAngle) THEN
		gSystemPrimary.Steering.TargetAngleIncrementDerived := 0.0 - lTargetAngleIncrement;
		gSystemPrimary.Steering.EnableDerivedTargetAngleIncrement := TRUE;
	END_IF
END_IF

gSystemPrimary.Travel.EnableInputSecondary := TRUE;
gSystemPrimary.Travel.InputScalingOverride := TRUE;
gSystemPrimary.Travel.InputSecondaryValue := lTravelThrottle;

IF (NOT(ActiveCondition)) THEN
	ProgMovDiagnostic := cProgMovDiagnosticDeactivatingFromWaiting;
	lState := cProgMovStateInactive;
END_IF

IF (StartCondition) THEN
	ProgMovDiagnostic := cProgMovDiagnosticStarting;
	lState := cProgMovStateRunning;

	lSuccess := FALSE;
	lTimeStep := 0;
END_IF

IF (gSystemPrimary.Steering.CurrentMode<>lSteerModeRequired) THEN
	gSystemPrimary.Steering.requestSteerMode(lSteerModeRequired);
END_IF

InterruptCondition := FALSE;

IF (gSystemPrimary.UInterface.TravelJoystickInputPresent) THEN
	InterruptCondition := TRUE;	
END_IF

lVROverrideReady.initializeValueReference(lOverrideReady,NopSelf,'OvrdReady','Override ready checks','',cValueStyleParameter);

SUPER^.initialize();

lSteerAngleMinimum := gSystemPrimary.Steering.SteerAnglePhysicalMinimum;
lSteerAngleMaximum := gSystemPrimary.Steering.SteerAnglePhysicalMaximum;
lTravelThrottleThreshold := 1.0;

IF (ABS(inputAngle)<cTravelThresholdUnrestrictedAngle) THEN
	lTravelThrottleThreshold := 1.0;
	RETURN;
END_IF

lTravelThrottleThreshold := ABS(1.0 + (ABS(inputAngle)-cTravelThresholdUnrestrictedAngle)*lTravelThresholdFactor);

(* 4WS
	lSteerAngle = alpha
	lSteerAngleOuter = beta = arctan( B*TAN(alpha) / (B+2T*TAN(alpha)))	*)

tmpReal := TAN(ABS(inputAngle));
steerAngleOuter := ATAN(steerWheelBase * tmpReal /
		(steerWheelBase + 2.0 * tmpReal * steerWheelTrack));

IF (inputAngle=0) THEN
	wheelVelocityFactor := 1.0;
	targetAngle := 0;

ELSIF ((wheel.InnerFlag) XOR (inputAngle>0)) THEN
	(* the outer wheel
		~inner on positive angles
		inner on negative angles *)
	targetAngle := wheel.StandardSign * steerAngleOuter * inputAngle/ABS(inputAngle);

	(* outer wheel is at requested speed *)
	wheelVelocityFactor := 1.0;

ELSE
	(* the inner wheel
		inner on positive angles
		~inner on negative angles *)
	targetAngle := wheel.StandardSign * inputAngle;

	(* single wheel per yoke: ratio of inner/outer = SIN(beta)/SIN(alpha)
	lWheelVelocityFactor := SIN(lSteerAngleOuter)/SIN(ABS(lSteerAngle)); *)

	(* ratio of inner/outer = [B/(2.SIN(alpha)) - offset]/[B/(2.SIN(beta)) + offset] *)
	wheelVelocityFactor := (steerWheelBase/(2*SIN(ABS(inputAngle))))/
		(steerWheelBase/(2*SIN(ABS(steerAngleOuter))));
END_IF

calculateWheeltargetAngle.targetAngle := targetAngle;
calculateWheeltargetAngle.wheelVelocityFactor := wheelVelocityFactor;
calculateWheeltargetAngle.steerInput := steerInput * wheel.StandardSign;

Name := 'Steer4WS';
SUPER^.initialize();

lMode := cSteerMode4WS;

lSteerAngleMinimum := cSteerAngleMinimum;
lSteerAngleMaximum := cSteerAngleMaximum;

lTravelThresholdFactor := (1.0-cTravelThresholdMinimumThreshold)/(cTravelThresholdUnrestrictedAngle-cSteerAngleMaximum);

targetAngle := gSystemPrimary.Steering.CarouselAngle * wheel.CarouselSign;

IF (wheel.IndependentWheels) THEN
	IF (wheel.InnerFlag) THEN
		wheelVelocityFactor := -1.0;
	ELSE
		wheelVelocityFactor := 1.0;
	END_IF
ELSE
	wheelVelocityFactor := 1.0;

	IF ((wheel.DriveWheel) AND (wheel.InnerFlag)) THEN
		targetAngle := targetAngle - 3.14159265;
	END_IF
END_IF

calculateWheeltargetAngle.targetAngle := targetAngle;
calculateWheeltargetAngle.wheelVelocityFactor := wheelVelocityFactor;
calculateWheeltargetAngle.steerInput := 0.0;

Name := 'SteerCarousel';
SUPER^.initialize();

lMode := cSteerModeCarousel;

lTravelThrottleThreshold := cTravelThrottleThreshold;

CASE wheel.ID OF
	1:
		calculateWheeltargetAngle.targetAngle := cTargetAngleA;

	2:
		calculateWheeltargetAngle.targetAngle := cTargetAngleB;

	3:
		calculateWheeltargetAngle.targetAngle := cTargetAngleC;

	4:
		calculateWheeltargetAngle.targetAngle := cTargetAngleD;
END_CASE

calculateWheeltargetAngle.wheelVelocityFactor := 0.0;
calculateWheeltargetAngle.steerInput := 0.0;

Name := 'SteerCustom';
SUPER^.initialize();

lMode := cSteerModeCustom;

lTravelThrottleThreshold := cTravelThrottleThreshold;

IF (steerMode=cSteerModeLateralNeg90) THEN
	getInitialTargetAngle := -cPiOn2;
ELSIF (steerMode=cSteerModeLateralPos90) THEN
	getInitialTargetAngle := cPiOn2;
ELSE	
	getInitialTargetAngle := 0.0;
END_IF

Name := 'SteerLateral';
SUPER^.initialize();

lMode := cSteerModeLateral;

lTravelThrottleThreshold := cTravelThrottleThreshold;

lSteerAngleMinimum := cSteerAngleMinimum;
lSteerAngleMaximum := cSteerAngleMaximum;

// positive is extension, wheelD is reversed, wheelC is normal
IF ((wheel.DriveWheel) AND (NOT(wheel.InnerFlag))) THEN
	calculateWheelTargetAngle.targetAngle := 0.0 - cPIOn2;
ELSE
	calculateWheelTargetAngle.targetAngle := cPIOn2;
END_IF

calculateWheelTargetAngle.wheelVelocityFactor := 1.0;
calculateWheeltargetAngle.steerInput := 0.0;

Name := 'SteerReconfigure';
SUPER^.initialize();

lMode := cSteerModeReconfigure;

lTravelThrottleThreshold := cTravelThrottleThreshold;

documentation.xhtml:
lControllerIO: REFERENCE TO ControllerIO;
lControllerMotor: REFERENCE TO ControllerMotor; 	
 lControlSystem: PID;

lRequestedPrevious: t_percentage:= 0.0;
lRequestedNonZero: t_percentage:= 0.0;
lRequestedNonZeroPrevious: t_percentage:= 0.0;
lRequestedDelta: t_percentage:= 0.0;
lRequestedDeltaPrevious: t_percentage:= 0.0;

ST.xhtml:
IF (ABS(lCurrentVelocity)<cSteerVelocityZeroThreshold) THEN
	lCurrentVelocity := 0;
END_IF

IF  (ABS(lCurrentAngle-lPreviousAngle) >= cSteerAngleMaxSensorDelta) THEN
	lAlarmSteerLargeSensorDelta.report(FALSE); //foobar
END_IF

lPredictedTargetAngle := lTargetAngle;
lTargetPredictionOffset := 0.0;
IF (lEnableTargetPrediction) THEN
	IF ((lSteerInput>0.0) AND
		(lCurrentAngle>lTargetAngle)) THEN
		lPredictedTargetAngle := lCurrentAngle;
		lTargetPredictionOffset := lPredictedTargetAngle - lTargetAngle;
	END_IF
	IF ((lSteerInput<0.0) AND
		(lCurrentAngle<lTargetAngle)) THEN
		lPredictedTargetAngle := lCurrentAngle;
		lTargetPredictionOffset := lPredictedTargetAngle - lTargetAngle;
	END_IF
END_IF

IF (lOverideControl) THEN
	lCurrentVelocity := 0;
	lTargetAngleAdjustment := 0.0;
	lDeltaConverging := FALSE;
	lPreviousAngle := lCurrentAngle := lTargetAngleAdjusted := lPredictedTargetAngle := lTargetAngle;
END_IF

lDeltaPrevious := lDelta;
lDelta := (lCurrentAngle-lTargetAngle) * lControlFeedbackSign;
lState := cAdjustStateAdjusting;

IF (ABS(lDelta)>=cSteerAngleMaxErrorDelta) THEN
	lState := cAdjustStateError;
END_IF

IF (ABS(lDelta)>cDeltaConvergingRestartThreshold) THEN
	lDeltaConverging := TRUE;
	lTargetAngleAdjustment := cTargetAngleAdjustment;
END_IF

IF (Stationary) THEN
	lDeltaConverging := FALSE;
END_IF

IF (lMovementCount>=cDeltaCancelMovementCount) THEN
	lDeltaConverging := FALSE;	
END_IF

lDeltaConverging := (((lDeltaPrevious*lDelta) > 0.0) AND
	(lDeltaConverging));;

IF ((NOT(lDeltaConverging)) OR
	(lTravelMovement.InputPresentAny))  THEN
	lTargetAngleAdjustment := 0.0;
END_IF

IF (lCurrentAngle<lPredictedTargetAngle) THEN
	lTargetAngleAdjusted := lPredictedTargetAngle + lTargetAngleAdjustment;
ELSIF (lCurrentAngle>lPredictedTargetAngle) THEN
	lTargetAngleAdjusted := lPredictedTargetAngle - lTargetAngleAdjustment;
ELSE
	lTargetAngleAdjusted := lPredictedTargetAngle;
END_IF

IF (lTargetAngleAdjusted>lSteerMovement.SteerAngleMaximum) THEN
	lTargetAngleAdjusted := lSteerMovement.SteerAngleMaximum;
END_IF
IF (lTargetAngleAdjusted<lSteerMovement.SteerAngleMinimum) THEN
	lTargetAngleAdjusted := lSteerMovement.SteerAngleMinimum;
END_IF

lFilteredDelta := (lCurrentAngle-lTargetAngleAdjusted) * lControlFeedbackSign;

IF (ABS(lFilteredDelta)>=cSteerAngleMaxDelta) THEN
	lFilteredDelta := cSteerAngleMaxDelta * lFilteredDelta/ABS(lFilteredDelta);
END_IF

IF (lEnableOvershoot) THEN
	lOvershoot := ((lMovementCount>=cMovementCountOvershoot) AND
		(NOT(lTravelMovement.InputPresentAny)));

	IF (lOvershoot) THEN
		lFilteredDelta := 0.0;
	END_IF

(*	IF (lOvershoot) THEN
		lOvershootTimer.operator();

		IF (NOT(lOvershootTimer.Expired)) THEN
			lFilteredDelta := 0.0;
		END_IF
	ELSE
		lOvershootTimer.reset();	
	END_IF*)
END_IF

IF (ABS(lDelta)<lDeltaZeroThreshold) THEN
	IF (Stationary) THEN
		lModeChange := FALSE;
		lDeltaZeroThreshold := cSteerDeltaZeroThreshold;
	END_IF

	IF (NOT(lDeltaConverging)) THEN
		lState :=cAdjustStateGood;
		lFilteredDelta := 0;
		lTargetAngleAdjustment := 0.0;
	END_IF
END_IF

IF ((lModeChange) AND
	(OK) AND
	(lEnableModeChangeClearOnOK)) THEN
	lModeChange := FALSE;
END_IF

lRequestedSimple := lFilteredDelta*cSteerThrottleFactor;

(*lControlSystem.KP := cControlSystemKp;
lControlSystem.TN := cControlSystemKi;
lControlSystem.TV := cControlSystemKd;
lControlSystem.Y_OFFSET := 0;
lControlSystem.Y_MAX := cThrottleMax;
lControlSystem.Y_MIN := -1.0 * cThrottleMax;

lControlSystem.SET_POINT := lTargetAngleAdjusted;
lControlSystem.ACTUAL := lCurrentAngle;
lControlSystem.RESET := FALSE;

lControlSystem();

//lControlSystem.LIMITS_ACTIVE
//lControlSystem.OVERFLOW
lRequestedPID := lControlSystem.Y * lControlFeedbackSign;

IF (lEnableControlSystem) THEN
	lRequested := lRequestedPID;
ELSE
	lRequested := lRequestedSimple;
END_IF*)
lRequested := lRequestedSimple;

lRequestDelta := lRequestedPID - lRequestedSimple;

(*lRequestedDeltaPrevious := lRequestedDelta;
IF (ABS(lRequested-lRequestedPrevious)>=cRequestedEquivalentThreshold) THEN
	lRequestedDelta := lRequested - lRequestedPrevious;
END_IF

lRequestedNonZeroPrevious := lRequestedNonZero;
IF (ABS(lRequested)>=cRequestedEquivalentThreshold) THEN
	lRequestedNonZero := lRequested;
END_IF*)

IF ((ABS(lCurrentAngle-lPreviousAngle) >= cSteerAngleMaxMovementDelta) OR
	(ABS(lTargetAngle-lPreviousTargetAngle)>cTargetAngleChangeThreshold) OR
	(lTravelMovement.InputPresentAny) OR
	(lSteerMovement.InputPresentAny) OR
	(gSystemPrimary.SystemState.State<cSystemStateOperational)) THEN
	lRequestedCurve.reset();

	//lMovementCount := 0;
	//lRequestedDelta := 0.0;
	//lRequestedDeltaPrevious := 0.0;
END_IF

lRequestedCurve.InputAsPercentage := lRequested;
lRequestedCurve.operator();
lMovementCount := lRequestedCurve.Inflexions;

(*IF (((lRequestedDeltaPrevious<0.0) AND (lRequestedDelta>0.0)) OR
	((lRequestedDeltaPrevious>0.0) AND (lRequestedDelta<0.0)) OR
	((lRequestedNonZeroPrevious<0.0) AND (lRequestedNonZero>0.0)) OR
	((lRequestedNonZeroPrevious>0.0) AND (lRequestedNonZero<0.0))) THEN
	lMovementCount := lMovementCount + 1;
	IF (lMovementCount>cSteerMovementCountMax) THEN
		lMovementEventCount := lMovementEventCount + 1;
	END_IF
END_IF*)

(*IF (((lRequestedPrevious=0.0) AND (lRequested<>0.0)) OR}
	((lRequestedPrevious<0.0) AND (lRequested>0.0)) OR
	((lRequestedPrevious>0.0) AND (lRequested<0.0))) THEN
	lMovementCount := lMovementCount + 1;
	IF (lMovementCount>cSteerMovementCountMax) THEN
		lMovementEventCount := lMovementEventCount + 1;
	END_IF
END_IF *)

IF ((lEnableMovementManagement) AND (lMovementCount>cSteerMovementCountMax)) THEN
	lRequested := 0.0;
	Diagnostic := cMovementDiagnosticHunting;
END_IF

IF ((NOT(__ISVALIDREF(lThrottle))) OR
	(NOT(__ISVALIDREF(lControllerSteerAngle))) OR
	(NOT(__ISVALIDREF(lSteerMovement))) OR
	(NOT(__ISVALIDREF(lTravelMovement)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lVROverideControl.initializeValueReference(lOverideControl,NopSelf,'OverrideControl','Disable automatic control','',cValueStyleParameter);

lVREnableMovementManagement.initializeValueReference(lEnableMovementManagement,NopSelf,'EnblMovMgmt','Enable movement management','',cValueStyleParameter);
lVREnableOvershoot.initializeValueReference(lEnableOvershoot,NopSelf,'EnblOvershoot','Enable overshoot control','',cValueStyleParameter);
lVREnableTargetPrediction.initializeValueReference(lEnableTargetPrediction,NopSelf,'EnblPrediction','Enable predictive control','',cValueStyleParameter);
lVREnableModeChangeClearOnOK.initializeValueReference(lEnableModeChangeClearOnOK,NopSelf,'EnblMdChngClr','Enable mode change clear on OK','',cValueStyleParameter);

lAlarmSteerLargeSensorDelta.initializeState(NopSelf,'',cACSteerALargeSensorDelta);

lRequestedCurve.initializeValueObject(NopSelf,'Curve','Control curve metric','',cValueStyleConfigurable);

SUPER^.initialize();

lFunctionalMode := cFunctionalModeAny;

lRegisterUMFSPrimary := FALSE;
lRegisterUMFSAuxilliary := FALSE;
lRegisterUMFSSecondary := FALSE;

lRegisterActive := FALSE;
lRegisterOperatingMode := FALSE;

lEnabled := TRUE;
lEnableOperatingModeSlow := FALSE;
lEnableOnlyOnActiveAllow := FALSE;
lEnableUMFSCheck := FALSE;

cSteerDeltaZeroThreshold := 0.015; // implies min throttle (* increased from 0.010 from 0.005 from 0.0025 *)
cSteerDeltaZeroThresholdChangingMode := 0.025;
cSteerDeltaZeroThresholdMax := 0.030;
cSteerDeltaZeroThresholdGain := 0.002;
cTargetAngleAdjustment := 0.0;
cDeltaConvergingRestartThreshold := 0.015;
cRequestedEquivalentThreshold := 0.05;
cDeltaCancelMovementCount := 1;

cSteerVelocityZeroThreshold := 0.1;
cSteerThrottleFactor := -8.0; // max throttle of 0.54, increased from -6.0 to -7.0 up to -10.0 down to -8.0 for elextric, up to -14 for hydraulic m190 *)
cSteerAngleMaxSensorDelta := 0.3; (* Up from 0.1 *)
cSteerAngleMaxDelta := 0.08; // implies max throttle, limits magnitude of correction, should not saturate the drive
cSteerAngleMaxErrorDelta := 0.15; // limit on when to halt the system
cSteerAngleMaxMovementDelta := 0.5;

cSteerMovementCountMax := 3;

cControlSystemKp := 14.0;
cControlSystemKi := 40.0;
cControlSystemKd := 0.0;
cThrottleMax := 0.8;	

cTargetStationaryPeriod := T#1S;
cOvershootPeriod := T#500MS;
cTargetAngleChangeThreshold := 0.01;
cMovementCountOvershoot := 1;

(*lControlSystem.KP := cControlSystemKp;
lControlSystem.TN := cControlSystemKi;
lControlSystem.TV := cControlSystemKd;
lControlSystem.Y_OFFSET := 0;
lControlSystem.Y_MAX := cThrottleMax;
lControlSystem.Y_MIN := -1.0 * cThrottleMax;
lControlSystem.RESET := TRUE;
lControlSystem();
lControlSystem.RESET := FALSE;*)

lTargetStationaryTimer.initialize();
lTargetStationaryTimer.Enable := TRUE;
lTargetStationaryTimer.Period := cTargetStationaryPeriod;

lOvershootTimer.initialize();
lOvershootTimer.Enable := TRUE;
lOvershootTimer.Period := cOvershootPeriod;

// angle in radians
lPreviousAngle := lCurrentAngle;
lPreviousTargetAngle := lTargetAngle;
//lRequestedPrevious := lRequested;

IF (lTargetAngle<>lPreviousTargetAngle) THEN
	lTargetStationaryTimer.reset();
END_IF
lTargetStationaryTimer.operator();
lTargetStationary := lTargetStationaryTimer.Expired;

lCurrentAngle := lControllerSteerAngle.Angle;

// velocity in hz
lCurrentVelocity := lControllerSteerAngle.AngularVelocity;

checkWheelState();

lEnableUMFSCheck := NOT(ModeChange);

IF ((lRequested<>0.0) AND
	(ABS(lRequested)<lThrottleMinThreshold)) THEN
	lRequested := lThrottleMinThreshold*lRequested/ABS(lRequested);
END_IF

hunting();

IF (lModeChangeDisableControl) THEN
	lRequested := 0.0;
END_IF

lInput.InputAsPercentage := lRequested;
lInput.operator();

SUPER^.operator();

lThrottle REF= throttle;
lControllerSteerAngle REF= controller;
lSteerMovement REF= steerMovement;
lTravelMovement REF= travelMovement;

lModeChange := ModeChange;

IF (lModeChange) THEN
	lDeltaZeroThreshold := cSteerDeltaZeroThresholdChangingMode;
ELSE
	lDeltaZeroThreshold := cSteerDeltaZeroThreshold;
END_IF

lTargetAngle := Target.targetAngle;
lWheelVelocityFactor := Target.wheelVelocityFactor;
lSteerInput := Target.steerInput;

Mode.calculateTravelThrottleThreshold(lTargetAngle.Value);

lWheelA.Target := Mode.calculateWheelTargetAngle(lWheelA,lTargetAngle.Value,SteerWheelBase,SteerWheelTrack,lInputProcessed);
lWheelB.Target := Mode.calculateWheelTargetAngle(lWheelB,lTargetAngle.Value,SteerWheelBase,SteerWheelTrack,lInputProcessed);
lWheelC.Target := Mode.calculateWheelTargetAngle(lWheelC,lTargetAngle.Value,SteerWheelBase,SteerWheelTrack,lInputProcessed);
lWheelD.Target := Mode.calculateWheelTargetAngle(lWheelD,lTargetAngle.Value,SteerWheelBase,SteerWheelTrack,lInputProcessed);

(*lWheelA.checkWheelState();
lWheelB.checkWheelState();
lWheelC.checkWheelState();
lWheelD.checkWheelState();*)

lCurrentPositiveDelta := -1000.0;
lCurrentPositiveDelta := MAX(lCurrentPositiveDelta,lWheelA.lDelta);
lCurrentPositiveDelta := MAX(lCurrentPositiveDelta,lWheelB.lDelta);
lCurrentPositiveDelta := MAX(lCurrentPositiveDelta,lWheelC.lDelta);
lCurrentPositiveDelta := MAX(lCurrentPositiveDelta,lWheelD.lDelta);

lCurrentNegativeDelta := 1000;
lCurrentNegativeDelta := MIN(lCurrentNegativeDelta,lWheelA.lDelta);
lCurrentNegativeDelta := MIN(lCurrentNegativeDelta,lWheelB.lDelta);
lCurrentNegativeDelta := MIN(lCurrentNegativeDelta,lWheelC.lDelta);
lCurrentNegativeDelta := MIN(lCurrentNegativeDelta,lWheelD.lDelta);

lCurrentAbsDelta := 0;
lCurrentAbsDelta := MAX(lCurrentAbsDelta,ABS(lWheelA.lDelta));
lCurrentAbsDelta := MAX(lCurrentAbsDelta,ABS(lWheelB.lDelta));
lCurrentAbsDelta := MAX(lCurrentAbsDelta,ABS(lWheelC.lDelta));
lCurrentAbsDelta := MAX(lCurrentAbsDelta,ABS(lWheelD.lDelta));

lStationary := (lWheelA.Stationary AND
	lWheelB.Stationary AND
	lWheelC.Stationary AND
	lWheelD.Stationary);

lStalledSubSystemsPrevious := lStalledSubSystems;
lStalledSubSystems := (lWheelA.Stalled OR
	lWheelB.Stalled OR
	lWheelC.Stalled OR
	lWheelD.Stalled);

lAdjustState := MAX(lWheelA.State,
	MAX(lWheelB.State,
	MAX(lWheelC.State,lWheelD.State)));

lModeChange := ((lWheelA.ModeChange) OR
	(lWheelB.ModeChange) OR
	(lWheelC.ModeChange) OR
	(lWheelD.ModeChange));

IF ((lEnableSequentialModeChange) AND (lModeChange)) THEN
	IF (NOT(lWheelD.ModeChange)) THEN
		lWheelD.ModeChangeDisableControl := FALSE;
		lWheelA.ModeChangeDisableControl := FALSE;
	END_IF
	IF (NOT(lWheelC.ModeChange)) THEN
		lWheelC.ModeChangeDisableControl := FALSE;
		lWheelD.ModeChangeDisableControl := FALSE;
	END_IF
	IF (NOT(lWheelB.ModeChange)) THEN
		lWheelB.ModeChangeDisableControl := FALSE;
		lWheelC.ModeChangeDisableControl := FALSE;
	END_IF
	IF (NOT(lWheelA.ModeChange)) THEN
		lWheelA.ModeChangeDisableControl := FALSE;
		lWheelB.ModeChangeDisableControl := FALSE;
	END_IF
ELSE
	lWheelA.ModeChangeDisableControl := FALSE;	
	lWheelB.ModeChangeDisableControl := FALSE;	
	lWheelC.ModeChangeDisableControl := FALSE;	
	lWheelD.ModeChangeDisableControl := FALSE;	
END_IF

IF (NOT(lModeChange)) THEN
	lSteerModeDiagnostic := cSteerModeDiagnosticOK;
ELSE
	IF (lEnableActiveOnModeChange) THEN
		gSystemPrimary.Active.registerActive();
	END_IF	
END_IF

getMode REF= lSteerMode4WS;	

CASE mode OF		
	cSteerMode4WS:
		getMode REF= lSteerMode4WS;	
	cSteerModeLateral:
		getMode REF= lSteerModeLateral;
	cSteerModeCarousel:
		getMode REF= lSteerModeCarousel;
	cSteerModeReconfigure:
		getMode REF= lSteerModeReconfigure;
	cSteerModeLateralPos90:
		getMode REF= lSteerModeLateral;
	cSteerModeLateralNeg90:
		getMode REF= lSteerModeLateral;
	cSteerModeCustom:
		getMode REF= lSteerModeCustom;
END_CASE

Name := 'Steer';

lVREnableRelativeSteering.initializeValueReference(lEnableRelativeSteering,NopSelf,'EnblRelative','Relative steering control is enabled','',cValueStyleParameter);
lVREnableZeroTargetAngleSwitch.initializeValueReference(lEnableZeroTargetAngleSwitch,NopSelf,'EnblZero','Zero target angle switch is enabled','',cValueStyleParameter);
lVREnableSequentialModeChange.initializeValueReference(lEnableSequentialModeChange,NopSelf,'EnblSeqMdChng','Sequential mode change is enabled','',cValueStyleParameter);
lVREnableActiveOnModeChange.initializeValueReference(lEnableActiveOnModeChange,NopSelf,'EnblActMdChng','Mode change has active checks enabled','',cValueStyleParameter);
lVREnableDerivedTargetAngleIncrement.initializeValueReference(lEnableDerivedTargetAngleIncrement,NopSelf,'EnblDerTrgAng','Derived target angle increment is enabled','',cValueStyleParameter);
lVREnableOperatingModeLockOnSteerModeChange.initializeValueReference(lEnableOperatingModeLockOnSteerModeChange,NopSelf,'EnblOpMdLck','Mode change has operating mode checks enabled','',cValueStyleParameter);

_Throttle.Name := 'Throttle';
lThrottle REF= _Throttle;
registerNonOperational(ADR(_Throttle));

WheelA.Name := 'mA';
