lSteerModeLateral.Available := TRUE;
lSteerModeLateral.Enabled := TRUE;
registerNonOperational(ADR(lSteerModeLateral));

lSteerModeCarousel.Available := TRUE;
lSteerModeCarousel.Enabled := TRUE;
registerNonOperational(ADR(lSteerModeCarousel));

lSteerModeReconfigure.Available := TRUE;
lSteerModeReconfigure.Enabled := FALSE;
registerNonOperational(ADR(lSteerModeReconfigure));

