setCarouselAngle();

lEnableSequentialModeChange := FALSE;

cSteerAngleMaxUpdateDelta := 0.06; // limit on how far away the target can be pushed
cSteerAngleMaxDerivedUpdateDelta := 0.07;
cSteerAngleThrottleIncrement := 0.006;
cSteerAngleDeltaGain := 0.0;

WheelA.ControlFeedbackSign := -1.0;
