WheelB.DriveWheel := TRUE;
WheelB.InnerFlag := TRUE;
WheelB.WheelDirection := -1.0;
WheelB.IndependentWheels := TRUE;

WheelC.ControlFeedbackSign := -1.0;
WheelC.CarouselSign := 1.0;
