WheelD.ControlFeedbackSign := -1.0;
WheelD.CarouselSign := -1.0;
WheelD.StandardSign := -1.0;
WheelD.DriveWheel := TRUE;
WheelD.InnerFlag := FALSE;
WheelD.WheelDirection := 1.0;
WheelD.IndependentWheels := TRUE;

{IF defined (TargetD19)}
	lEnableSequentialModeChange := TRUE;

	cSteerAngleMaxUpdateDelta := 0.07; // limit on how far away the target can be pushed
	cSteerAngleMaxDerivedUpdateDelta := 0.07;
	cSteerAngleThrottleIncrement := 0.08;
	cSteerAngleDeltaGain := 1.0; // foobar

	WheelA.ControlFeedbackSign := 1.0;
	WheelA.CarouselSign := 1.0;
	WheelA.StandardSign := 1.0;
	WheelA.DriveWheel := FALSE;
	WheelA.InnerFlag := FALSE;
	WheelA.WheelDirection := 1.0;
	WheelA.IndependentWheels := TRUE;

	WheelB.ControlFeedbackSign := 1.0;
	WheelB.CarouselSign := -1.0;
	WheelB.StandardSign := 1.0;
	WheelB.DriveWheel := FALSE;
	WheelB.InnerFlag := TRUE;
	WheelB.WheelDirection := -1.0;
	WheelB.IndependentWheels := TRUE;

	WheelC.ControlFeedbackSign := 1.0;
	WheelC.CarouselSign := 1.0;
	WheelC.StandardSign := -1.0;
	WheelC.DriveWheel := TRUE;
	WheelC.InnerFlag := TRUE;
	WheelC.WheelDirection := -1.0;
	WheelC.IndependentWheels := TRUE;

	WheelD.ControlFeedbackSign := 1.0;
	WheelD.CarouselSign := -1.0;
	WheelD.StandardSign := -1.0;
	WheelD.DriveWheel := TRUE;
	WheelD.InnerFlag := FALSE;
	WheelD.WheelDirection := 1.0;
	WheelD.IndependentWheels := TRUE;
{END_IF}

lFunctionalMode := cFunctionalModeAny;

lMode REF= lSteerMode4WS;

lTargetAngleUpdateTimer.Period := cTargetAngleUpdatePeriod;
lTargetAngleUpdateTimer.Enable := TRUE;
lTargetAngleUpdateTimer.initialize();

requestSteerMode(gSystemPrimary.UInterface.SteerModeRequest);

lInput.InputAsPercentage := gSystemPrimary.UInterface.Steer;
lInput.operator();

SUPER^.operator();

lZeroTargetAngleSwitch.Value := gSystemPrimary.UInterface.ZeroSteerTargetAngle;
lZeroTargetAngleSwitch.operator();

IF (lEnableRelativeSteering) THEN
	lRegisterActive := TRUE;

	IF ((lZeroTargetAngleSwitch.Value) AND (lEnableZeroTargetAngleSwitch)) THEN
		zeroTargetAngle();
	END_IF

	lTargetAngleShift := lInput.Value;
ELSE
	lRegisterActive := TRUE;

	IF (lZeroTargetAngleSwitch.Value) THEN
		gSystemPrimary.Active.registerActive();
	END_IF

	IF (gSystemPrimary.Active.Allow) THEN
		lRequestedAbsoluteTargetAngle := lInput.Value;

		IF (lRequestedAbsoluteTargetAngle>=Mode.SteerAngleMaximum) THEN
			lRequestedAbsoluteTargetAngle := Mode.SteerAngleMaximum;
		END_IF
		IF (lRequestedAbsoluteTargetAngle<=Mode.SteerAngleMinimum) THEN
			lRequestedAbsoluteTargetAngle := Mode.SteerAngleMinimum;
		END_IF

		lTargetAngleShift := (lRequestedAbsoluteTargetAngle - lTargetAngle.Value) * cSteerAbsoluteShiftFactor;
	ELSE
		lTargetAngleShift := 0.0;	
	END_IF

	IF (lTargetAngleShift<-1.0) THEN
		lTargetAngleShift := -1.0;
	END_IF
	IF (lTargetAngleShift>1.0) THEN
		lTargetAngleShift := 1.0;
	END_IF
END_IF

updateTargetAngle();
checkWheelStates();

lWheelA.operator();
lWheelB.operator();
lWheelC.operator();
lWheelD.operator();

IF (lStalledSubSystems) THEN
	IF (NOT(lStalledSubSystemsPrevious)) THEN
		lStallClearPreCondition := NOT(InputPresentAny);
		lStallClearPreConditionCleared := FALSE;
	END_IF

	lStalled := TRUE;
END_IF

IF (lStalled) THEN
	lStallClearPreConditionCleared := (((InputPresentAny) AND (lStallClearPreCondition)) OR
		((NOT(InputPresentAny)) AND (NOT(lStallClearPreCondition))));

	lStalled := (NOT((gSystemPrimary.Travel.InputPresentAny) OR
		((InputPresentAny) AND
		(lStallClearPreConditionCleared))));
END_IF

IF (NOT(lStalled)) THEN
	WheelA.Throttle.clearStalled();
	WheelB.Throttle.clearStalled();
	WheelC.Throttle.clearStalled();
	WheelD.Throttle.clearStalled();
END_IF

IF (requestedSteerMode=cSteerModeNone) THEN
	RETURN;
END_IF

lSteerModeDiagnostic := cSteerModeDiagnosticOK;

IF (Mode.matches(requestedSteerMode)) THEN
	// essentially re-initializes to this steering mode
	angle := Mode.getInitialTargetAngle(lTargetAngle.Value,requestedSteerMode);
	IF (lTargetAngle.Value<>angle) THEN
		lTargetAngle.Value := angle;

		lWheelA.ModeChange := TRUE;
		lWheelB.ModeChange := TRUE;
		lWheelC.ModeChange := TRUE;
		lWheelD.ModeChange := TRUE;

		IF (lEnableSequentialModeChange) THEN
			lWheelA.ModeChangeDisableControl := FALSE;
			lWheelB.ModeChangeDisableControl := TRUE;
			lWheelC.ModeChangeDisableControl := TRUE;
			lWheelD.ModeChangeDisableControl := TRUE;
		END_IF
	END_IF

	requestSteerMode := lSteerModeDiagnostic;
	RETURN;
END_IF

IF (NOT(checkModeEnabled(requestedSteerMode))) THEN
	lSteerModeDiagnostic := cSteerModeDiagnosticNotEnabled;
	//gMessageManager.register(lCode:=cMCAdviseSteerModeIllegalRequest);

	requestSteerMode := lSteerModeDiagnostic;
	RETURN;
END_IF

IF ((lEnableOperatingModeLockOnSteerModeChange) AND
	(gSystemPrimary.OperatingMode.lock(cOperatingModeLockPeriod)<>cOperatingModeLocked)) THEN
	lSteerModeDiagnostic := cSteerModeDiagnosticUnableToLockDrive;
	//gMessageManager.register(lCode:=cMCAdviseSteerModeUnableToLockDrive);

	requestSteerMode := lSteerModeDiagnostic;
	RETURN;
END_IF

lMode.leave();
lMode REF= getMode(requestedSteerMode);
lSteerModeDiagnostic := cSteerModeDiagnosticChanging;

lTargetAngle.Value := Mode.getInitialTargetAngle(0.0,requestedSteerMode);

lWheelA.ModeChange := TRUE;
lWheelB.ModeChange := TRUE;
lWheelC.ModeChange := TRUE;
lWheelD.ModeChange := TRUE;

IF (lEnableSequentialModeChange) THEN // foobar apollo issue remaining - not all wheels are moving at the same time during mode changes, but could be spurious due to stalling
	lWheelA.ModeChangeDisableControl := FALSE;
	lWheelB.ModeChangeDisableControl := TRUE;
	lWheelC.ModeChangeDisableControl := TRUE;
	lWheelD.ModeChangeDisableControl := TRUE;
END_IF

// checkWheelStates();

CASE lMode.Mode OF
	cSteerModeNone:
		requestSteerMode(cSteerMode4WS);
	cSteerMode4WS:
		requestSteerMode(cSteerModeLateral);
	cSteerModeLateral:
		requestSteerMode(cSteerModeCarousel);
	cSteerModeCarousel:
		requestSteerMode(cSteerMode4WS);
END_CASE

IF (lEnableUpdateTimer) THEN
	lTargetAngleUpdateTimer.operator();
	IF (NOT(lTargetAngleUpdateTimer.lExpired)) THEN
		RETURN;
	END_IF
	lTargetAngleUpdateTimer.reset();
END_IF

IF (lTargetAngleShift=0.0) THEN
	IF (lEnableDerivedTargetAngleIncrement) THEN
		lTargetAngleIncrementDerivedPost := lTargetAngleIncrementDerived;

		IF (((lTargetAngleIncrementDerived>0) AND
			(ABS(lCurrentPositiveDelta)>cSteerAngleMaxDerivedUpdateDelta)) OR
			((lTargetAngleIncrementDerived<0) AND
			(ABS(lCurrentNegativeDelta)>cSteerAngleMaxDerivedUpdateDelta))) THEN
			lTargetAngleIncrementDerivedPost := 0.0;
		END_IF

		lTargetAngle.Value := lTargetAngle.Value + lTargetAngleIncrementDerivedPost;

		//lTargetAngleIncrementDerived := 0.0;
	END_IF
ELSE
	lTargetAngleIncrement := 0;

	IF (lTargetAngleShift>0) THEN
		IF (ABS(lCurrentPositiveDelta)<cSteerAngleMaxUpdateDelta) THEN
			lTargetAngleIncrement := lTargetAngleShift*cSteerAngleThrottleIncrement + cSteerAngleDeltaGain*lCurrentNegativeDelta;
			lTargetAngleIncrement := MAX(0,lTargetAngleIncrement);
		ELSIF (gSystemPrimary.Travel.Stationary) THEN
			lTargetAngleIncrement := lStationaryTargetAngleIncrement;
		END_IF
	END_IF

	IF (lTargetAngleShift<0) THEN
		IF (ABS(lCurrentNegativeDelta)<cSteerAngleMaxUpdateDelta) THEN
			lTargetAngleIncrement := lTargetAngleShift*cSteerAngleThrottleIncrement + cSteerAngleDeltaGain*lCurrentPositiveDelta;
			lTargetAngleIncrement := MIN(0,lTargetAngleIncrement);
		ELSIF (gSystemPrimary.Travel.Stationary) THEN
			lTargetAngleIncrement := 0.0 - lStationaryTargetAngleIncrement;
		END_IF
	END_IF

	lTargetAngle.Value := lTargetAngle.Value + lTargetAngleIncrement;
END_IF

lEnableDerivedTargetAngleIncrement := FALSE;
lTargetAngleIncrementDerived := 0.0;

lTargetAngle.operator();

IF (lTargetAngle.Value>=Mode.SteerAngleMaximum) THEN
	lTargetAngle.Value := Mode.SteerAngleMaximum;
END_IF
IF (lTargetAngle.Value<=Mode.SteerAngleMinimum) THEN
	lTargetAngle.Value := Mode.SteerAngleMinimum;
END_IF

// foobar, gradually change speed with steering angle, especially in lateral mode

lSteerWheelTrack := gSystemPrimary.LocalMachinePrimary.WheelTrack; //foobar move to calibrate()?
lSteerWheelBase := gSystemPrimary.LocalMachinePrimary.WheelBase;

_ThrottleA.Name := 'ThrottleA';
_ThrottleA.SubSystem := cSubsystemSteerA;
_ThrottleA.ControllerMotor REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerA;
_ThrottleA.PositionObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleA.AngleObject;
_ThrottleA.VelocityObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleB.AngularVelocityObject;
WheelA.initializeSlew(_ThrottleA,gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleA,THIS^,gSystemPrimary.Travel);
registerNonOperational(ADR(_ThrottleA));

_ThrottleB.Name := 'ThrottleB';
_ThrottleB.SubSystem := cSubsystemSteerB;
_ThrottleB.ControllerMotor REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerB;
_ThrottleB.PositionObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleB.AngleObject;
_ThrottleB.VelocityObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleB.AngularVelocityObject;
WheelB.initializeSlew(_ThrottleB,gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleB,THIS^,gSystemPrimary.Travel);
registerNonOperational(ADR(_ThrottleB));

_ThrottleC.Name := 'ThrottleC';
_ThrottleC.SubSystem := cSubsystemSteerC;
_ThrottleC.ControllerMotor REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerC;
_ThrottleC.PositionObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleC.AngleObject;
_ThrottleC.VelocityObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleC.AngularVelocityObject;
WheelC.initializeSlew(_ThrottleC,gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleC,THIS^,gSystemPrimary.Travel);
registerNonOperational(ADR(_ThrottleC));

_ThrottleD.Name := 'ThrottleD';
_ThrottleD.SubSystem := cSubsystemSteerD;
_ThrottleD.ControllerMotor REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerD;
_ThrottleD.PositionObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleD.AngleObject;
_ThrottleD.VelocityObject REF= gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleD.AngularVelocityObject;
WheelD.initializeSlew(_ThrottleD,gSystemPrimary.CANOpenMasterDrivePrimary.SteerAngleD,THIS^,gSystemPrimary.Travel);
registerNonOperational(ADR(_ThrottleD));

SUPER^.initialize();

lRegisterUMFSPrimary := TRUE;
lRegisterUMFSAuxilliary := TRUE;
lRegisterUMFSSecondary := TRUE;

lRegisterActive := TRUE;
lRegisterOperatingMode := TRUE;

lEnabled := TRUE;
lEnableOperatingModeSlow := FALSE;
lEnableOnlyOnActiveAllow := FALSE;
lEnableUMFSCheck := TRUE;

IF (NOT(__ISVALIDREF(lThrottle))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lCurrentVelocity := 0.0;
lStationary := FALSE;
lStalled := FALSE;

IF (CurrentVelocity=0) THEN
	CurrentDirection := cDirectionStationary;
ELSIF (CurrentVelocity>0.0) THEN
	CurrentDirection := cDirectionForward;
ELSE
	CurrentDirection := cDirectionReverse;
END_IF

lThrottle REF= _Throttle;
_Throttle.initializeValueObjectOp(OpSelf,'Value','Throttle value','',cValueStyleConfigurable);

IF (NOT(__ISVALIDREF(lMovement))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lThrottle REF= _Throttle;
_Throttle.initializeValueObjectOp(OpSelf,'Value','Throttle value','',cValueStyleConfigurable);

IF (NOT(__ISVALIDREF(lControllerMotor))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

SUPER^.operator();

lControllerMotor.RequestedThrottle := lThrottle.Value;

lCurrentVelocity := lControllerMotor.Velocity;
lStationary := lControllerMotor.Stationary;
lStalled := lControllerMotor.Stalled;

SUPER^.operator();

lCurrentVelocity := lVelocity.Value;
lStationary := ((lVelocity.Value=0) AND (lThrottle.Value=0));
lStalled := false;

IF ((NOT(__ISVALIDREF(lPosition))) OR
	(NOT(__ISVALIDREF(lVelocity)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

Name := 'Alarm';

lAlarmSecondaryPowerFail.initializeState(NopSelf,'',cACSecondaryPowerFail);
lAlarmSecondaryPowerFail.Life := 10;
lAlarmSecondaryPowerFail.InitialSeverity := cSeverityNone;
lAlarmSecondaryPowerFail.SeverityWarningTimeout := T#1S;
lAlarmSecondaryPowerFail.SeverityErrorTimeout := T#2S;
lAlarmSecondaryPowerFail.SeverityCriticalTimeout := T#5S;

lOutputSystemState := cSystemStateOperational;

SUPER^.initialize();
SubSystem := cSubsystemPowerpack;

IF (lEnableAlarmInReverseOnly) THEN
	lOutput.Value := (gSystemPrimary.Travel.Throttle.Value < 0);
ELSE
	lOutput.Value := gSystemPrimary.OperatingMode.Moving;
END_IF

IF ((lOutput.Value) AND
	(gSystemPrimary.lSecondaryPowerSupply.Availability<cSecondaryRequiredAvailability)) THEN	
	lAlarmSecondaryPowerFail.trigger(FALSE);

	lOutput.Value := FALSE;
END_IF

SUPER^.operator();

Name := 'Beacons';

lAlarmSecondaryPowerFail.initializeState(NopSelf,'',cACBeaconsSecondaryPowerFail);
lAlarmSecondaryPowerFail.Life := 10;
lAlarmSecondaryPowerFail.InitialSeverity := cSeverityNone;
lAlarmSecondaryPowerFail.SeverityWarningTimeout := T#1S;
lAlarmSecondaryPowerFail.SeverityErrorTimeout := T#2S;
lAlarmSecondaryPowerFail.SeverityCriticalTimeout := T#5S;

SUPER^.initialize();
SubSystem := cSubsystemBeacons;

lOutputSystemState := cSystemStateOperational;

lOutput.Value := (gSystemPrimary.SystemState.State=cSystemStateOperational);

IF ((lOutput.Value) AND
	(gSystemPrimary.lSecondaryPowerSupply.Availability<cSecondaryRequiredAvailability)) THEN	
	lAlarmSecondaryPowerFail.trigger(FALSE);

	lOutput.Value := FALSE;
END_IF

SUPER^.operator();

Name := 'CabinSecPwr';

SUPER^.initialize();
SubSystem := cSubsystemPowerpack;

lOutputSystemState := cSystemStatePreparing;

Name := 'EstopLoad';

SUPER^.initialize();
SubSystem := cSubsystemUInterface;

lOutputSystemState := cSystemStatePoweringUp;

Name := 'Horn';

SUPER^.initialize();
SubSystem := cSubsystemPowerpack;

lOutputSystemState := cSystemStatePreOperational;

Name := 'Lights';

SUPER^.initialize();
SubSystem := cSubsystemLights;

lOutputSystemState := cSystemStateCharging;

Name := 'PumpCooling';

SUPER^.initialize();
SubSystem := cSubsystemBattery;

lOutputSystemState := cSystemStateOperational;

Name := 'SensorSupply';

SUPER^.initialize();
SubSystem := cSubsystemPowerpack;

lOutputSystemState := cSystemStatePreparing;

lOutput.Scaling := 12000;

Name := 'Active';

lVREnableExitOperational.initializeValueReference(lEnableExitOperational,NopSelf,'EnblExitOp','Automatically exit operational upon timeout','',cValueStyleParameter);

lCausalStopOnTimeout.initializeState(NopSelf,'',cCCStopOnTimeout);
lCausalStopOnTimeout.Control := cSystemControlStop;
lCausalStopOnTimeout.AllowableSystemState := cSystemStatePreOperational;

SUPER^.initialize();

lExitOperationalTimer.lEnable := TRUE;
lExitOperationalTimer.lPeriod := cActiveExitOperationalTimeout;
lExitOperationalTimer.initialize();

{IF defined(target_d19)}
lPreTimer.lPeriod := T#750MS;
lPostTimer.lPeriod := T#5S;
{END_IF}

lValueUI := lRegisterUI;
lRegisterUI := FALSE;

IF (gSystemPrimary.UInterface.UMFS) THEN
	registerActive();
END_IF

SUPER^.operator();

IF (gSystemPrimary.SystemState.State<>cSystemStateOperational) THEN
	lState := t_active_state.cActiveStateNone;
	lExitOperationalTimer.reset();
END_IF

IF (IsActive) THEN
	lExitOperationalTimer.reset();
END_IF
lExitOperationalTimer.operator();

IF ((gSystemPrimary.SystemState.State=cSystemStateOperational) AND
	((lExitOperationalTimer.lExpired) AND (lEnableExitOperational))) THEN
	lCausalStopOnTimeout.trigger(FALSE);
END_IF

Name := 'OperatingMode';

lCausalWaitingForParked.initializeState(NopSelf,'',cCCWaitingForParked);

lVRForceSlow.initializeValueReference(lForceSlow,NopSelf,'ForceSlow','Force slow mode','',cValueStyleParameter);

SUPER^.initialize();

lSlow := FALSE;

lAllParked := TRUE;
lAllStopped := TRUE;
lAnyStalled := FALSE;

lMode := cOperatingModeParked;

lLockTimer.Enable := TRUE;
lLockTimer.Period := T#1S;
lLockTimer.initialize();

IF (lMode=cOperatingModeStopped) THEN
	lMode := cOperatingModeLocked;
	IF (period>T#0S) THEN
		lLockTimer.Period := period;
		lLockTimer.reset();
		lEnableLockTimer := TRUE;
	ELSE
		lEnableLockTimer := FALSE;		
	END_IF
END_IF

lock := lMode;

request(gSystemPrimary.UInterface.OperatingMethodRequest);

IF (gSystemPrimary.SystemState.State<cSystemStateOperational) THEN
	park();
END_IF

IF (gSystemPrimary.SystemState.State<=cSystemStatePreOperational) THEN
	reset();
END_IF

IF ((lEnableAutoUnpark) AND
	(gSystemPrimary.SystemState.State=cSystemStateOperational) AND
	(lMode<=cOperatingModeParking)) THEN
	unpark();
END_IF

(* wait until movement has stopped *)
IF (gSystemPrimary.SystemState.State=cSystemStateExitOperational) THEN
	IF (lMode>cOperatingModeParked) THEN
		gSystemPrimary.SystemState.transitionAllowDown(cSystemStateExitOperational,ADR(lCausalWaitingForParked),lCausalWaitingForParked.Override);
	END_IF
END_IF

IF ((lMode=cOperatingModeParking) AND (lAllParked)) THEN
	lMode := cOperatingModeParked;
END_IF

IF ((lMode=cOperatingModeUnparking) AND (lAllStopped)) THEN
	lMode := cOperatingModeStopped;
END_IF

IF ((lEnableLockTimer) AND (lMode=cOperatingModeLocked)) THEN
	lLockTimer.operator();
	IF (lLockTimer.Expired) THEN
		unlock();
	END_IF
END_IF

IF (lMode>cOperatingModeLocked) THEN
	IF (lAllStopped) THEN
		lMode := cOperatingModeStopped;
	ELSIF (lAnyStalled) THEN
		lMode := cOperatingModeStalled;
	ELSIF ((lSlow) OR
		(lForceSlow)) THEN
		lMode := cOperatingModeSlow;
	ELSE
		lMode := cOperatingModeNormal;
	END_IF
END_IF

lAllParked := TRUE;
lAllStopped := TRUE;
lAnyStalled := FALSE;

(* allows recovery from inoperable and locked *)

IF (lMode=cOperatingModeParked) THEN
	RETURN;
END_IF

lMode := cOperatingModeParking;

park := lMode;

lAnyStalled := TRUE;
lAllStopped := FALSE;
lAllParked := FALSE;

IF ((lMode=cOperatingModeParked) OR
	(lMode=cOperatingModeParking)) THEN
	lMode := cOperatingModeUnparking;
	togglePark := lMode;
	RETURN;
END_IF

lMode := cOperatingModeParking;

togglePark := lMode;

IF ((lMode=cOperatingModeParked) OR
	(lMode=cOperatingModeParking)) THEN
	lMode := cOperatingModeUnparking;
END_IF

unpark := lMode;

SUPER^.operator();

(* traffic FROM master PLC *)

lExternalState := fMergeBitsIntoWord(pWord:=lExternalState,pData:=gSystemPrimary.SystemState.State,pStart:=0);
lExternalState := fMergeBitsIntoWord(pWord:=lExternalState,pData:=gSystemPrimary.OperatingMode.Mode,pStart:=4);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=gSystemPrimary.lUMFS.Allow,pStart:=8);

(* traffic to master PLC *)

IF (lOperatingModeLockRequest.Value) THEN
	gSystemPrimary.OperatingMode.lock(T#2S);
END_IF

IF (lOperatingModeRunningRegister.Value) THEN
	gSystemPrimary.OperatingMode.registerRunning();
ELSE
	gSystemPrimary.OperatingMode.registerStopped();
END_IF

IF (lUMFSRegister.Value) THEN
	gSystemPrimary.lUMFS.registerSlave();
END_IF

CASE lUIEventCode OF
	cUIEventCodeToggleLights:
		gSystemPrimary.Lights.toggleOutput();

	cUIEventCodeStart:
		IF (gSystemPrimary.SystemState.State=cSystemStatePreOperational) THEN
			lCausalCommandStart.trigger(FALSE);
			gSystemPrimary.SystemState.transitionStart(cSystemStateOperational,ADR(lCausalCommandStart),lCausalCommandStart.Override);
		END_IF

	cUIEventCodeStop:
		IF (gSystemPrimary.SystemState.State>cSystemStatePreOperational) THEN
			lCausalCommandStop.trigger(FALSE);
			gSystemPrimary.SystemState.transitionStop(cSystemStatePreOperational,ADR(lCausalCommandStop),lCausalCommandStop.Override);
		END_IF
END_CASE

lUIEventCode := gSystemPrimary.UInterface.UIEventCodeRequest;

IF (lUIEventCode=lUIEventCodePrevious) THEN
	RETURN;
END_IF
lUIEventCodePrevious := lUIEventCode;

IF (lUIEventCode=cUIEventCodeNone) THEN
	RETURN;
END_IF

_operator();

Name := 'UMFS';

lAllow.initializeValueObjectOp(OpSelf,'Allow','UMFS allows related movements','',cValueStyleConfigurable);

SUPER^.initialize();
SubSystem := cSubsystemUInterface;

lSeatSwitch := FALSE;
lUISwitch := FALSE;
lUISignal := FALSE;
lUIPrimary := FALSE;
lUIAuxilliary := FALSE;
lUISlave := FALSE;

lSmoothingTimer.Enable := TRUE;
lSmoothingTimer.Period := cSmoothingPeriod;
lSmoothingTimer.initialize();

IF (gSystemPrimary.UInterface.UMFS) THEN
	registerUISwitch();
END_IF

lAllow.Value := (((lSeatSwitch) AND (lUISignal) AND (lEnableSeat)) OR
	((lUISwitch) AND (lEnableSwitch)) OR
	((lUISignal) AND (lEnableSignal)) OR
	((lUIPrimary) AND (lEnablePrimary)) OR
	((lUISecondary) AND (lEnableSecondary)) OR
	((lUIAuxilliary) AND (lEnableAuxilliary)) OR
	((lUISlave) AND (lEnableSlave)));

lSmoothingTimer.operator();
IF (lAllow.Value) THEN
	lSmoothingTimer.reset();
END_IF
lAllow.Value := ((lAllow.Value) OR (NOT(lSmoothingTimer.Expired)));

SUPER^.operator();

lSeatSwitch := FALSE;
lUISwitch := FALSE;
lUISignal := FALSE;
lUIPrimary := FALSE;
lUISecondary := FALSE;
lUIAuxilliary := FALSE;
lUISlave := FALSE;

Name := 'Cabin';

IF (NOT(__ISVALIDREF(lControllerUInterfaceCabin))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

lUInterfaceId := t_ui_id.cUIIdA;

AutomationStart := FALSE;

IF ((Active) AND
	(gSystemPrimary.ProgrammedMovementControl.Enabled)) THEN
	AutomationStart := lControllerUInterfaceCabin.AutomationStart;
END_IF

TwistlockLock := FALSE;

IF (Active) THEN
	TwistlockLock := lControllerUInterfaceCabin.TwistlockLock;
END_IF

TwistlockUnlock := FALSE;

IF (Active) THEN
	TwistlockUnlock := lControllerUInterfaceCabin.TwistlockUnlock;
END_IF

ZeroSteerTargetAngle := FALSE;

IF (Active) THEN
	ZeroSteerTargetAngle := lControllerUInterfaceCabin.ZeroSteerTargetAngle;
END_IF

Lift := 0;

IF (Active) THEN
	Lift := lControllerUInterfaceCabin.Lift;
END_IF

LiftBalanceAB := 0;

IF (Active) THEN
	LiftBalanceAB := lControllerUInterfaceCabin.LiftBalanceAB;
END_IF

LiftBalanceAD := 0;

IF (Active) THEN
	LiftBalanceAD := lControllerUInterfaceCabin.LiftBalanceAD;
END_IF

SideshiftAB := 0;

IF (Active) THEN
	SideshiftAB := lControllerUInterfaceCabin.SideshiftAB;
END_IF

SideshiftCD := 0;

IF (Active) THEN
	SideshiftCD := lControllerUInterfaceCabin.SideshiftCD;
END_IF

SpreaderTelescopingExtend := FALSE;

IF ((Active) AND
