lPower.initializeOutput(outputRadio);

lInputEstopStatus.InputReference REF= inputEstopStatus;

lInputSafetyHardwiredA.InputReference REF= inputUMFSA;
lInputSafetyHardwiredB.InputReference REF= inputUMFSB;

AutomationStart := FALSE;

IF ((Active) AND
	(gSystemPrimary.ProgrammedMovementControl.Enabled)) THEN
	AutomationStart := lControllerUInterfaceRadio.AutomationStart;
END_IF

TwistlockLock := FALSE;

IF (Active) THEN
	TwistlockLock := lControllerUInterfaceRadio.TwistlockLock;
END_IF

IF ((InputMode<>cInputModeNone) AND (gSystemPrimary.SystemState.State=cSystemStateOperational)) THEN
	lInputMode := InputMode;
END_IF

Lift := 0;

IF ((Active) AND
	(gSystemPrimary.FunctionalModeControl.CurrentMode<>cFunctionalModeTopbeamConfiguration) AND
	(InputMode=cInputModeDefault)) THEN
	Lift := lControllerUInterfaceRadio.RightRotation;
END_IF

LiftBalanceAB := 0;

IF (Active) THEN
	CASE lUIOrientation OF
		cUIOrientationForward:
			LiftBalanceAB := lControllerUInterfaceRadio.RightXaxis;

		cUIOrientationSide:
			LiftBalanceAB := lControllerUInterfaceRadio.RightYaxis;

		cUIOrientationReverse:
			LiftBalanceAB := lControllerUInterfaceRadio.RightXaxis * -1.0;

		cUIOrientationOpposite:		
			LiftBalanceAB := lControllerUInterfaceRadio.RightYaxis * -1.0;
	END_CASE
END_IF

LiftBalanceAD := 0;

IF (Active) THEN
	CASE lUIOrientation OF
		cUIOrientationForward:
			LiftBalanceAD := lControllerUInterfaceRadio.RightYaxis;

		cUIOrientationSide:
			LiftBalanceAD := lControllerUInterfaceRadio.RightXaxis;

		cUIOrientationReverse:
			LiftBalanceAD := lControllerUInterfaceRadio.RightYaxis * -1.0;

		cUIOrientationOpposite:		
			LiftBalanceAD := lControllerUInterfaceRadio.RightXaxis * -1.0;
	END_CASE
END_IF

Sideshift := 0;

IF (Active) THEN
	CASE lUIOrientation OF
		cUIOrientationForward:
			Sideshift := lControllerUInterfaceRadio.RightXaxis;

		cUIOrientationSide:
			Sideshift := lControllerUInterfaceRadio.RightYaxis;

		cUIOrientationReverse:
			Sideshift := lControllerUInterfaceRadio.RightXaxis * -1.0;

		cUIOrientationOpposite:		
			Sideshift := lControllerUInterfaceRadio.RightYaxis * -1.0;
	END_CASE
END_IF

SideshiftAB := 0;

SideshiftAB := Sideshift;
IF (SideshiftBalanceAD<0.0) THEN
	SideshiftAB := Sideshift * ABS(1.0+SideshiftBalanceAD);
END_IF

SideshiftBalanceAD := 0;

IF (Active) THEN
	CASE lUIOrientation OF
		cUIOrientationForward:
			SideshiftBalanceAD := lControllerUInterfaceRadio.RightYaxis;

		cUIOrientationSide:
			SideshiftBalanceAD := lControllerUInterfaceRadio.RightXaxis;

		cUIOrientationReverse:
			SideshiftBalanceAD := lControllerUInterfaceRadio.RightYaxis * -1.0;

		cUIOrientationOpposite:		
			SideshiftBalanceAD := lControllerUInterfaceRadio.RightXaxis * -1.0;
	END_CASE
END_IF

SideshiftCD := 0;

SideshiftCD := Sideshift;
IF (SideshiftBalanceAD>0.0) THEN
	SideshiftCD := Sideshift * ABS(1.0-SideshiftBalanceAD);
END_IF

SpreaderTelescopingExtend := FALSE;

IF ((Active) AND
	(gSystemPrimary.FunctionalModeControl.CurrentMode<>cFunctionalModeTopbeamConfiguration) AND
	(InputMode=cInputModeSpreaderConfiguration)) THEN
	SpreaderTelescopingExtend := (lControllerUInterfaceRadio.RightRotation>cTelescopingDeadband);
END_IF

SpreaderTelescopingRetract := FALSE;

IF ((Active) AND
	(gSystemPrimary.FunctionalModeControl.CurrentMode<>cFunctionalModeTopbeamConfiguration) AND
	(InputMode=cInputModeSpreaderConfiguration)) THEN
	SpreaderTelescopingRetract := (lControllerUInterfaceRadio.RightRotation<(-cTelescopingDeadband));
END_IF

Steer := 0;

IF ((Active) AND
	(gSystemPrimary.FunctionalModeControl.CurrentMode<>cFunctionalModeTopbeamConfiguration) AND
	(InputMode=cInputModeDefault)) THEN

	CASE lUIOrientation OF
		cUIOrientationForward:
			Steer := lControllerUInterfaceRadio.LeftXaxis;

		cUIOrientationSide:
			Steer := lControllerUInterfaceRadio.LeftYaxis;

		cUIOrientationReverse:
			Steer := lControllerUInterfaceRadio.LeftXaxis * -1.0;

		cUIOrientationOpposite:		
			Steer := lControllerUInterfaceRadio.LeftYaxis * -1.0;
	END_CASE
END_IF

Travel := 0;

IF ((Active) AND
	(gSystemPrimary.FunctionalModeControl.CurrentMode<>cFunctionalModeTopbeamConfiguration) AND
	(InputMode=cInputModeDefault)) THEN

	CASE lUIOrientation OF
		cUIOrientationForward:
			Travel := lControllerUInterfaceRadio.LeftYaxis;

		cUIOrientationSide:
			Travel := lControllerUInterfaceRadio.LeftXaxis * -1.0;

		cUIOrientationReverse:
			Travel := lControllerUInterfaceRadio.LeftYaxis * -1.0;

		cUIOrientationOpposite:		
			Travel := lControllerUInterfaceRadio.LeftXaxis;
	END_CASE
END_IF

TwistlockUnlock := FALSE;

IF (Active) THEN
	TwistlockUnlock := lControllerUInterfaceRadio.TwistlockUnlock;
END_IF

ZeroSteerTargetAngle := FALSE;

IF (Active) THEN
	ZeroSteerTargetAngle := lControllerUInterfaceRadio.ZeroSteerTargetAngle;
END_IF

SUPER^.initialize();

lUInterfaceA.Resolved REF= THIS^;
lUInterfaceB.Resolved REF= THIS^;

lUInterfaceId := cUIIDNone;

lSwitching := FALSE;

lSwitchTimer.lPeriod := T#10s;
lSwitchTimer.initialize();
lSwitchTimer.lEnable := FALSE;

lUInterfaceA.lSingleMode :=FALSE;
lUInterfaceB.lSingleMode :=FALSE;

lDiagnostic := _Diagnostic;
_Diagnostic := cUInterfaceDiagnosticOK;

lUInterfaceA.operator();
lUInterfaceB.operator();

IF ((lUInterfaceA.UIMode<=cUIModeSlave) AND (lUInterfaceA.lReady)) THEN
	CASE (lUInterfaceB.UIMode) OF
		cUIModeInoperable:
			lUInterfaceA.UIMode := cUIModeSingle;
		cUIModeSlave:
			lUInterfaceA.UIMode := cUIModeSlave;
			lUInterfaceB.UIMode := cUIModeMaster;
		cUIModeSingle:
			lUInterfaceA.UIMode := cUIModeSlave;
			lUInterfaceB.UIMode := cUIModeMaster;
		cUIModeMaster:
			lUInterfaceA.UIMode := cUIModeSlave;
			lUInterfaceB.UIMode := cUIModeMaster;
	END_CASE
END_IF

IF ((lUInterfaceB.UIMode<=cUIModeSlave) AND (lUInterfaceB.lReady)) THEN
	CASE (lUInterfaceA.UIMode) OF
		cUIModeInoperable:
			lUInterfaceB.UIMode := cUIModeSingle;
		cUIModeSlave:
			lUInterfaceB.UIMode := cUIModeSlave;
			lUInterfaceA.UIMode := cUIModeMaster;
		cUIModeSingle:
			lUInterfaceB.UIMode := cUIModeSlave;
			lUInterfaceA.UIMode := cUIModeMaster;
		cUIModeMaster:
			lUInterfaceB.UIMode := cUIModeSlave;
			lUInterfaceA.UIMode := cUIModeMaster;
	END_CASE
END_IF

IF ((lUInterfaceB.UIMode=cUIModeInoperable) AND (lUInterfaceA.UIMode=cUIModeMaster)) THEN
	lUInterfaceA.UIMode := cUIModeSingle;
END_IF
IF ((lUInterfaceA.UIMode=cUIModeInoperable) AND (lUInterfaceB.UIMode=cUIModeMaster)) THEN
	lUInterfaceB.UIMode := cUIModeSingle;
END_IF

lReady := (((lUInterfaceA.lReady) AND (lUInterfaceB.UIMode=cUIModeInoperable)) OR
	((lUInterfaceB.lReady) AND (lUInterfaceA.UIMode=cUIModeInoperable)) OR
	((lUInterfaceA.lReady) AND (lUInterfaceB.lReady)));

IF (NOT(lReady)) THEN
	Diagnostic := cUInterfaceDiagnosticNotReady;

	lAlarmUInterfaceNotReady.trigger(FALSE);
END_IF

lSwitchTimer.operator();
lSwitching := ((lSwitchTimer.Enable) AND (NOT(lSwitchTimer.Expired)));
lSwitchTimer.Enable := lSwitching;

IF (NOT(lSwitching)) THEN
	lUInterfaceA.UIModeRequest := FALSE;
	lUInterfaceB.UIModeRequest := FALSE;
END_IF

CASE id OF
	cUIIdA:
		IF ((lUInterfaceA.UIMode=cUIModeSlave) AND (NOT(lSwitching))) THEN
			lSwitching := TRUE;
			lSwitchTimer.Enable := TRUE;
			lSwitchTimer.reset();

			lUInterfaceB.UIModeRequest := TRUE;
		END_IF

		IF ((lUInterfaceA.UIMode=cUIModeMaster) AND (lSwitching)) THEN
			lSwitching := FALSE;
			lSwitchTimer.Enable := FALSE;
			lUInterfaceA.UIMode := cUIModeSlave;
			lUInterfaceB.UIMode := cUIModeMaster;
		END_IF

	cUIIdB:
		IF ((lUInterfaceB.UIMode=cUIModeSlave) AND (NOT(lSwitching))) THEN
			lSwitching := TRUE;
			lSwitchTimer.Enable := TRUE;
			lSwitchTimer.reset();

			lUInterfaceA.UIModeRequest := TRUE;
		END_IF

		IF ((lUInterfaceB.UIMode=cUIModeMaster) AND (lSwitching)) THEN
			lSwitching := FALSE;
			lSwitchTimer.Enable := FALSE;
			lUInterfaceB.UIMode := cUIModeSlave;
			lUInterfaceA.UIMode := cUIModeMaster;
		END_IF
END_CASE

AutomationRequest := cProgMovCodeNone;

IF (lUInterfaceA.Active) THEN
	AutomationRequest := lUInterfaceA.AutomationRequest;
END_IF
IF (lUInterfaceB.Active) THEN
	AutomationRequest := lUInterfaceB.AutomationRequest;
END_IF

AutomationStart := FALSE;

IF (lUInterfaceA.Active) THEN
	AutomationStart := lUInterfaceA.AutomationStart;
END_IF
IF (lUInterfaceB.Active) THEN
	AutomationStart := lUInterfaceB.AutomationStart;
END_IF

ConfigurationJoystickInputPresent := FALSE;

IF (lUInterfaceA.Active) THEN
	ConfigurationJoystickInputPresent := lUInterfaceA.ConfigurationJoystickInputPresent;
END_IF
IF (lUInterfaceB.Active) THEN
	ConfigurationJoystickInputPresent := lUInterfaceB.ConfigurationJoystickInputPresent;
END_IF

Emgy := lUInterfaceA.Emgy AND lUInterfaceB.Emgy;

IF (lUInterfaceA.UIMode=cUIModeInoperable) THEN
	Emgy := lUInterfaceB.Emgy;
END_IF
IF (lUInterfaceB.UIMode=cUIModeInoperable) THEN
	Emgy := lUInterfaceA.Emgy;
END_IF

Estop := lUInterfaceA.Estop AND lUInterfaceB.Estop;

IF (lUInterfaceA.UIMode=cUIModeInoperable) THEN
	Estop := lUInterfaceB.Estop;
END_IF
IF (lUInterfaceB.UIMode=cUIModeInoperable) THEN
	Estop := lUInterfaceA.Estop;
END_IF

FunctionalModeRequest := cFunctionalModeAny;

IF (lUInterfaceA.Active) THEN
	FunctionalModeRequest := lUInterfaceA.FunctionalModeRequest;
END_IF
IF (lUInterfaceB.Active) THEN
	FunctionalModeRequest := lUInterfaceB.FunctionalModeRequest;
END_IF

IsBeginner := FALSE;

IF (lUInterfaceA.Active) THEN
	IsBeginner := lUInterfaceA.IsBeginner;
END_IF
IF (lUInterfaceB.Active) THEN
	IsBeginner := lUInterfaceB.IsBeginner;
END_IF

IsSlow := FALSE;

IF (lUInterfaceA.Active) THEN
	IsSlow := lUInterfaceA.IsSlow;
END_IF
IF (lUInterfaceB.Active) THEN
	IsSlow := lUInterfaceB.IsSlow;
END_IF

JoystickInputPresent := FALSE;

IF (lUInterfaceA.Active) THEN
	JoystickInputPresent := lUInterfaceA.JoystickInputPresent;
END_IF
IF (lUInterfaceB.Active) THEN
	JoystickInputPresent := lUInterfaceB.JoystickInputPresent;
END_IF

Lift := 0;

IF (lUInterfaceA.Active) THEN
	Lift := lUInterfaceA.Lift;
END_IF
IF (lUInterfaceB.Active) THEN
	Lift := lUInterfaceB.Lift;
END_IF

LiftBalanceAB := 0;

IF (lUInterfaceA.Active) THEN
	LiftBalanceAB := lUInterfaceA.LiftBalanceAB;
END_IF
IF (lUInterfaceB.Active) THEN
	LiftBalanceAB := lUInterfaceB.LiftBalanceAB;
END_IF

LiftBalanceAD := 0;

IF (lUInterfaceA.Active) THEN
	LiftBalanceAD := lUInterfaceA.LiftBalanceAD;
END_IF
IF (lUInterfaceB.Active) THEN
	LiftBalanceAD := lUInterfaceB.LiftBalanceAD;
END_IF

LiftJoystickInputPresent := FALSE;

IF (lUInterfaceA.Active) THEN
	LiftJoystickInputPresent := lUInterfaceA.LiftJoystickInputPresent;
END_IF
IF (lUInterfaceB.Active) THEN
	LiftJoystickInputPresent := lUInterfaceB.LiftJoystickInputPresent;
END_IF

OperatingMethodRequest := cOperatingMethodNone;

IF (lUInterfaceA.Active) THEN
	OperatingMethodRequest := lUInterfaceA.OperatingMethodRequest;
END_IF
IF (lUInterfaceB.Active) THEN
	OperatingMethodRequest := lUInterfaceB.OperatingMethodRequest;
END_IF

