SUPER^.initialize();

lOperationalHoursMeterTickPrevious := lCurrentTime.Value;
lHoursMeterTickPrevious := lCurrentTime.Value;

SUPER^.operator();

IF ((gSystemPrimary.SystemState.State<cSystemStateOperational) AND
	(lCurrentTime.Value>lOperationalHoursMeterTickOffset)) THEN
	lOperationalHoursMeterTickPrevious := lCurrentTime.Value - lOperationalHoursMeterTickOffset;
END_IF
IF (lCurrentTime.Value > (lOperationalHoursMeterTickPrevious+lOperationalHoursMeterTickPeriod)) THEN
	lOperationalHoursMeterTickPrevious := lOperationalHoursMeterTickPrevious + lOperationalHoursMeterTickPeriod;
	lOperationalHours.Value := lOperationalHours.Value + ULINT_TO_REAL(lOperationalHoursMeterTickPeriod)/3600000000;
END_IF

IF (lCurrentTime.Value>lHoursMeterTickOffset) THEN
	lHoursMeterTickPrevious := lCurrentTime.Value - lHoursMeterTickOffset;
END_IF
IF (lCurrentTime.Value > (lHoursMeterTickPrevious+lHoursMeterTickPeriod)) THEN
	lHoursMeterTickPrevious := lHoursMeterTickPrevious + lHoursMeterTickPeriod;
	lHours.Value := lHours.Value + ULINT_TO_REAL(lHoursMeterTickPeriod)/3600000000;
END_IF

CASE lCode OF
	cLEDCodeNone,
	cLEDCodeStartup:
		scrollBidirectional(1);

	cLEDCodeNormal:
		flash(T#500MS,T#500MS,cColorGreen);

	cLEDCodeStandby:
		scrollUnidirectional(1);

	cLEDCodeMaintenance:
		flash(T#500MS,T#500MS,cColorYellow);

	cLEDCodeSoftwareCrash:
		flash(T#500MS,T#500MS,cColorRed);

	cLEDCodeWatchDogDisabled:
		flash(T#125MS,T#125MS,cColorGreen);

	cLEDCodeFailSafe:
		flash(T#125MS,T#125MS,cColorYellow);

	cLEDCodeFailSafeSevere:
		flash(T#125MS,T#125MS,cColorRed);
END_CASE

SUPER^.operator();

lState.initializeValueObjectOp(OpSelf,'State','Diagnostic LED pattern','',cValueStyleConfigurable);
lColor.initializeValueObjectOp(OpSelf,'Color','Diagnostic LED color','',cValueStyleConfigurable);

SUPER^.initialize();

lTimer.Enable := TRUE;
lTimer.Period := T#1S;
lTimer.initialize();

lCounter := lCounter + 1;
index := lCounter/rate;

IF (index>200) THEN
	lCounter := 0;
	index := 0;
END_IF

IF (index>100) THEN
	lColor.Value := index - 100;
ELSE
	lColor.Value := 100 - index;
END_IF

lState.Value := TRUE;

lCounter := lCounter + 1;
index := lCounter/rate;

IF (index>100) THEN
	lCounter := 0;
	index := 0;
END_IF

lColor.Value := index;
lState.Value := TRUE;

lTimer.operator();

IF (lTimer.Expired) THEN
	IF (lState.Value) THEN
		lTimer.Period := off;
	ELSE
		lTimer.Period := on;
	END_IF

	lState.Value := NOT(lState.Value);
	lTimer.reset();
END_IF

lColor.Value := color;

